-- Poems batch 44
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('056991fb-c566-4e84-a542-9fe39ec434f4','感遇詩三十八首 十三','陳子昂','唐','唐诗','tang','','[]','林居病時久，水木澹孤清。',48,'全唐诗/poet.tang.4000.json','["林居病時久，水木澹孤清。", "閑臥觀物化，悠悠念無生。", "青春始萌達，朱火已滿盈。", "徂落方自此，感歎何時平。"]'),
('16be7346-e99d-4633-b2a6-241ccb74ca37','感遇詩三十八首 十四','陳子昂','唐','唐诗','tang','','[]','臨岐泣世道，天命良悠悠。',48,'全唐诗/poet.tang.4000.json','["臨岐泣世道，天命良悠悠。", "昔日殷王子，玉馬遂朝周。", "寶鼎淪伊穀，瑤臺成古丘。", "西山傷遺老，東陵有故侯。"]'),
('c1e33779-9055-47f0-81bd-5f426ac8b973','感遇詩三十八首 十五','陳子昂','唐','唐诗','tang','','[]','貴人難得意，賞愛在須臾。',60,'全唐诗/poet.tang.4000.json','["貴人難得意，賞愛在須臾。", "莫以心如玉，探他明月珠。", "昔稱夭桃子，今爲舂市徒。", "鴟鴞悲東國，麋鹿泣姑蘇。", "誰見鴟夷子，扁舟去五湖。"]'),
('364ee260-96ec-4e74-979b-32c80c990221','感遇詩三十八首 十六','陳子昂','唐','唐诗','tang','','[]','聖人去已久，公道緬良難。',72,'全唐诗/poet.tang.4000.json','["聖人去已久，公道緬良難。", "蚩蚩夸毘子，堯禹以爲謾。", "驕榮貴工巧，勢利迭相干。", "燕王尊樂毅，分國願同歡。", "魯連讓齊爵，遺組去邯鄲。", "伊人信往矣，感激爲誰歎。"]'),
('9ed6ec42-d293-4c71-ad8a-20cca19915ef','感遇詩三十八首 十七','陳子昂','唐','唐诗','tang','','[]','幽居觀天運，悠悠念羣生。',120,'全唐诗/poet.tang.4000.json','["幽居觀天運，悠悠念羣生。", "終古代興沒，豪聖莫能爭。", "三季淪周赧，七雄滅秦嬴。", "復聞赤精子，提劒入咸京。", "炎光既無象，晉虜復縱橫。", "堯禹道已昧，昏虐勢方行。", "豈無當世雄，天道與胡兵。", "咄咄安可言，時醉而未醒。", "仲尼溺東魯，伯陽遁西溟。", "大運自古來，旅人胡歎哉。"]'),
('83724c68-655e-4d34-9190-46c957dd5cbe','感遇詩三十八首 十八','陳子昂','唐','唐诗','tang','','[]','逶迤勢已久，骨鯁道斯窮。',48,'全唐诗/poet.tang.4000.json','["逶迤勢已久，骨鯁道斯窮。", "豈無感激者，時俗頹此風。", "灌園何其鄙，皎皎於陵中。", "世道不相容，嗟嗟張長公。"]'),
('d4028319-c3b7-4542-93fa-5b45440058c1','感遇詩三十八首 十九','陳子昂','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u8bae\u8bba", "\u548f\u53f2\u6000\u53e4", "\u8bbd\u523a"]','聖人不利己，憂濟在元元。',84,'全唐诗/poet.tang.4000.json','["聖人不利己，憂濟在元元。", "黃屋非堯意，瑤臺安可論。", "吾聞西方化，清淨道彌敦。", "奈何窮金玉，雕刻以爲尊。", "雲構山林盡，瑤圖珠翠煩。", "鬼工尚未可，人力安能存。", "夸愚適增累，矜智道逾昏。"]'),
('9b7aa6ce-fd41-40c7-bd5b-cda1eb3a7b9f','感遇詩三十八首 二十','陳子昂','唐','唐诗','tang','','[]','玄天幽且默，羣議曷嗤嗤。',48,'全唐诗/poet.tang.4000.json','["玄天幽且默，羣議曷嗤嗤。", "聖人教猶在，世運久陵夷。", "一繩將何繫？憂醉不能持。", "去去行采芝，勿爲塵所欺。"]'),
('8061b8a8-5483-4707-ac47-91370377239d','感遇詩三十八首 二十一','陳子昂','唐','唐诗','tang','','[]','蜻蛉遊天地，與世本無患。',72,'全唐诗/poet.tang.4000.json','["蜻蛉遊天地，與世本無患。", "飛飛未能止，黃雀來相干。", "穰侯富秦寵，金石比交歡。", "出入咸陽裏，諸侯莫敢言。", "寧知山東客，激怒秦王肝。", "布衣取丞相，千載爲辛酸。"]'),
('d9aebc27-e033-4186-bd86-a8a57cf9a9de','感遇詩三十八首 二十二','陳子昂','唐','唐诗','tang','','[]','微霜知歲晏，斧柯始青青。',48,'全唐诗/poet.tang.4000.json','["微霜知歲晏，斧柯始青青。", "況乃金天夕，浩露沾羣英。", "登山望宇宙，白日已西暝。", "雲海方蕩潏，孤鱗安得寧。"]'),
('03aa639d-0376-49da-aede-eca417244862','感遇詩三十八首 二十三','陳子昂','唐','唐诗','tang','','[]','翡翠巢南海，雄雌珠樹林。',72,'全唐诗/poet.tang.4000.json','["翡翠巢南海，雄雌珠樹林。", "何知美人意，驕愛比黃金。", "殺身炎州裏，委羽玉堂陰。", "旖旎光首飾，葳蕤爛錦衾。", "豈不在遐遠，虞羅忽見尋。", "多材信爲累，歎息此珍禽。"]'),
('64cb21e9-3cef-4923-a647-12cd22882279','感遇詩三十八首 二十四','陳子昂','唐','唐诗','tang','','[]','挈瓶者誰子，姣服當青春。',48,'全唐诗/poet.tang.4000.json','["挈瓶者誰子，姣服當青春。", "三五明月滿，盈盈不自珍。", "高堂委金玉，微縷懸千鈞。", "如何負公鼎，被敓笑時人。"]'),
('f21f3856-bffc-42dc-94ae-f115ce424d82','感遇詩三十八首 二十五','陳子昂','唐','唐诗','tang','','[]','玄蟬號白露，茲歲已蹉跎。',48,'全唐诗/poet.tang.4000.json','["玄蟬號白露，茲歲已蹉跎。", "羣物從大化，孤英將奈何？", "瑤臺有青鳥，遠食玉山禾。", "崑崙見玄鳳，豈復虞雲羅。"]'),
('f7c5742a-ee23-4525-980d-7ca6c75270c1','感遇詩三十八首 二十六','陳子昂','唐','唐诗','tang','','[]','荒哉穆天子，好與白雲期。',48,'全唐诗/poet.tang.4000.json','["荒哉穆天子，好與白雲期。", "宮女多怨曠，層城閉蛾眉。", "日耽瑤池樂，豈傷桃李時。", "青苔空萎絕，白髮生羅帷。"]'),
('a57f92e6-bbe4-4e84-b826-6c674992c5b0','感遇詩三十八首 二十七','陳子昂','唐','唐诗','tang','','[]','朝發宜都渚，浩然思故鄉。',72,'全唐诗/poet.tang.4000.json','["朝發宜都渚，浩然思故鄉。", "故鄉不可見，路隔巫山陽。", "巫山綵雲沒，高丘正微茫。", "佇立望已久，涕落沾衣裳。", "豈茲越鄉感，憶昔楚襄王。", "朝雲無處所，荆國亦淪亡。"]'),
('a49874e5-df2b-4261-b092-4a30cdf0663a','感遇詩三十八首 二十八','陳子昂','唐','唐诗','tang','','[]','昔日章華宴，荆王樂荒淫。',48,'全唐诗/poet.tang.4000.json','["昔日章華宴，荆王樂荒淫。", "霓旌翠羽蓋，射兕雲夢林。", "朅來高唐觀，悵望雲陽岑。", "雄圖今何在？黃雀空哀吟。"]'),
('9ab6fb82-2158-4a2a-9ebb-88a8b5927246','感遇詩三十八首 二十九','陳子昂','唐','唐诗','tang','','[]','丁亥歲云暮，西山事甲兵。',96,'全唐诗/poet.tang.4000.json','["丁亥歲云暮，西山事甲兵。", "贏糧匝邛道，荷戟爭羗城。", "嚴冬陰風勁，窮岫泄雲生。", "昏噎無晝夜，羽檄復相驚。", "拳跼競萬仞，崩危走九冥。", "籍籍峰壑裏，哀哀冰雪行。", "聖人御宇宙，聞道泰階平。", "肉食謀何失，藜藿緬縱橫。"]'),
('24d98247-7ed3-421e-82b7-8442cf1125bc','感遇詩三十八首 三十','陳子昂','唐','唐诗','tang','','[]','可憐瑤臺樹，灼灼佳人姿。',48,'全唐诗/poet.tang.4000.json','["可憐瑤臺樹，灼灼佳人姿。", "碧華映朱實，攀折青春時。", "豈不盛光寵，榮君白玉墀。", "但恨紅芳歇，凋傷感所思。"]'),
('45485010-1065-4afa-8ab2-13158115bfbe','感遇詩三十八首 三十一','陳子昂','唐','唐诗','tang','','[]','朅來豪遊子，勢利禍之門。',72,'全唐诗/poet.tang.4000.json','["朅來豪遊子，勢利禍之門。", "如何蘭膏歎，感激自生冤。", "衆趨明所避，時棄道猶存。", "雲淵既已失，羅網與誰論。", "箕山有高節，湘水有清源。", "唯應白鷗鳥，可爲洗心言。"]'),
('0a08f964-d36e-482c-b11d-b83485d3cdbb','感遇詩三十八首 三十二','陳子昂','唐','唐诗','tang','','[]','索居猶幾日，炎夏忽然衰。',60,'全唐诗/poet.tang.4000.json','["索居猶幾日，炎夏忽然衰。", "陽彩皆陰翳，親友盡暌違。", "登山望不見，涕泣久漣洏。", "宿夢感顏色，若與白雲期。", "馬上驕豪子，驅逐正蚩蚩。"]'),
('2d40fe2f-d6fa-4ac0-b831-791da1ed9e48','感遇詩三十八首 三十三','陳子昂','唐','唐诗','tang','','[]','金鼎合神丹，世人將見欺。',60,'全唐诗/poet.tang.4000.json','["金鼎合神丹，世人將見欺。", "飛飛騎羊子，胡乃在峨眉。", "變化固幽類，芳菲能幾時。", "疲痾苦淪世，憂痗日侵淄。", "眷然顧幽褐，白雲空涕洟。"]'),
('f37f8a2e-4acd-40ae-8294-04dd22581cdd','感遇詩三十八首 三十四','陳子昂','唐','唐诗','tang','','[]','朔風吹海樹，蕭條邊已秋。',96,'全唐诗/poet.tang.4000.json','["朔風吹海樹，蕭條邊已秋。", "亭上誰家子，哀哀明月樓。", "自言幽燕客，結髮事遠遊。", "赤丸殺公吏，白刃報私讎。", "避讎至海上，被役此邊州。", "故鄉三千里，遼水復悠悠。", "每憤胡兵入，常爲漢國羞。", "何知七十戰，白首未封侯。"]'),
('9dc7d672-2be6-4bc3-b162-2914c8ff3264','感遇詩三十八首 三十五','陳子昂','唐','唐诗','tang','','[]','本爲貴公子，平生實愛才。',60,'全唐诗/poet.tang.4000.json','["本爲貴公子，平生實愛才。", "感時思報國，拔劒起蒿萊。", "西馳丁零塞，北上單于臺。", "登山見千里，懷古心悠哉。", "誰言未忘禍，磨滅成塵埃。"]'),
('a3e0c03f-0eb4-46f8-bb5c-18af10d98263','感遇詩三十八首 三十六','陳子昂','唐','唐诗','tang','','[]','浩然坐何慕，吾蜀有峨眉。',72,'全唐诗/poet.tang.4000.json','["浩然坐何慕，吾蜀有峨眉。", "念與楚狂子，悠悠白雲期。", "時哉悲不會，涕泣久漣洏。", "夢登綏山穴，南采巫山芝。", "探元觀羣化，遺世從雲螭。", "婉變時永矣，感悟不見之。"]'),
('103974bc-643c-4de0-a44e-7b0486f72387','感遇詩三十八首 三十七','陳子昂','唐','唐诗','tang','','[]','朝入雲中郡，北望單于臺。',60,'全唐诗/poet.tang.4000.json','["朝入雲中郡，北望單于臺。", "胡秦何密邇，沙朔氣雄哉。", "藉藉天驕子，猖狂已復來。", "塞垣無名將，亭堠空崔嵬。", "咄嗟吾何歎，邊人塗草萊。"]'),
('ced57707-edca-47b8-a69f-60c22685e87e','感遇詩三十八首 三十八','陳子昂','唐','唐诗','tang','','[]','仲尼探元化，幽鴻順陽和。',48,'全唐诗/poet.tang.4000.json','["仲尼探元化，幽鴻順陽和。", "大運自盈縮，春秋遞來過。", "盲飆忽號怒，萬物相紛劘。", "溟海皆震蕩，孤鳳其如何。"]'),
('ef5c637d-04bf-4ff8-9d4b-a0b2e6a97001','觀荆玉篇','陳子昂','唐','唐诗','tang','','[]','鴟夷雙白玉，此玉有緇磷。',48,'全唐诗/poet.tang.4000.json','["鴟夷雙白玉，此玉有緇磷。", "懸之千金價，舉世莫知真。", "丹青非異色，輕重有殊倫。", "勿信玉工言，徒悲荆國人。"]'),
('b504905f-507a-447e-9f7d-8d7f1181eb2d','鴛鴦篇','陳子昂','唐','唐诗','tang','','[]','飛飛鴛鴦鳥，舉翼相蔽虧。',168,'全唐诗/poet.tang.4000.json','["飛飛鴛鴦鳥，舉翼相蔽虧。", "俱來綠潭裏，共向白雲涯。", "音容相眷戀，羽翮兩逶迤。", "蘋萍戲春渚，霜霰遶寒池。", "浦沙連岸淨，汀樹拂潭垂。", "年年此遊翫，歲歲來追隨。", "鳳凰起丹穴，獨向梧桐枝。", "鴻雁來紫塞，空憶稻粱肥。", "烏啼倦依托，鶴鳴傷別離。", "豈若此雙禽，飛翻不異林。", "刷尾青江浦，交頸紫山岑。", "文章負奇色，和鳴多好音。", "聞有鴛鴦綺，復有鴛鴦衾。", "持爲美人贈，勖此故交心。"]'),
('e3b3ebe1-ee79-410d-820a-a10cbcc3a990','與東方左史虬修竹篇','陳子昂','唐','唐诗','tang','','["\u8861\u5c71"]','龍種生南嶽，孤翠鬱亭亭。',216,'全唐诗/poet.tang.4000.json','["龍種生南嶽，孤翠鬱亭亭。", "峰嶺上崇崒，煙雨下微冥。", "夜聞鼯鼠呌，晝聒泉鶴聲。", "春風正淡蕩，白露已清泠。", "哀響激金奏，密色滋玉英。", "歲寒霜雪苦，含彩獨青青。", "豈不厭凝洌，羞比春木榮。", "春木有榮歇，此節無凋零。", "始願與金石，終古保堅貞。", "不意伶倫子，吹之學鳳鳴。", "遂偶雲和瑟，張樂奏天庭。", "妙曲方千變，簫韶亦九成。", "信蒙雕斲美，常願事仙靈。", "驅馳翠虯駕，伊鬱紫鸞笙。", "結交嬴臺女，吟弄昇天行。", "攜手登白日，遠遊戲赤城。", "低昂玄鶴舞，斷續綵雲生。", "永隨衆仙逝，三山遊玉京。"]'),
('b3ae934e-62e3-4fa6-97b7-7dfbf1859e69','薊丘覽古贈盧居士藏用七首 軒轅臺','陳子昂','唐','唐诗','tang','','[]','北登薊丘望，求古軒轅臺。',36,'全唐诗/poet.tang.4000.json','["北登薊丘望，求古軒轅臺。", "應龍已不見，牧馬空黃埃。", "尚想廣成子，遺跡白雲隈。"]'),
('b4b0e3f4-b442-400b-8b22-38ad077e0eb7','薊丘覽古贈盧居士藏用七首 燕昭王','陳子昂','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u53e4"]','南登碣石坂，遙望黃金臺。',36,'全唐诗/poet.tang.4000.json','["南登碣石坂，遙望黃金臺。", "丘陵盡喬木，昭王安在哉。", "霸圖悵已矣，驅馬復歸來。"]'),
('5c8bc3ce-65da-4e0e-95f3-fab8d8e3d8b3','薊丘覽古贈盧居士藏用七首 樂生','陳子昂','唐','唐诗','tang','','[]','王道已淪昧，戰國競貪兵。',36,'全唐诗/poet.tang.4000.json','["王道已淪昧，戰國競貪兵。", "樂生何感激，仗義下齊城。", "雄圖竟中夭，遺歎寄阿衡。"]'),
('5255d81f-b504-4cdd-9e06-1d46f46e8108','薊丘覽古贈盧居士藏用七首 燕太子','陳子昂','唐','唐诗','tang','','[]','秦王日無道，太子怨亦深。',36,'全唐诗/poet.tang.4000.json','["秦王日無道，太子怨亦深。", "一聞田光義，匕首贈千金。", "其事雖不立，千載爲傷心。"]'),
('a43e2d3f-22d9-4918-89e6-e415e78da015','薊丘覽古贈盧居士藏用七首 田光先生','陳子昂','唐','唐诗','tang','','[]','自古皆有死，狥義良獨稀。',36,'全唐诗/poet.tang.4000.json','["自古皆有死，狥義良獨稀。", "奈何燕太子，尚使田生疑。", "伏劒誠已矣，感我涕沾衣。"]'),
('a69d5e93-b16e-479f-a1b0-88c8df11cf2d','薊丘覽古贈盧居士藏用七首 鄒衍','陳子昂','唐','唐诗','tang','','[]','大運淪三代，天人罕有窺。',36,'全唐诗/poet.tang.4000.json','["大運淪三代，天人罕有窺。", "鄒子何寥廓，漫說九瀛垂。", "興亡已千載，今也則無推。"]'),
('564115e5-bb0b-4769-8e50-f5b8377a1561','薊丘覽古贈盧居士藏用七首 郭隗','陳子昂','唐','唐诗','tang','','[]','逢時獨爲貴，歷代非無才。',24,'全唐诗/poet.tang.4000.json','["逢時獨爲貴，歷代非無才。", "隗君亦何幸，遂起黃金臺。"]'),
('aa7cc16e-1a5a-4c62-9e33-8e1977d03932','西還至散關答喬補闕知之','陳子昂','唐','唐诗','tang','','[]','葳蕤蒼梧鳳，嘹唳白露蟬。',120,'全唐诗/poet.tang.4000.json','["葳蕤蒼梧鳳，嘹唳白露蟬。", "羽翰本非匹，結交何獨全。", "昔君事胡馬，余得奉戎旃。", "攜手向沙塞，關河緬幽燕。", "芳歲幾陽止，白日屢徂遷。", "功業雲臺薄，平生玉佩捐。", "歎此南歸日，猶聞北戍邊。", "代水不可涉，巴江亦潺湲。", "攬衣度函谷，銜涕望秦川。", "蜀門自茲始，雲山方浩然。"]'),
('fd8f273b-c73a-43f1-8d47-7f33dd88c9f5','度峽口山贈喬補闕知之王二無競','陳子昂','唐','唐诗','tang','','[]','峽口大漠南，橫絕界中國。',120,'全唐诗/poet.tang.4000.json','["峽口大漠南，橫絕界中國。", "叢石何紛糺，赤山復翕赩。", "遠望多衆容，逼之無異色。", "崔崒乍孤斷，逶迤屢回直。", "信關胡馬衝，亦距漢邊塞。", "豈依河山險，將順休明德。", "物壯誠有衰，勢雄良易極。", "邐迤忽而盡，泱漭平不息。", "之子黃金軀，如何此荒域。", "雲臺盛多士，待君丹墀側。"]'),
('88c67a5e-4918-4804-b302-fcf3851dfaeb','題居延古城贈喬十二知之','陳子昂','唐','唐诗','tang','','[]','聞君東山意，宿昔紫芝榮。',72,'全唐诗/poet.tang.4000.json','["聞君東山意，宿昔紫芝榮。", "滄洲今何在？華髪旅邊城。", "還漢功既薄，逐胡策未行。", "徒嗟白日暮，坐對黃雲生。", "桂枝芳欲晚，薏苡謗誰明。", "無爲空自老，含歎負生平。"]'),
('85cdce99-a4ec-4656-826f-e2c462f398ab','贈趙六貞固二首 一','陳子昂','唐','唐诗','tang','','[]','回中[烽]火入，塞上追兵起。',38,'全唐诗/poet.tang.4000.json','["回中[烽]火入，塞上追兵起。", "此時邊朔寒，登隴思君子。", "東顧望漢京，南山雲霧裏。"]'),
('e3020ff2-706e-46b0-bd06-e3c24a3f14be','贈趙六貞固二首 二','陳子昂','唐','唐诗','tang','','[]','赤螭媚其彩，婉孌蒼梧泉。',96,'全唐诗/poet.tang.4000.json','["赤螭媚其彩，婉孌蒼梧泉。", "昔者瑯琊子，躬耕亦慨然。", "美人豈遐曠，之子乃前賢。", "良辰在何許，白日屢頹遷。", "道心固微密，神用無留連。", "舒可彌宇宙，攬之不盈拳。", "蓬萊久蕪沒，金石徒精堅。", "良寶委短褐，閑琴獨嬋娟。"]'),
('27fed33a-9147-49c8-abaa-8b1ed24acc0d','答韓使同在邊','陳子昂','唐','唐诗','tang','','[]','漢家失中策，胡馬屢南驅。',144,'全唐诗/poet.tang.4000.json','["漢家失中策，胡馬屢南驅。", "聞詔安邊使，曾是故人謨。", "廢書悵懷古，負劒許良圖。", "出關歲方晏，乘障日多虞。", "虜入白登道，烽交紫塞途。", "連兵屯北地，清野備東胡。", "邊城方晏閉，斥堠始昭蘇。", "復聞韓長孺，辛苦事匈奴。", "雨雪顏容改，縱橫才位孤。", "空懷老臣策，未獲趙軍租。", "但蒙魏侯重，不受謗書誣。", "當取金人祭，還歌凱入都。"]'),
('41346e48-f881-4c5c-bfd1-035098fc2a35','征東至淇門答宋十一參軍之問','陳子昂','唐','唐诗','tang','','[]','南星中大火，將子涉清淇。',48,'全唐诗/poet.tang.4000.json','["南星中大火，將子涉清淇。", "西林改微月，征斾空自持。", "碧潭去已遠，瑤華折遺誰。", "若問遼陽戍，悠悠天際旗。"]'),
('f499c1aa-a05e-4f24-b637-37d1de936769','答洛陽主人','陳子昂','唐','唐诗','tang','','[]','平生白雲志，早愛赤松遊。',84,'全唐诗/poet.tang.4000.json','["平生白雲志，早愛赤松遊。", "事親恨未立，從宦此中州。", "主人亦何問，旅客非悠悠。", "方謁明天子，清宴奉良籌。", "再取連城璧，三陟平津侯。", "不然拂衣去，歸從海上鷗。", "寧隨當代子，傾側且沈浮。"]'),
('e1620671-e4e3-4866-b52f-ce4a04107fa5','酬暉上人秋夜山亭有贈','陳子昂','唐','唐诗','tang','','["\u79cb\u5929", "\u5199\u666f", "\u8d60\u7b54", "\u665a\u4e0a"]','皎皎白林秋，微微翠山靜。',48,'全唐诗/poet.tang.4000.json','["皎皎白林秋，微微翠山靜。", "禪居感物變，獨坐開軒屏。", "風泉夜聲雜，月露宵光冷。", "多謝忘機人，塵憂未能整。"]'),
('33ed3eeb-86a6-4b77-9fc3-7f4dc78c241e','酬李參軍崇嗣旅館見贈','陳子昂','唐','唐诗','tang','','[]','昨夜銀河畔，星文犯遙漢。',120,'全唐诗/poet.tang.4000.json','["昨夜銀河畔，星文犯遙漢。", "今朝紫氣新，物色果逢真。", "言從天上落，乃是地仙人。", "白璧疑冤楚，烏裘似入秦。", "摧藏多古意，歷覽備艱辛。", "樂廣雲雖覩，夷吾風未春。", "鳳歌空有問，龍性詎能馴。", "寶劒終應出，驪珠會見珍。", "未及馮公老，何驚孺子貧。", "青雲儻可致，北海憶孫賓。"]'),
('4369b3bc-36be-45b7-95ea-3793ce68dad3','酬暉上人夏日林泉','陳子昂','唐','唐诗','tang','','[]','聞道白雲居，窈窕青蓮宇。',48,'全唐诗/poet.tang.4000.json','["聞道白雲居，窈窕青蓮宇。", "巖泉萬丈流，樹石千年古。", "林臥對軒窗，山陰滿庭戶。", "方釋塵事勞，從君襲蘭杜。"]'),
('f00d5956-f824-4533-bd3a-9e7f99018575','同宋參軍之問夢趙六贈盧陳二子之作','陳子昂','唐','唐诗','tang','','[]','曉霽望嵩丘，白雲半巖足。',240,'全唐诗/poet.tang.4000.json','["曉霽望嵩丘，白雲半巖足。", "氛氳涵翠微，宛如嬴臺曲。", "故人昔所尚，幽琴歌斷續。", "變化竟無常，人琴遂兩亡。", "白雲失處所，夢想曖容光。", "疇昔疑緣業，儒道兩相妨。", "前期許幽報，迨此尚茫茫。", "晤言既已失，感歎情何一。", "始憶攜手期，雲臺與峨眉。", "達兼濟天下，窮獨善其時。", "諸君推管樂，之子慕巢夷。", "奈何蒼生望，卒爲黃綬欺。", "銘鼎功未立，山林事亦微。", "撫孤一流慟，懷舊日暌違。", "盧子尚高節，終南臥松雪。", "宋侯逢聖君，驂馭遊青雲。", "而我獨蹭蹬，語默道猶屯。", "征戍在遼陽，蹉跎草再黃。", "丹丘恨不及，白露已蒼蒼。", "遠聞山陽賦，感涕下沾裳。"]'),
('fcf3dd81-c835-406b-a18d-8be09208ed3d','送別出塞','陳子昂','唐','唐诗','tang','','[]','平生聞高義，書劒百夫雄。',72,'全唐诗/poet.tang.4000.json','["平生聞高義，書劒百夫雄。", "言登青雲去，非此白頭翁。", "胡兵屯塞下，漢騎屬雲中。", "君爲白馬將，腰佩騂角弓。", "單于不敢射，天子佇深功。", "蜀山余方隱，良會何時同。"]'),
('11ed5ca2-c7e5-4dbb-a7b5-dcc556b2b04b','登薊丘樓送賈兵曹入都','陳子昂','唐','唐诗','tang','','[]','東山宿昔意，北征非我心。',84,'全唐诗/poet.tang.4000.json','["東山宿昔意，北征非我心。", "孤負平生願，感涕下沾襟。", "暮登薊樓上，永望燕山岑。", "遼海方漫漫，胡沙飛且深。", "峨眉杳如夢，仙子曷由尋。", "擊劒起歎息，白日忽西沈。", "聞君洛陽使，因子寄南音。"]'),
('159c0352-851d-4b1d-816f-282e339a46fa','夏日暉上人房別李參軍崇嗣','陳子昂','唐','唐诗','tang','','[]','四十九變化，一十三死生。',144,'全唐诗/poet.tang.4000.json','["四十九變化，一十三死生。", "翕忽玄黃裏，驅馳風雨情。", "是非紛妄作，寵辱坐相驚。", "至人獨幽鑒，窈窕隨昏明。", "咫尺山河道，軒窗日月庭。", "別離焉足問，悲樂固能幷。", "我輩何爲爾，棲皇猶未平。", "金臺可攀陟，寶界絕將迎。", "戶牖觀天地，階基上杳冥。", "自超三界樂，安知萬里征。", "中國要荒內，人寰宇宙榮。", "弦望如朝夕，寧嗟蜀道行。"]'),
('52e3a479-7c70-4400-9bf9-693905bb9d97','秋園臥病呈暉上人','陳子昂','唐','唐诗','tang','','[]','幽寂曠日遙，林園轉清密。',120,'全唐诗/poet.tang.4000.json','["幽寂曠日遙，林園轉清密。", "疲疴澹無豫，獨坐泛瑤瑟。", "懷挾萬古情，憂虞百年疾。", "綿綿多滯念，忽忽每如失。", "緬想赤松遊，高尋白雲逸。", "榮吝始都喪，幽人遂貞吉。", "圖書紛滿床，山水藹盈室。", "宿昔心所尚，平生自茲畢。", "願言誰見知，梵筵有同術。", "八月高秋晚，涼風正蕭瑟。"]'),
('792eb9a6-3452-4a3d-a8f2-d44b2d832482','登澤州城北樓讌','陳子昂','唐','唐诗','tang','','[]','平生倦遊者，觀化久無窮。',72,'全唐诗/poet.tang.4000.json','["平生倦遊者，觀化久無窮。", "復來登此國，臨望與君同。", "坐見秦兵壘，遙聞趙將雄。", "武安君何在，長平事已空。", "且歌玄雲曲，御酒舞薰風。", "勿使青衿子，嗟爾白頭翁。"]'),
('e21385b2-4aaa-44ba-b18d-ab5f9682713a','山水粉圖','陳子昂','唐','唐诗','tang','','[]','山圖之白雲兮，若巫山之高丘。',45,'全唐诗/poet.tang.4000.json','["山圖之白雲兮，若巫山之高丘。", "紛羣翠之鴻溶，又似蓬瀛海水之周流。", "信夫人之好道，愛雲山以幽求。"]'),
('0c7aaa18-d2ee-4533-ba92-fc1a0dc790ea','綵樹歌','陳子昂','唐','唐诗','tang','','[]','嘉錦筵之珍樹兮，錯衆綵之氛氳。',89,'全唐诗/poet.tang.4000.json','["嘉錦筵之珍樹兮，錯衆綵之氛氳。", "狀瑤臺之微月，點巫山之朝雲。", "青春兮不可逢，況蕙色之增芬。", "結芳意而誰賞，怨絕世之無聞。", "紅榮碧豔坐看歇，素華流年不待君。", "故吾思崑崙之琪樹，厭桃李之繽紛。"]'),
('0b09e4b4-3d7e-4cdf-b91e-c2d50ec14e5f','春臺引','陳子昂','唐','唐诗','tang','','[]','感陽春兮生碧草之油油，懷宇宙以傷遠，登高臺而寫憂。',239,'全唐诗/poet.tang.4000.json','["感陽春兮生碧草之油油，懷宇宙以傷遠，登高臺而寫憂。", "遲美人兮不見，恐青歲之遂遒。", "從畢公以酣飲，寄林塘而一留。", "採芳蓀於北渚，憶桂樹於南州。", "何雲木之美麗，而池館之崇幽。", "星臺秀士，月旦諸子。", "嘉青鳥之辰，迎火龍之始。", "挾寶書與瑤瑟，芳蕙華而蘭靡。", "乃掩白蘋，藉綠芷。", "酒既醉，樂未已。", "擊青鐘，歌淥水。", "怨青春之萎絕，贈瑤臺之旖旎。", "願一見而道意，結衆芳之綢繆。", "曷余情之蕩漾，矚青雲以增愁。", "悵三山之飛鶴，憶海上之白鷗。", "重曰：羣仙去兮青春頹，歲華歇兮黃鳥哀。", "富貴榮樂幾時兮，朱宮碧堂生青苔，白雲兮歸來。"]'),
('c244a5b4-0ed0-48fe-8694-95309acac184','登幽州臺歌','陳子昂','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u4f24\u6000", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u8a00\u53e4\u8bd7"]','前不見古人，後不見來者。',26,'全唐诗/poet.tang.4000.json','["前不見古人，後不見來者。", "念天地之悠悠，獨愴然而涕下。"]'),
('ff6e2546-b554-46b4-bf15-a3d455a6e375','喜馬參軍相遇醉歌','陳子昂','唐','唐诗','tang','','[]','獨幽默以三月兮，深林潛居。',39,'全唐诗/poet.tang.4000.json','["獨幽默以三月兮，深林潛居。", "時歲忽兮，孤憤遐吟。", "誰知我心，孺子孺子，其可與理分。"]'),
('4649fe31-583d-4ce4-a615-f8b3d21cd6f2','度荆門望楚','陳子昂','唐','唐诗','tang','','[]','遙遙去巫峽，望望下章臺。',48,'全唐诗/poet.tang.4000.json','["遙遙去巫峽，望望下章臺。", "巴國山川盡，荆門煙霧開。", "城分蒼野外，樹斷白雲隈。", "今日狂歌客，誰知入楚來。"]'),
('b59f38cf-5ad0-456c-8da8-4df0536f8290','晚次樂鄉縣','陳子昂','唐','唐诗','tang','','["\u601d\u4e61", "\u5bd3\u60c5\u4e8e\u666f"]','故鄉杳無際，日暮且孤征。',48,'全唐诗/poet.tang.4000.json','["故鄉杳無際，日暮且孤征。", "川原迷舊國，道路入邊城。", "野戍荒煙斷，深山古木平。", "如何此時恨，噭噭夜猿鳴。"]'),
('9e45dcf4-2c6d-4fed-b4c2-319251e80563','同王員外雨後登開元寺南樓因酬暉上人獨坐山亭有贈','陳子昂','唐','唐诗','tang','','[]','鐘梵經行罷，香林坐入禪。',48,'全唐诗/poet.tang.4000.json','["鐘梵經行罷，香林坐入禪。", "巖庭交雜樹，石瀨瀉鳴泉。", "水月心方寂，雲霞思獨玄。", "寧知人世裏，疲病得攀緣。"]'),
('6aa56aaa-9f6c-4754-8124-2d5343927ef1','東征答朝臣相送','陳子昂','唐','唐诗','tang','','[]','平生白雲意，疲薾愧爲雄。',48,'全唐诗/poet.tang.4000.json','["平生白雲意，疲薾愧爲雄。", "君王謬殊寵，旌節此從戎。", "挼繩當繫虜，單馬豈邀功。", "孤劒將何托，長謠塞上風。"]'),
('f564368f-34c5-4519-9656-8e2291f3b619','詠主人壁上畫鶴寄喬主簿崔著作','陳子昂','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','古壁仙人畫，丹青尚有文。',48,'全唐诗/poet.tang.4000.json','["古壁仙人畫，丹青尚有文。", "獨舞紛如雪，孤飛曖似雲。", "自矜彩色重，寧憶故池羣。", "江海聯翩翼，長鳴誰復聞。"]'),
('3e5a260f-9d71-435f-b293-5b875a36b0fa','居延海樹聞鶯同作','陳子昂','唐','唐诗','tang','','[]','邊地無芳樹，鶯聲忽聽新。',48,'全唐诗/poet.tang.4000.json','["邊地無芳樹，鶯聲忽聽新。", "間關如有意，愁絕若懷人。", "明妃失漢寵，蔡女沒胡塵。", "坐聞應落淚，況憶故園春。"]'),
('be041e20-6457-4a08-aeed-f318b3025324','題李三書齋','陳子昂','唐','唐诗','tang','','[]','灼灼青春仲，悠悠白日昇。',48,'全唐诗/poet.tang.4000.json','["灼灼青春仲，悠悠白日昇。", "聲容何足恃，榮吝坐相矜。", "願與金庭會，將待玉書徵。", "還丹應有術，煙駕共君乘。"]'),
('edf8dcc9-e351-4348-9de9-465401d15de7','送魏大從軍','陳子昂','唐','唐诗','tang','','["\u8c6a\u653e", "\u7231\u56fd", "\u9001\u522b"]','匈奴猶未滅，魏絳復從戎。',48,'全唐诗/poet.tang.4000.json','["匈奴猶未滅，魏絳復從戎。", "悵別三河道，言追六郡雄。", "雁山橫代北，狐塞接雲中。", "勿使燕然上，惟留漢將功。"]'),
('6e1cc583-7d7b-429d-bfda-f88f696001ec','送殷大入蜀','陳子昂','唐','唐诗','tang','','[]','禺山金碧路，此地饒英靈。',48,'全唐诗/poet.tang.4000.json','["禺山金碧路，此地饒英靈。", "送君一爲別，悽斷故鄉情。", "片雲生極浦，斜日隱離亭。", "坐看征騎沒，惟見遠山青。"]'),
('aafc4eea-04f2-43c0-b0b7-356194b8ef04','落第西還別劉祭酒高明府','陳子昂','唐','唐诗','tang','','[]','別館分周國，歸驂入漢京。',48,'全唐诗/poet.tang.4000.json','["別館分周國，歸驂入漢京。", "地連函谷塞，川接廣陽城。", "望迥樓臺出，途遙煙霧生。", "莫言長落羽，貧賤一交情。"]'),
('07965c4e-274f-448f-b259-770fd9479727','落第西還別魏四懍','陳子昂','唐','唐诗','tang','','[]','轉蓬方不定，落羽自驚弦。',48,'全唐诗/poet.tang.4000.json','["轉蓬方不定，落羽自驚弦。", "山水一爲別，歡娛復幾年。", "離亭暗風雨，征路入雲煙。", "還因北山逕，歸守東陂田。"]'),
('84790fee-2ec6-4e29-b63c-7c34a62bb647','送客','陳子昂','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','故人洞庭去，楊柳春風生。',48,'全唐诗/poet.tang.4000.json','["故人洞庭去，楊柳春風生。", "相送河洲晚，蒼茫別思盈。", "白蘋已堪把，綠芷復含榮。", "江南多桂樹，歸客贈生平。"]'),
('8f2c0609-680d-41b8-ac33-d377d0ece8f5','春夜別友人二首 一','陳子昂','唐','唐诗','tang','','["\u79bb\u522b", "\u5bb4\u996e", "\u76f8\u601d"]','銀燭吐青煙，金樽對綺筵。',48,'全唐诗/poet.tang.4000.json','["銀燭吐青煙，金樽對綺筵。", "離堂思琴瑟，別路遶山川。", "明月隱高樹，長河沒曉天。", "悠悠洛陽道，此會在何年。"]'),
('cddc4453-683b-4476-8447-569bf85c15c2','春夜別友人二首 二','陳子昂','唐','唐诗','tang','','["\u79bb\u522b", "\u53cb\u4eba", "\u6101\u7eea", "\u5199\u666f"]','紫塞白雲斷，青春明月初。',48,'全唐诗/poet.tang.4000.json','["紫塞白雲斷，青春明月初。", "對此芳樽夜，離憂悵有餘。", "清冷花露滿，滴瀝檐宇虛。", "懷君欲何贈，願上大臣書。"]'),
('a5d6804d-5f10-4cbe-b54d-b9ad12c6910a','遂州南江別鄉曲故人','陳子昂','唐','唐诗','tang','','[]','楚江復爲客，征棹方悠悠。',48,'全唐诗/poet.tang.4000.json','["楚江復爲客，征棹方悠悠。", "故人憫追送，置酒此南洲。", "平生亦何恨，夙昔在林丘。", "違此鄉山別，長謠去國愁。"]'),
('fe399c82-1a77-41b8-8275-c9ab0f62aa39','送東萊王學士無競','陳子昂','唐','唐诗','tang','','["\u9ad8\u5c1a", "\u6292\u60c5", "\u5199\u4eba", "\u8d5e\u7f8e", "\u54c1\u683c", "\u6124\u61d1"]','寶劒千金買，平生未許人。',48,'全唐诗/poet.tang.4000.json','["寶劒千金買，平生未許人。", "懷君萬里別，持贈結交親。", "孤松宜晚歲，衆木愛芳春。", "已矣將何道，無令白首新。"]'),
('167422ef-6ad8-4fc5-ac5e-7ae43dd60491','送梁李二明府','陳子昂','唐','唐诗','tang','','[]','負書猶在漢，懷策未聞秦。',48,'全唐诗/poet.tang.4000.json','["負書猶在漢，懷策未聞秦。", "復此窮秋日，芳樽別故人。", "黃金裝屢盡，白首契逾新。", "空羨雙鳧舄，俱飛向玉輪。"]'),
('043898cb-8c03-4452-abc4-0044ab6d69c0','送魏兵曹使嶲州得登字','陳子昂','唐','唐诗','tang','','[]','陽山淫霧雨，之子慎攀登。',48,'全唐诗/poet.tang.4000.json','["陽山淫霧雨，之子慎攀登。", "羗笮多珍寶，人言有愛憎。", "欲酬明主惠，當盡使臣能。", "勿以王陽道，迢遞畏崚嶒。"]'),
('5f024768-7d7f-49d4-90c3-004541ece6e1','送著作佐郎崔融等從梁王東征','陳子昂','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u529d\u8beb"]','金天方肅殺，白露始專征。',48,'全唐诗/poet.tang.4000.json','["金天方肅殺，白露始專征。", "王師非樂戰，之子慎佳兵。", "海氣侵南部，邊風掃北平。", "莫賣盧龍塞，歸邀麟閣名。"]'),
('e1383682-eae8-4a2e-b529-fdc760dff4ef','春晦餞陶七於江南同用風字','陳子昂','唐','唐诗','tang','','[]','黃鶴煙雲去，青江琴酒同。',48,'全唐诗/poet.tang.4000.json','["黃鶴煙雲去，青江琴酒同。", "離帆方楚越，溝水復西東。", "芙蓉生夏浦，楊柳送春風。", "明日相思處，應對菊花叢。"]'),
('309ab392-7ff3-4f0a-a294-340f2e3f9dad','喜遇冀侍御珪崔司議泰之二使','陳子昂','唐','唐诗','tang','','[]','謝病南山下，幽臥不知春。',48,'全唐诗/poet.tang.4000.json','["謝病南山下，幽臥不知春。", "使星入東井，云是故交親。", "惠風吹寶瑟，微月憶清真。", "憑軒一留醉，江海寄情人。"]'),
('e5cb6407-7b81-4293-b304-3b5d33f89056','登薊城西北樓送崔著作融入都','陳子昂','唐','唐诗','tang','','[]','薊樓望燕國，負劒喜茲登。',48,'全唐诗/poet.tang.4000.json','["薊樓望燕國，負劒喜茲登。", "清規子方奏，單戟我無能。", "仲冬邊風急，雲漢復霜稜。", "慷慨竟何道，西南恨失朋。"]'),
('a73f37fb-0d50-4144-9775-f2646e14373d','月夜有懷','陳子昂','唐','唐诗','tang','','[]','美人挾趙瑟，微月在西軒。',48,'全唐诗/poet.tang.4000.json','["美人挾趙瑟，微月在西軒。", "寂寞夜何久，殷勤玉指繁。", "清光委衾枕，遙思屬湘沅。", "空簾隔星漢，猶夢感精魂。"]'),
('f2e0553c-9b06-4284-ad2d-fa905c0d60cc','夏日遊暉上人房','陳子昂','唐','唐诗','tang','','[]','山水開精舍，琴歌列梵筵。',48,'全唐诗/poet.tang.4000.json','["山水開精舍，琴歌列梵筵。", "人疑白樓賞，地似竹林禪。", "對戶池光亂，交軒巖翠連。", "色空今已寂，乘月弄澄泉。"]'),
('e2592592-68d0-44db-8f57-bff9a4bef624','春日登金華觀','陳子昂','唐','唐诗','tang','','[]','白玉仙臺古，丹丘別望遙。',48,'全唐诗/poet.tang.4000.json','["白玉仙臺古，丹丘別望遙。", "山川亂雲日，樓榭入煙霄。", "鶴舞千年樹，虹飛百尺橋。", "還疑赤松子，天路坐相邀。"]'),
('51a6da3f-0fff-4bff-8b96-04a5f61bcf29','羣公集畢氏林亭','陳子昂','唐','唐诗','tang','','[]','金門有遺世，鼎實恣和邦。',48,'全唐诗/poet.tang.4000.json','["金門有遺世，鼎實恣和邦。", "默語誰能識，琴樽寄北窗。", "子牟戀魏闕，漁父愛滄江。", "良時信同此，歲晚迹難雙。"]'),
('bbc2c7e5-49f1-4d76-b79b-fe59babad367','宴胡楚真禁所','陳子昂','唐','唐诗','tang','','[]','人生固有命，天道信無言。',48,'全唐诗/poet.tang.4000.json','["人生固有命，天道信無言。", "青繩一相點，白璧遂成冤。", "請室閑逾邃，幽庭春未暄。", "寄謝韓安國，何驚獄吏尊。"]'),
('8779ed36-367b-4eac-9238-d6de7d789d5f','魏氏園林人賦一物得秋亭萱草','陳子昂','唐','唐诗','tang','','[]','昔時幽徑裏，榮耀雜春叢。',48,'全唐诗/poet.tang.4000.json','["昔時幽徑裏，榮耀雜春叢。", "今來玉墀上，銷歇畏秋風。", "細葉猶含綠，鮮花未吐紅。", "忘憂誰見賞，空此北堂中。"]'),
('d089e270-7c9d-4cbf-811a-5b84c7a2dc7c','晦日宴高氏林亭','陳子昂','唐','唐诗','tang','','[]','尋春遊上路，追宴入山家。',48,'全唐诗/poet.tang.4000.json','["尋春遊上路，追宴入山家。", "主第簪纓滿，皇州景望華。", "玉池初吐溜，珠樹始開花。", "歡娛方未極，林閣散餘霞。"]'),
('902a1310-1b42-4d91-acea-152d386e8504','晦日重宴高氏林亭','陳子昂','唐','唐诗','tang','','[]','公子好追隨，愛客不知疲。',36,'全唐诗/poet.tang.4000.json','["公子好追隨，愛客不知疲。", "象筵開玉饌，翠羽飾金巵。", "此時高宴所，詎減習家池。"]'),
('2955b0c3-7e1d-4ffb-aaac-01619e09266f','上元夜效小庾體','陳子昂','唐','唐诗','tang','','[]','三五月華新，遨遊逐上春。',48,'全唐诗/poet.tang.4000.json','["三五月華新，遨遊逐上春。", "相邀洛城曲，追宴小平津。", "樓上看珠妓，車中見玉人。", "芳宵殊未極，隨意守燈輪。"]'),
('94e277fe-052a-45b1-b5b6-d0a337f31ff6','洛城觀酺應制','陳子昂','唐','唐诗','tang','','[]','聖人信恭己，天命允昭回。',96,'全唐诗/poet.tang.4000.json','["聖人信恭己，天命允昭回。", "蒼極神功被，青雲祕籙開。", "垂衣受金冊，張樂宴瑤臺。", "雲鳳休徵滿，魚龍雜戲來。", "崇恩踰五日，惠澤暢三才。", "玉帛羣臣醉，徽章縟禮該。", "方覩升中禪，言觀拜洛迴。", "微臣固多幸，敢上萬年杯。"]'),
('fecaefd1-4271-4114-ab80-bddd81bd5886','奉和皇帝上禮撫事述懷應制','陳子昂','唐','唐诗','tang','','[]','大君忘自我，應運居紫宸。',120,'全唐诗/poet.tang.4000.json','["大君忘自我，應運居紫宸。", "揖讓期明辟，謳歌且順人。", "軒宮帝圖盛，皇極禮容申。", "南面朝萬國，東堂會百神。", "雲陛旂常滿，天庭玉帛陳。", "鐘石和睿思，雷雨被深仁。", "承平信娛樂，王業本艱辛。", "願罷瑤池宴，來觀農扈春。", "卑宮昭夏德，尊老睦堯親。", "微臣敢拜手，歌舞頌維新。"]'),
('36d4d9d7-31e7-473d-98be-9f049add404d','酬田逸人遊巖見尋不遇題隱居里壁','陳子昂','唐','唐诗','tang','','[]','遊人獻書去，薄暮返靈臺。',60,'全唐诗/poet.tang.4000.json','["遊人獻書去，薄暮返靈臺。", "傳道尋仙友，青囊賣卜來。", "聞鶯忽相訪，題鳳久裴回。", "石髓空盈握，金經祕不開。", "還疑縫掖子，復似洛陽才。"]'),
('a82d7998-836d-419e-90b6-cfda7568d8af','白帝城懷古','陳子昂','唐','唐诗','tang','','["\u7231\u56fd", "\u6000\u53e4", "\u5199\u666f", "\u6292\u60c5", "\u5730\u65b9", "\u611f\u6168"]','日落滄江晚，停橈問土風。',72,'全唐诗/poet.tang.4000.json','["日落滄江晚，停橈問土風。", "城臨巴子國，臺沒漢王宮。", "荒服任周甸，深山尚禹功。", "巖懸青壁斷，地險碧流通。", "古木生雲際，孤帆出霧中。", "川途去無限，客思坐何窮。"]'),
('a6ca35ce-c68f-491a-8455-cafd4dc421ed','峴山懷古','陳子昂','唐','唐诗','tang','','["\u6292\u60c5", "\u767b\u9ad8", "\u6000\u53e4"]','秣馬臨荒甸，登高覽舊都。',72,'全唐诗/poet.tang.4000.json','["秣馬臨荒甸，登高覽舊都。", "猶悲墮淚碣，尚想臥龍圖。", "城邑遙分楚，山川半入吳。", "丘陵徒自出，賢聖幾凋枯。", "野樹蒼煙斷，津樓晚氣孤。", "誰知萬里客，懷古正躊躕。"]'),
('373d9a22-c9c0-4b03-b44f-32364e8a0eeb','宿空舲峽青樹邨浦','陳子昂','唐','唐诗','tang','','[]','的的明月水，啾啾寒夜猿。',72,'全唐诗/poet.tang.4000.json','["的的明月水，啾啾寒夜猿。", "客思浩方亂，洲浦寂無喧。", "憶作千金子，寧知九逝魂。", "虛聞事朱闕，結綬騖華軒。", "委別高堂愛，窺覦明主恩。", "今成轉蓬去，歎息復何言。"]'),
('38b8f8b9-fa3b-4388-b2d6-49e42a1cb796','宿襄河驛浦','陳子昂','唐','唐诗','tang','','[]','沿流辭北渚，結纜宿南洲。',72,'全唐诗/poet.tang.4000.json','["沿流辭北渚，結纜宿南洲。", "合岸昏初夕，廻塘暗不流。", "臥聞塞鴻斷，坐聽峽猿愁。", "沙浦明如月，汀葭晦若秋。", "不及能鳴雁，徒思海上鷗。", "天河殊未曉，滄海信悠悠。"]'),
('9fe27593-d067-4479-8a8c-7eec5ede7e92','贈嚴倉曹乞推命錄','陳子昂','唐','唐诗','tang','','[]','少學縱橫術，遊楚復遊燕。',72,'全唐诗/poet.tang.4000.json','["少學縱橫術，遊楚復遊燕。", "棲遑長委命，富貴未知天。", "聞道沈冥客，青囊有秘篇。", "九宮探萬象，三算極重玄。", "願奉唐生訣，將知躍馬年。", "非同墨翟問，空滯殺龍川。"]'),
('8f5789d8-49a7-44eb-8957-09443c891107','和陸明府贈將軍重出塞','陳子昂','唐','唐诗','tang','','["\u9001\u522b", "\u5c06\u519b", "\u8c6a\u8fc8", "\u8d5e\u7f8e"]','忽聞天上將，關塞重橫行。',72,'全唐诗/poet.tang.4000.json','["忽聞天上將，關塞重橫行。", "始返樓蘭國，還向朔方城。", "黃金裝戰馬，白羽集神兵。", "星月開天陣，山川列地營。", "晚風吹畫角，春色耀飛旌。", "寧知班定遠，猶是一書生。"]'),
('9b21246a-746d-4d0a-b438-7e55eb793ca8','江上暫別蕭四劉三旋欣接遇','陳子昂','唐','唐诗','tang','','[]','昨夜滄江別，言乖天漢遊。',72,'全唐诗/poet.tang.4000.json','["昨夜滄江別，言乖天漢遊。", "寧期此相遇，尚接武陵洲。", "結綬還逢育，銜杯且對劉。", "波潭一瀰瀰，臨望幾悠悠。", "山水丹青雜，煙雲紫翠浮。", "終愧神仙友，來接野人舟。"]'),
('36a0e625-bdbe-4bae-bf49-d4db36e135db','秋日遇荆州府崔兵曹使宴','陳子昂','唐','唐诗','tang','','[]','輶軒鳳皇使，林藪鶡雞冠。',72,'全唐诗/poet.tang.4000.json','["輶軒鳳皇使，林藪鶡雞冠。", "江湖一相許，雲霧坐交歡。", "興盡崔亭伯，言忘釋道安。", "林光稍欲暮，歲物已將闌。", "古樹蒼煙斷，虛亭白露寒。", "瑤琴山水曲，今日爲君彈。"]'),
('1fdfef2c-bb0e-49eb-9d3e-a06bfd49b8d0','臥病家園','陳子昂','唐','唐诗','tang','','[]','世上無名子，人間歲月賒。',72,'全唐诗/poet.tang.4000.json','["世上無名子，人間歲月賒。", "縱橫策已棄，寂寞道爲家。", "臥病誰能問，閒居空物華。", "猶憶靈臺友，棲真隱太霞。", "還丹奔日御，却老餌雲芽。", "寧知白社客，不厭青門瓜。"]'),
('b6537bdd-3490-4a1c-a5f2-bf6be6c2c55b','于長史山池三日曲水宴','陳子昂','唐','唐诗','tang','','[]','摘蘭藉芳月，祓宴坐廻汀。',72,'全唐诗/poet.tang.4000.json','["摘蘭藉芳月，祓宴坐廻汀。", "泛灩清流滿，葳蕤白芷生。", "金弦揮趙瑟，玉指弄秦箏。", "巖榭風光媚，郊園春樹平。", "煙花飛御道，羅綺照昆明。", "日落紅塵合，車馬亂縱橫。"]'),
('08e9f33f-c0dd-4c3e-a5af-e71c9e56cb07','合州津口別舍弟至東陽峽步趂不及眷然有憶作以示之','陳子昂','唐','唐诗','tang','','[]','江潭共爲客，洲浦獨迷津。',84,'全唐诗/poet.tang.4000.json','["江潭共爲客，洲浦獨迷津。", "思積芳庭樹，心斷白眉人。", "同衾成楚越，別島類胡秦。", "林岸隨天轉，雲峰逐望新。", "遙遙終不見，默默坐含嚬。", "念別疑三月，經遊未一旬。", "孤舟多逸興，誰共爾爲鄰。"]'),
('33887bff-a836-4320-8f96-f9f4d34e34c2','萬州曉發放舟乘漲還寄蜀中親朋','陳子昂','唐','唐诗','tang','','[]','空濛巖雨霽，爛熳曉雲歸。',96,'全唐诗/poet.tang.4000.json','["空濛巖雨霽，爛熳曉雲歸。", "嘯旅乘明發，奔橈騖斷磯。", "蒼茫林岫轉，絡繹漲濤飛。", "遠岸孤煙出，遙峰曙日微。", "前瞻未能眴，坐望已相依。", "曲直多今古，經過失是非。", "還期方浩浩，征思日騑騑。", "寄謝千金子，江海事多違。"]'),
('33678a13-152a-423c-ac13-c1f3b2164c88','入峭峽安居谿伐木谿源幽邃林嶺相映有奇致焉','陳子昂','唐','唐诗','tang','','[]','肅徒歌伐木，騖檝漾輕舟。',108,'全唐诗/poet.tang.4000.json','["肅徒歌伐木，騖檝漾輕舟。", "靡迤隨廻水，潺湲泝淺流。", "煙沙分兩岸，露島夾雙洲。", "古樹連雲密，交峰入浪浮。", "巖潭相映媚，谿谷屢環周。", "路迥光逾逼，山深興轉幽。", "麕鼯寒思晚，猿鳥暮聲秋。", "誓息蘭臺策，將從桂樹遊。", "因書謝親愛，千歲覓蓬丘。"]'),
('23f73293-7bd0-420d-bbc8-d66b53abddef','入東陽峽與李明府舟前後不相及','陳子昂','唐','唐诗','tang','','[]','東巖初解纜，南浦遂離羣。',120,'全唐诗/poet.tang.4000.json','["東巖初解纜，南浦遂離羣。", "出沒同洲島，沿洄異渚濆。", "風煙猶可望，歌笑浩難聞。", "路轉青山合，峰廻白日曛。", "奔濤上漫漫，積水下沄沄。", "倏忽猶疑及，差池復兩分。", "離離間遠樹，藹藹沒遙氛。", "地上巴陵道，星連牛斗文。", "孤狖啼寒月，哀鴻呌斷雲。", "仙舟不可見，搖思坐氛氳。"]'),
('af5ef458-310a-449a-9d31-6175f68beafb','同旻上人傷壽安傅少府','陳子昂','唐','唐诗','tang','','[]','生涯良浩浩，天命固諄諄。',120,'全唐诗/poet.tang.4000.json','["生涯良浩浩，天命固諄諄。", "聞道神仙尉，懷德遂爲鄰。", "疇昔逢堯日，衣冠仕漢辰。", "交遊紛若鳳，詞翰宛如麟。", "太息勞黃綬，長思謁紫宸。", "金蘭徒有契，玉樹已埋塵。", "把臂雖無託，平生固亦親。", "援琴一流涕，舊館幾霑巾。", "杳杳泉中夜，悠悠世上春。", "幽明長隔此，歌哭爲何人。"]'),
('1388d7d7-5fd7-4b17-8adb-ea66d045dea9','南山家園林木交映盛夏五月幽然清涼獨坐思遠率成十韻','陳子昂','唐','唐诗','tang','','[]','寂寥守寒巷，幽獨臥空林。',120,'全唐诗/poet.tang.4000.json','["寂寥守寒巷，幽獨臥空林。", "松竹生虛白，階庭橫古今。", "鬱蒸炎夏晚，棟宇閟清陰。", "軒窗交紫靄，簷戶對蒼岑。", "鳳蘊仙人籙，鸞歌素女琴。", "忘機委人代，閉牖察天心。", "蛺蝶憐紅藥，蜻蜓愛碧潯。", "坐觀萬象化，方見百年侵。", "擾擾將何息，青青長苦吟。", "願隨白雲駕，龍鶴相招尋。"]'),
('3c8b680e-ed52-4e35-ab8a-cf675c2e6c4e','還至張掖古城聞東軍告捷贈韋五虛己','陳子昂','唐','唐诗','tang','','[]','孟秋首歸路，仲月旅邊亭。',132,'全唐诗/poet.tang.4000.json','["孟秋首歸路，仲月旅邊亭。", "聞道蘭山戰，相邀在井陘。", "屢鬬關月滿，三捷虜雲平。", "漢軍追北地，胡騎走南庭。", "君爲幕中士，疇昔好言兵。", "白虎鋒應出，青龍陣幾成。", "披圖見丞相，按節入咸京。", "寧知玉門道，翻作隴西行。", "北海朱旄落，東歸白露生。", "縱橫未得意，寂寞寡相迎。", "負劒空歎息，蒼茫登古城。"]'),
('ae094f36-9ed9-4687-b926-72e3053f2484','題祀山烽樹贈喬十二侍御','陳子昂','唐','唐诗','tang','','[]','漢庭榮巧宦，雲閣薄邊功。',24,'全唐诗/poet.tang.4000.json','["漢庭榮巧宦，雲閣薄邊功。", "可憐驄馬使，白首爲誰雄。"]'),
('c361c97a-f3e4-40f7-8b50-0bc236efcf10','初入峽苦風寄故鄉親友','陳子昂','唐','唐诗','tang','','[]','故鄉今日友，歡會坐應同。',24,'全唐诗/poet.tang.4000.json','["故鄉今日友，歡會坐應同。", "寧知巴峽路，辛苦石尤風。"]'),
('3e5a9ae0-5a39-478a-9a85-98edaafd321f','題田洗馬遊巖桔槔','陳子昂','唐','唐诗','tang','','[]','望苑長爲客，商山遂不歸。',24,'全唐诗/poet.tang.4000.json','["望苑長爲客，商山遂不歸。", "誰憐北陵井，未息漢陰機。"]'),
('ae67aa0c-09f7-479a-839c-7bd635d6ff48','古意題徐令壁','陳子昂','唐','唐诗','tang','','[]','白雲蒼梧來，氛氳萬里色。',24,'全唐诗/poet.tang.4000.json','["白雲蒼梧來，氛氳萬里色。", "聞君太平世，棲泊靈臺側。"]'),
('aacccb99-3312-4253-a2a4-3099992eaa2c','贈別冀侍御崔司議','陳子昂','唐','唐诗','tang','','[]','有道君匡國，無悶余在林。',24,'全唐诗/poet.tang.4000.json','["有道君匡國，無悶余在林。", "白雲峨眉上，歲晚來相尋。"]'),
('0b5ba9aa-1472-44a9-bbb2-6ef28427df63','三月三日宴王明府山亭','陳子昂','唐','唐诗','tang','','[]','暮春嘉月，上巳芳辰。',60,'全唐诗/poet.tang.4000.json','["暮春嘉月，上巳芳辰。", "羣公禊飲，于洛之濱。", "奕奕車騎，粲粲都人。", "連帷競野，袨服縟津。", "青郊樹密，翠渚萍新。", "今我不樂，含意□申。"]'),
('ce8e3003-0741-4a1d-94ee-761086827b5d','唐封泰山樂章 豫和六首 一','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','挹泰壇，紫泰清。',32,'全唐诗/poet.tang.4000.json','["挹泰壇，紫泰清。", "受天命，報天成。", "竦皇心，薦樂聲。", "志上達，歌下迎。"]'),
('091e047c-9f70-40c9-a30c-b578c8416fa3','唐封泰山樂章 豫和六首 二','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','億上帝，臨下庭。',32,'全唐诗/poet.tang.4000.json','["億上帝，臨下庭。", "騎日月，陪列星。", "嘉視信，大糦聲。", "澹神心，醉皇靈。"]'),
('1a7e9ebf-3577-41dd-af76-0b172828bc4b','唐封泰山樂章 豫和六首 三','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','相百辟，貢八荒。',32,'全唐诗/poet.tang.4000.json','["相百辟，貢八荒。", "九歌敘，萬舞翔。", "肅振振，鏗皇皇。", "帝欣欣，福穰穰。"]'),
('dd168ba5-e055-4c6d-aadb-42870f80391c','唐封泰山樂章 豫和六首 四','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','高在上，道光明。',32,'全唐诗/poet.tang.4000.json','["高在上，道光明。", "物資始，德難名。", "承眷命，牧蒼生。", "寰宇謐，泰階平。"]'),
('0525e3ad-b2cd-448a-8432-a3d9cff1639b','唐封泰山樂章 豫和六首 五','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','天道無親，至誠與鄰。',40,'全唐诗/poet.tang.4000.json','["天道無親，至誠與鄰。", "山川遍禮，宮徵惟新。", "玉帛非盛，聰明會真。", "正斯一德，通乎百神。"]'),
('2aa4faf5-71fb-4721-a191-4bb415b7ee8a','唐封泰山樂章 豫和六首 六','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','享帝享親，維孝維聖。',40,'全唐诗/poet.tang.4000.json','["享帝享親，維孝維聖。", "緝熙懿德，敷揚成命。", "華夷志同，笙鏞禮盛。", "明靈降止，感此誠敬。"]'),
('440b840d-d9d0-419b-8e03-aca8a10fbcb9','唐封泰山樂章 太和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','孝敬中發，和容外彰。',40,'全唐诗/poet.tang.4000.json','["孝敬中發，和容外彰。", "騰華照宇，如昇太陽。", "貞璧就奠，玄靈垂光。", "禮樂具舉，濟濟洋洋。"]'),
('67f4029f-9090-4253-9544-2e90df171abd','唐封泰山樂章 肅和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','奠祖配天，承天享帝。',40,'全唐诗/poet.tang.4000.json','["奠祖配天，承天享帝。", "百靈咸秩，四海來祭。", "植我蒼璧，布我玄製。", "華日裴回，神煙容裔。"]'),
('d3846ed3-9fe0-4c1c-b225-3ff1917b059c','唐封泰山樂章 雍和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','俎豆有馥，粢盛絜豐。',40,'全唐诗/poet.tang.4000.json','["俎豆有馥，粢盛絜豐。", "亦有和羹，既戒既平。", "鼓鐘管磬，肅唱和鳴。", "皇皇我祖，來我思成。"]'),
('6b773a93-eddb-44b8-a00e-82cd2dfe4af5','唐封泰山樂章 壽和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','烝烝我后，享獻惟寅。',40,'全唐诗/poet.tang.4000.json','["烝烝我后，享獻惟寅。", "躬酌鬱鬯，跪奠明神。", "孝莫孝乎，配上帝親。", "敬莫敬乎，教天下臣。"]'),
('0f55cac7-8e74-4692-97de-a67d0c443c66','唐封泰山樂章 壽和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','皇祖嚴配，配享皇天。',20,'全唐诗/poet.tang.4000.json','["皇祖嚴配，配享皇天。", "皇皇降嘏，天子萬年。"]'),
('92a18743-c88d-4cd3-b654-b82b0cada99e','唐封泰山樂章 舒和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','六鐘翕協六變成，八佾徜徉八風生。',36,'全唐诗/poet.tang.4000.json','["六鐘翕協六變成，八佾徜徉八風生。", "樂九[韶]兮[人神]感，美七德兮天地清。"]'),
('7b53b6fe-49aa-4ca3-a09a-f5c053543b79','唐封泰山樂章 凱和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','烈祖順三靈，文宗威四海。',48,'全唐诗/poet.tang.4000.json','["烈祖順三靈，文宗威四海。", "黃鉞誅羣盜，朱旗掃多罪。", "戢兵天下安，約法人心改。", "大哉干羽意，常見風雲在。"]'),
('f4bc9ca4-dab8-40de-b76c-29ab3e6640e7','唐封泰山樂章 豫和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','禮樂終，[煙]燎上。',36,'全唐诗/poet.tang.4000.json','["禮樂終，[煙]燎上。", "懷靈惠，結皇想。", "歸風疾，回風爽。", "百[福]來，衆神往。"]'),
('78df6ed3-3b15-4e1a-b8e9-8da3e0ac95bc','唐享太廟樂章 永和三首 一','張說','唐','唐诗','tang','','[]','肅九室，諧八音。',32,'全唐诗/poet.tang.4000.json','["肅九室，諧八音。", "歌皇慕，動神心。", "禮宿設，樂妙尋。", "聲明備，祼奠臨。"]'),
('5a50afa2-92f0-4ff8-8da7-0bed702c39fc','唐享太廟樂章 永和三首 二','張說','唐','唐诗','tang','','[]','律迓氣，音入玄。',32,'全唐诗/poet.tang.4000.json','["律迓氣，音入玄。", "依玉几，御黼筵。", "聆愾息，僾周旋。", "九韶徧，百福傳。"]'),
('a1497c90-e83d-4b81-a5c7-d38c361e08b7','唐享太廟樂章 永和三首 三','張說','唐','唐诗','tang','','[]','信工祝，永頌聲。',32,'全唐诗/poet.tang.4000.json','["信工祝，永頌聲。", "來祖考，聽和平。", "相百辟，貢九瀛。", "神休委，帝孝成。"]'),
('e8203ddb-a0d5-49ef-9fea-721a17b09491','唐享太廟樂章 太和','張說','唐','唐诗','tang','','[]','時文聖后，清廟肅邕。',40,'全唐诗/poet.tang.4000.json','["時文聖后，清廟肅邕。", "致誠勤薦，在貌思恭。", "玉節肆夏，金鏘五鐘。", "繩繩雲步，穆穆天容。"]'),
('01c5f01f-b1a6-457e-b288-1ba08ccb2c13','唐享太廟樂章 肅和','張說','唐','唐诗','tang','','[]','天子享孝，工歌溥將。',40,'全唐诗/poet.tang.4000.json','["天子享孝，工歌溥將。", "射祼鬱鬯，乃焚膋薌。", "臭以達旨，聲以求陽。", "奉時烝嘗，永代不忘。"]'),
('5106cdbd-2fb3-42d0-ac9f-bb393416b4c4','唐享太廟樂章 雍和二首 一','張說','唐','唐诗','tang','','[]','在滌嘉豢，麗碑敬牲。',40,'全唐诗/poet.tang.4000.json','["在滌嘉豢，麗碑敬牲。", "角握之牝，色純之騂。", "火傳陽燧，水溉陰精。", "太公胖俎，傅說和羹。"]'),
('d2396a68-1853-4969-a3c9-42666a157f39','唐享太廟樂章 雍和二首 二','張說','唐','唐诗','tang','','[]','俎豆有馥，齊盛絜豐。',40,'全唐诗/poet.tang.4000.json','["俎豆有馥，齊盛絜豐。", "亦有和羹，既戒既平。", "鼓鐘管磬，肅唱和鳴。", "皇皇后祖，來我思成。"]'),
('cb0ce32f-de5e-450c-a271-242f7c87f48d','唐享太廟樂章 文舞','張說','唐','唐诗','tang','','[]','聖謨九德，真言五千。',100,'全唐诗/poet.tang.4000.json','["聖謨九德，真言五千。", "慶集昌胄，符開帝先。", "高文杖鉞，克配彼天。", "三宗握鏡，六合渙燃。", "帝其承祀，率禮罔愆。", "圖書霧出，日月清懸。", "舞形德類，詠諗功傳。", "黃龍蜿蟺，彩雲蹁躚。", "五行氣順，八佾風宣。", "介此百祿，於皇萬年。"]'),
('7a2700d9-5ff7-4535-b1fc-2154886f28a2','唐享太廟樂章 光大舞','張說','唐','唐诗','tang','','[]','肅肅藝祖，滔滔濬源。',40,'全唐诗/poet.tang.4000.json','["肅肅藝祖，滔滔濬源。", "有雄玉劒，作鎮金門。", "玄王貽緒，后稷謀孫。", "肇禋九廟，四海來尊。"]'),
('c7322d88-e16c-4607-8649-e22e65d52f4a','唐享太廟樂章 長發舞','張說','唐','唐诗','tang','','[]','具禮崇德，備樂承風。',40,'全唐诗/poet.tang.4000.json','["具禮崇德，備樂承風。", "魏推幢主，周贈司空。", "不行而至，無成有終。", "神興王業，天歸帝功。"]'),
('ea9e6eea-ced2-4495-b994-358bc3de1956','唐享太廟樂章 大政舞','張說','唐','唐诗','tang','','[]','於赫元命，權輿帝文。',40,'全唐诗/poet.tang.4000.json','["於赫元命，權輿帝文。", "天齊八柱，地半三分。", "宗廟觀德，笙鏞樂勳。", "封唐之兆，成天下君。"]'),
('85404b91-989a-4bb9-967a-4903d7a8fa97','唐享太廟樂章 大成舞','張說','唐','唐诗','tang','','[]','帝舞季歷，龍聖生昌。',40,'全唐诗/poet.tang.4000.json','["帝舞季歷，龍聖生昌。", "后歌有蟜，胎炎孕黃。", "天地合德，日月齊光。", "肅雍孝享，祚我萬方。"]'),
('0b032d71-6e53-4f6a-ad71-786202a0b486','唐享太廟樂章 大明舞','張說','唐','唐诗','tang','','[]','赤精亂德，四海困窮。',40,'全唐诗/poet.tang.4000.json','["赤精亂德，四海困窮。", "黃旗舉義，三靈會同。", "早望春雨，雲披大風。", "溥天來祭，高祖之功。"]'),
('221980c0-157e-4ab7-9286-c5c09463a723','唐享太廟樂章 崇德舞','張說','唐','唐诗','tang','','[]','皇合一德，朝宗百神。',40,'全唐诗/poet.tang.4000.json','["皇合一德，朝宗百神。", "削平天地，大拯生人。", "上帝配食，單于入臣。", "戎歌陳武，曄曄震震。"]'),
('88b5df22-c75a-4f22-a228-fba21d052255','唐享太廟樂章 鈞天舞','張說','唐','唐诗','tang','','[]','高皇邁道，端拱無爲。',42,'全唐诗/poet.tang.4000.json','["高皇邁道，端拱無爲。", "化懷獯鬻，兵[戢]句驪。", "禮尊封禪，樂盤來儀。", "合位媧后，同稱伏羲。"]'),
('1f8b24bd-ff95-4886-bde5-c1e36b266441','唐享太廟樂章 大和舞','張說','唐','唐诗','tang','','[]','退居江水，鬱起丹陵。',40,'全唐诗/poet.tang.4000.json','["退居江水，鬱起丹陵。", "禮物還舊，朝章中興。", "龍圖友及，駿命恭膺。", "鳴球香瓚，大糦是承。"]'),
('eb9ea81a-58f9-4e82-b85f-b44498660479','唐享太廟樂章 景雲舞','張說','唐','唐诗','tang','','[]','景雲霏爛，告我帝符。',40,'全唐诗/poet.tang.4000.json','["景雲霏爛，告我帝符。", "噫帝沖德，與天爲徒。", "笙鏞遙遠，俎豆虛無。", "春秋孝獻，回復此都。"]'),
('b5a55fbd-d955-430f-9bd8-bef7a99193c0','唐享太廟樂章 福和','張說','唐','唐诗','tang','','[]','備禮用樂，崇親致尊。',50,'全唐诗/poet.tang.4000.json','["備禮用樂，崇親致尊。", "誠通慈降，敬徹愛存。", "獻懷稱壽，啐感承恩。", "皇帝孝德，子孫千億。", "大包天域，長亙不極。"]'),
('bfa136c9-c472-4095-a172-fd4b9a02dbd4','唐享太廟樂章 舒和','張說','唐','唐诗','tang','','[]','六鐘翕協六變成，八佾徜徉八風生。',32,'全唐诗/poet.tang.4000.json','["六鐘翕協六變成，八佾徜徉八風生。", "樂九韶兮人神感，美七德兮天地清。"]'),
('aeefef60-1b6d-4747-9fbb-8b77371a13b2','唐享太廟樂章 凱安三首 一','張說','唐','唐诗','tang','','[]','瑟彼瑤爵，亞維上公。',40,'全唐诗/poet.tang.4000.json','["瑟彼瑤爵，亞維上公。", "室如屏氣，門不容躬。", "禮殷其本，樂執其中。", "聖皇永慕，天地幽通。"]'),
('1a034e87-1c87-46fb-9c17-a06294a4dce3','唐享太廟樂章 凱安三首 二','張說','唐','唐诗','tang','','[]','禮匝三獻，樂徧九成。',40,'全唐诗/poet.tang.4000.json','["禮匝三獻，樂徧九成。", "降循軒陛，仰欷皇情。", "福與仁合，德因孝明。", "百年神畏，四海風行。"]'),
('d7421548-22b1-454e-a9e5-5da5fd63969b','唐享太廟樂章 凱安三首 三','張說','唐','唐诗','tang','','[]','總總干戚，填填鼓鐘。',40,'全唐诗/poet.tang.4000.json','["總總干戚，填填鼓鐘。", "奮揚增氣，坐作爲容。", "離若鷙鳥，合如戰龍。", "萬方觀德，肅肅邕邕。"]'),
('13720122-7d30-4270-9f0f-39d418fe79d9','唐享太廟樂章 登歌','張說','唐','唐诗','tang','','[]','止笙磬，撤豆籩。',40,'全唐诗/poet.tang.4000.json','["止笙磬，撤豆籩。", "廓無響，窅入玄。", "主在室，神在天。", "情餘慕，禮罔愆。", "喜黍稷，屢豐年。"]'),
('28c59869-f23c-418f-a160-6d639f355efe','唐享太廟樂章 永和','張說','唐','唐诗','tang','','[]','眇嘉樂，授靈爽。',40,'全唐诗/poet.tang.4000.json','["眇嘉樂，授靈爽。", "感若來，思如往。", "休氣散，回風上。", "返寂寞，還惚恍。", "懷靈駕，結空想。"]'),
('f6eb43b4-b342-47c0-bd80-2df868433752','奉和聖製賜諸州刺史應制以題坐右','張說','唐','唐诗','tang','','[]','文明遍禹跡，鰥寡達堯心。',120,'全唐诗/poet.tang.4000.json','["文明遍禹跡，鰥寡達堯心。", "正在親人守，能令王澤深。", "朝廷多秀士，鎔鍊比精金。", "犀節同分命，熊軒各外臨。", "聖主賦新詩，穆若聽薰琴。", "先言教爲本，次言則是欽。", "三時農不奪，午夜犬無侵。", "願使天宇內，品物遂浮沈。", "寄情羣飛鶴，千里一揚音。", "共躡華胥夢，龔黃安足尋。"]'),
('b21219b7-bbc9-426d-910f-85568464d646','奉和聖製送宇文融安輯戶口應制','張說','唐','唐诗','tang','','[]','至德臨天下，勞情遍九圍。',96,'全唐诗/poet.tang.4000.json','["至德臨天下，勞情遍九圍。", "念茲人去本，蓬轉將何依。", "外避征戍數，內傷親黨稀。", "嗟不逢明盛，胡能照隱微。", "柏臺簡行李，蘭殿錫朝衣。", "別曲動秋風，恩令生春輝。", "使出四海安，詔下萬心歸。", "怍非夔龍佐，徒歌鴻雁飛。"]'),
('34ca1da0-47bf-446b-b974-00e47f499580','奉和聖製過晉陽宮應制','張說','唐','唐诗','tang','','[]','太原俗尚武，高皇初奮庸。',144,'全唐诗/poet.tang.4000.json','["太原俗尚武，高皇初奮庸。", "星軒三晉躔，土樂二堯封。", "北風遂舉鵬，西河亦上龍。", "至德起王業，繼明賴人雍。", "六合啓昌期，再興廣聖蹤。", "傳呼大駕來，文物如雲從。", "連營火百里，縱觀人千重。", "翠華渡汾水，白日臨崒峰。", "枌榆恩賞洽，桑梓舊情恭。", "往運感不追，清時惜難逢。", "詩發尊祖心，頌刊盛德容。", "願君及春事，廻輿綏萬邦。"]'),
('50ee99f4-7a07-44e7-aaa1-7c038667e972','奉和聖製行次成臯應制','張說','唐','唐诗','tang','','[]','夏氏階隋亂，自言河朔雄。',72,'全唐诗/poet.tang.4000.json','["夏氏階隋亂，自言河朔雄。", "王師進穀水，兵氣臨山東。", "前掃成臯陣，却下洛陽宮。", "義合帝圖起，威加天宇同。", "軒臺百年外，虞典一巡中。", "戰龍思王業，倚馬賦神功。"]'),
('7e2ee9bd-bf98-4c40-9ac0-e63b5c683089','奉和聖製溫湯對雪應制','張說','唐','唐诗','tang','','[]','瑞雪帶寒風，寒風入陰琯。',48,'全唐诗/poet.tang.4000.json','["瑞雪帶寒風，寒風入陰琯。", "陰琯方凝閉，寒風復淒斷。", "宮似瑤林匝，庭如月華滿。", "正賡挾纊詞，非近溫湯暖。"]'),
('340fd0e0-4205-45e9-99aa-b32a3dc7c003','奉和聖製義成校獵喜雪應制','張說','唐','唐诗','tang','','[]','文教資武功，郊畋閱邦政。',108,'全唐诗/poet.tang.4000.json','["文教資武功，郊畋閱邦政。", "不知仁育久，徒看禽獸盛。", "夜霰氛埃滅，朝日山川淨。", "綽仗飛走繁，抨絃筋角勁。", "帝射參神道，龍馳合人性。", "五豝連一發，百中皆先命。", "勇爵均萬夫，雄圖羅七聖。", "星爲吉符老，雪作豐年慶。", "喜聽行獵詩，威神入軍令。"]'),
('877edc30-59cc-4593-acc8-94b2080ef52d','清明日詔宴寧王山池賦得飛字','張說','唐','唐诗','tang','','[]','今日清明宴，佳境惜芳菲。',60,'全唐诗/poet.tang.4000.json','["今日清明宴，佳境惜芳菲。", "搖揚花雜下，嬌囀鸎亂飛。", "綠渚傳歌榜，紅橋度舞旂。", "和風偏應律，細雨不霑衣。", "承恩如改火，春去春來歸。"]'),
('e9170257-f685-45b7-b69e-7b39d3d6f1a7','四月十三日詔宴寧王亭子賦得好字','張說','唐','唐诗','tang','','[]','何許承恩宴，山亭風日好。',48,'全唐诗/poet.tang.4000.json','["何許承恩宴，山亭風日好。", "綠嫩鳴鶴洲，陰穠鬬雞道。", "果思夏來茂，花嫌春去早。", "行樂無限時，皇情及芳草。"]'),
('3d34dd2e-ac91-419f-985b-74bdb893bcad','藥園宴武輅沙將軍賦得洛字','張說','唐','唐诗','tang','','[]','東第乘餘興，南園宴清洛。',48,'全唐诗/poet.tang.4000.json','["東第乘餘興，南園宴清洛。", "文學引鄒枚，歌鐘陳衞霍。", "風高大夫樹，露下將軍藥。", "待聞出塞還，丹青上麟閣。"]'),
('a77e00fb-854a-4ec7-86ab-3d53653b1073','修書院學士奉敕宴梁王宅賦得樹字','張說','唐','唐诗','tang','','[]','虎殿成鴻業，猿巖題鳳賦。',48,'全唐诗/poet.tang.4000.json','["虎殿成鴻業，猿巖題鳳賦。", "既荷大君恩，還蒙小山遇。", "秋吹迎絃管，涼雲生竹樹。", "共惜朱邸歡，無辭洛城暮。"]'),
('30700331-9b75-4911-8ea3-556546092bf9','夕宴房主簿舍','張說','唐','唐诗','tang','','[]','歲晏關雍空，風急河謂冰。',72,'全唐诗/poet.tang.4000.json','["歲晏關雍空，風急河謂冰。", "薄遊羈物役，微尚愜遠憑。", "旅館月宿永，閉扃雲思興。", "伊人美修夜，朋酒惠來稱。", "交談既清雅，琴吹亦淒凝。", "不逢君蹇涸，幽意長鬱蒸。"]'),
('5c9e5b55-7849-42cc-bd06-bab68a6a02e2','行從方秀川與劉評事文同宿','張說','唐','唐诗','tang','','[]','方秀美盤遊，頻年降天罕。',120,'全唐诗/poet.tang.4000.json','["方秀美盤遊，頻年降天罕。", "水共伊川接，山將闕門斷。", "捧日照恩華，攀雲引疲散。", "野宿霜入帳，孤衾寒不暖。", "靜聞宮漏疎，臥視庭月滿。", "開爐命溫酎，中夜發清管。", "風送關山長，氣遒星歲短。", "寓言情思愜，適興真意坦。", "寰中病羈掛，方外嫌縱誕。", "願君樂盛時，無嗟帶纕緩。"]'),
('d1ec6ab6-a121-437c-a042-ef5622aa23fe','送郭大夫元振再使吐蕃','張說','唐','唐诗','tang','','[]','犬戎廢東獻，漢使馳西極。',96,'全唐诗/poet.tang.4000.json','["犬戎廢東獻，漢使馳西極。", "長策問酋渠，猜阻自夷殛。", "容髪徂邊歲，旌裘敝海色。", "五年一見家，妻子不相識。", "武庫兵猶動，金方事未息。", "遠圖待才智，苦節輸筋力。", "脫刀贈分手，書帶加餐食。", "知君萬里侯，立功在異域。"]'),
('15009be4-4070-4c22-ad6a-d9d5c21c26bc','送李侍郎逈秀薛長史季昶同賦得水字','張說','唐','唐诗','tang','','[]','漢郡接胡庭，幽幷對烽壘。',72,'全唐诗/poet.tang.4000.json','["漢郡接胡庭，幽幷對烽壘。", "旌旗按部曲，文武惟卿士。", "薛公善籌畫，李相威邊鄙。", "中冀分兩河，長城各萬里。", "藉馬黃花塞，蒐兵白狼水。", "勝敵在安人，爲君汗青史。"]'),
('e5deb0bb-355f-40dc-bf23-a876b34ba77a','別平一師','張說','唐','唐诗','tang','','[]','王子不事俗，高駕眇難追。',72,'全唐诗/poet.tang.4000.json','["王子不事俗，高駕眇難追。", "茅土非屑盼，傾城無樂資。", "宴坐深林中，三世同一時。", "皎皎獨往心，不爲塵網欺。", "朅來已復去，今去何來思。", "廻首謝同行，勤會安請期。"]'),
('ca7ec325-7949-47d7-8b60-c927f68e3fdb','送王光庭','張說','唐','唐诗','tang','','[]','同居洛陽陌，經日懶相求。',48,'全唐诗/poet.tang.4000.json','["同居洛陽陌，經日懶相求。", "及爾江湖去，言別悵悠悠。", "楚雲眇羈翼，海月倦行舟。", "愛而不可見，徒嗟芳歲流。"]'),
('bba1de99-5c14-49e8-bd7e-5ca50fd96480','新都南亭送郭元振盧崇道','張說','唐','唐诗','tang','','[]','竹徑女蘿蹊，蓮洲文石隄。',72,'全唐诗/poet.tang.4000.json','["竹徑女蘿蹊，蓮洲文石隄。", "靜深人俗斷，尋玩往還迷。", "碧潭秀初月，素林驚夕棲。", "褰幌納蟾影，理琴聽猿啼。", "佳辰改宿昔，勝寄坐暌攜。", "長懷賞心愛，如玉復如珪。"]'),
('055b7091-3c96-42e7-8131-72193bbd970f','贈崔公','張說','唐','唐诗','tang','','[]','我聞西漢日，四老南山幽。',132,'全唐诗/poet.tang.4000.json','["我聞西漢日，四老南山幽。", "長歌紫芝秀，高臥白雲浮。", "朝野光塵絕，榛蕪年貌秋。", "一朝驅駟馬，連轡入龍樓。", "昔遯高皇去，今從太子遊。", "行藏惟聖節，福禍在人謀。", "卒能匡惠帝，豈不賴留侯。", "事隨年代遠，名與圖籍留。", "平生欽淳德，慷慨景前修。", "蜯蛤伺陰兔，蛟龍望斗牛。", "無嗟異飛伏，同氣幸相求。"]'),
('90849769-bd57-4dcd-aac8-14d3efdb4a31','贈趙公','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','湘東股肱守，心與帝鄉期。',120,'全唐诗/poet.tang.4000.json','["湘東股肱守，心與帝鄉期。", "舟楫中途蹇，風波復來思。", "嘉我常聯翼，金貂侍玉墀。", "迹參前馬聖，名綴鬻熊師。", "寒暑一何速，山川遠間之。", "寧知洞庭上，獨得平生時。", "精意微絕簡，從權討妙棋。", "林壑爲予請，紛靄發華滋。", "流賞忽已散，驚帆杳難追。", "送君在南浦，侘傺投此詞。"]'),
('58dcb426-0643-4090-adff-bc33c1476d72','贈趙侍御','張說','唐','唐诗','tang','','["\u897f\u6e56"]','祿放跡異端，偏荒事同蹇。',168,'全唐诗/poet.tang.4000.json','["祿放跡異端，偏荒事同蹇。", "苟忘風波累，俱會雲壑踐。", "險式壓西湖，僑廬對南峴。", "夜樓江月入，朝幌山雲捲。", "山勢遠濤連，江途斜漢轉。", "坐嘯予多暇，行吟子獨善。", "並轡躧郊郭，方舟玩遊演。", "虛聲萬籟分，水色千里辨。", "不知岸陰謝，再見春露泫。", "綠壤發欣顏，華年助蟲篆。", "上世時難接，古人情可選。", "泊渚煩爲媒，多才怨成褊。", "長沙鵩作賦，任道可知淺。", "請從三已心，榮辱兩都遣。"]'),
('c29980e0-a410-4a84-bf9e-476be5c29468','答李伯魚桐竹','張說','唐','唐诗','tang','','[]','結廬桐竹下，室邇人相深。',60,'全唐诗/poet.tang.4000.json','["結廬桐竹下，室邇人相深。", "接垣分竹徑，隔戶共桐陰。", "落花朝滿岸，明月夜披林。", "竹有龍鳴管，桐留鳳舞琴。", "奇聲與高節，非吾誰賞心。"]'),
('6081c046-007a-4535-bb3f-fb9ff6e4e1de','寄姚司馬','張說','唐','唐诗','tang','','[]','共君春種瓜，本期清夏暑。',48,'全唐诗/poet.tang.4000.json','["共君春種瓜，本期清夏暑。", "瓜成人已去，失望將誰語。", "裛露摘香園，感味懷心許。", "偶逢西風便，因之寄鄂渚。"]'),
('79bd177a-d96f-49f6-8156-50e27e57a656','代書答姜七崔九','張說','唐','唐诗','tang','','[]','婀娜金閨樹，離披野田草。',48,'全唐诗/poet.tang.4000.json','["婀娜金閨樹，離披野田草。", "雖殊兩地榮，幸共三春好。", "花殊鳥飛處，葉鏤蟲行道。", "真心獨感人，惆悵令人老。"]'),
('c44f4181-060a-4ff0-ada9-2f31ee0b13ac','代書寄吉十一','張說','唐','唐诗','tang','','[]','一雁雪上飛，值我衡陽道。',60,'全唐诗/poet.tang.4000.json','["一雁雪上飛，值我衡陽道。", "口銜離別字，遠寄當歸草。", "目想春來遲，心驚寒去早。", "憶鄉乘羽翮，慕侶盈懷抱。", "零落答故人，將隨江樹老。"]'),
('74f3b22d-2d02-449e-9d27-e56931c39796','代書寄薛四','張說','唐','唐诗','tang','','[]','孤雁東飛來，寄我紋與素。',60,'全唐诗/poet.tang.4000.json','["孤雁東飛來，寄我紋與素。", "紋足經三象，素當綜羣務。", "遠見故人心，一言重千金。", "答之綵毛翰，繼以瑤華音。", "歲寒衆木改，松柏心常在。"]'),
('312f898d-94e3-4ce0-983f-fca1ef82a5fe','過蜀道山','張說','唐','唐诗','tang','','[]','我行春三月，山中百花開。',48,'全唐诗/poet.tang.4000.json','["我行春三月，山中百花開。", "披林入峭蒨，攀磴陟崔嵬。", "白雲半峰起，清江出峽來。", "誰知高深意，緬邈心幽哉。"]'),
('17294113-e63d-4282-9cd3-6a5732aa9cb0','蜀路二首 一','張說','唐','唐诗','tang','','[]','雲埃夜澄廓，山日曉晴鮮。',48,'全唐诗/poet.tang.4000.json','["雲埃夜澄廓，山日曉晴鮮。", "葉落蒼江岸，鴻飛白露天。", "磷磷含水石，冪冪覆林煙。", "客心久無緒，秋風殊未然。"]'),
('017ca3d7-c762-4c97-90bd-8327c8ef5b7a','蜀路二首 二','張說','唐','唐诗','tang','','[]','徭蜀時未改，別家鄉念盈。',120,'全唐诗/poet.tang.4000.json','["徭蜀時未改，別家鄉念盈。", "憶昨出門日，春風發鮮榮。", "及茲旋轅地，秋風滿路生。", "昏曉思魏闕，夢寐還秦京。", "秦京開朱第，魏闕垂紫纓。", "幽獨玄虛閣，不聞人馬聲。", "藝業爲君重，名位爲君輕。", "玉琴知調苦，寶鏡對膽清。", "鷹飢常啄腥，鳳飢亦待瓊。", "於君自有屬，物外豈能輕。"]'),
('63559e35-7d6f-4430-9752-ac1faef055b4','再使蜀道','張說','唐','唐诗','tang','','[]','眇眇葭萌道，蒼蒼褒斜谷。',108,'全唐诗/poet.tang.4000.json','["眇眇葭萌道，蒼蒼褒斜谷。", "煙壑爭晦深，雲山共重複。", "古來風塵子，同眩望鄉目。", "芸閣有儒生，軺車倦馳逐。", "青春客岷嶺，白露搖江服。", "歲月鎮羈孤，山川俄反覆。", "魚遊戀深水，鳥遷戀喬木。", "如何別親愛，坐去文章國。", "蟋蟀鳴戶庭，蟏蛸網琴筑。"]'),
('4c02a617-dfae-4fed-85d4-cf38043b7000','江路憶郡','張說','唐','唐诗','tang','','[]','霧斂江早明，星翻漢將沒。',108,'全唐诗/poet.tang.4000.json','["霧斂江早明，星翻漢將沒。", "臥聞峽猿響，起視榜人發。", "倚棹攀岸篠，憑船弄波月。", "水宿厭洲渚，晨光屢揮忽。", "林澤來不窮，煙波去無歇。", "結思笙竽里，搖情遊俠窟。", "年貌不暫留，歡愉及玄髪。", "雲涓戀山海，禽馬懷燕越。", "自非行役人，安知慕城闕。"]'),
('f1e6d6cf-5bbc-4ecd-ba74-01f2bdeb7248','過漢南城歎古墳','張說','唐','唐诗','tang','','[]','舊國多陵墓，荒涼無歲年。',72,'全唐诗/poet.tang.4000.json','["舊國多陵墓，荒涼無歲年。", "洶湧蔽平岡，汩若波濤連。", "上世千金子，潛臥九重泉。", "松柏剪無餘，碑記滅罔傳。", "葬於不毛地，咸謂楚先賢。", "事盡情可識，使人心悵然。"]'),
('8292b6f2-089b-43e5-af27-784fdd4c099b','至尉氏','張說','唐','唐诗','tang','','[]','夕次阮公臺，嘯歌臨爽塏。',96,'全唐诗/poet.tang.4000.json','["夕次阮公臺，嘯歌臨爽塏。", "高名安足賴，故物今皆改。", "吾兄昔茲邑，遺愛稱賢宰。", "桑中雉未飛，屋上烏猶在。", "途逢舊甿吏，城有同僚寀。", "望塵遠見迎，拂館來欣待。", "慈惠留千室，友于存四海。", "始知魯衞間，優劣相懸倍。"]'),
('76b2da4c-4588-4df1-a9ce-b222824566fc','襄州景空寺題融上人蘭若','張說','唐','唐诗','tang','','[]','高名出漢陰，禪閣跨香岑。',72,'全唐诗/poet.tang.4000.json','["高名出漢陰，禪閣跨香岑。", "衆山既圍繞，長川復迴臨。", "雲峰曉靈變，風木夜虛吟。", "碧湫龍池滿，蒼松虎徑深。", "舊知青巖意，偏入杳冥心。", "何由侶飛錫，從此脫朝簪。"]'),
('76ca9f2e-682c-42c4-8b77-7c508b08923c','巡邊在河北作','張說','唐','唐诗','tang','','[]','撫劒空餘勇，彎弧遂無力。',48,'全唐诗/poet.tang.4000.json','["撫劒空餘勇，彎弧遂無力。", "老去事如何，據鞍長歎息。", "故交索將盡，後進稀相識。", "獨憐半死心，尚有寒松直。"]'),
('1439acb0-0c50-4fe6-84da-b89457995c2d','入海二首 一','張說','唐','唐诗','tang','','[]','乘桴入南海，海曠不可臨。',60,'全唐诗/poet.tang.4000.json','["乘桴入南海，海曠不可臨。", "茫茫失方面，混混如凝陰。", "雲山相出沒，天地互浮沈。", "萬里無涯際，云何測廣深。", "潮波自盈縮，安得會虛心。"]'),
('05f5cc4b-4a84-45c9-84f7-f9bb03313bed','入海二首 二','張說','唐','唐诗','tang','','[]','海上三神山，逍遙集衆仙。',72,'全唐诗/poet.tang.4000.json','["海上三神山，逍遙集衆仙。", "靈心豈不同，變化無常全。", "龍伯如人類，一釣兩鰲連。", "金臺此淪沒，玉真時播遷。", "問子勞何事，江上泣經年。", "隰中生紅草，所美非美然。"]'),
('cc556445-c706-48b8-9962-8e235a8952d4','相州山池作','張說','唐','唐诗','tang','','[]','嘗懷謝公詠，山水陶嘉月。',72,'全唐诗/poet.tang.4000.json','["嘗懷謝公詠，山水陶嘉月。", "及此年事衰，徒看衆花發。", "觀魚樂何在，聽鳥情都歇。", "星漢流不停，蓬萊去難越。", "鄴中秋麥秀，淇上春雲沒。", "日見塵物空，如何靜心闕。"]'),
('7898a7c7-680e-4346-ab88-e49773b1bb31','岳州作','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','夜夢雲闕間，從容簪履列。',96,'全唐诗/poet.tang.4000.json','["夜夢雲闕間，從容簪履列。", "朝遊洞庭上，緬望京華絕。", "潦收江未清，火退山更熱。", "重欷視欲醉，懵滿氣如噎。", "器留魚鼈腥，衣點蚊虻血。", "髪白思益壯，心玄用彌拙。", "冠劒日苔蘚，琴書坐廢撤。", "唯有報恩字，刻意長不滅。"]'),
('f59f3db1-a16f-4f8b-bbd4-2efd8381f6ee','岳州行郡竹籬','張說','唐','唐诗','tang','','[]','山郡不溝郭，荒居無翳壅。',120,'全唐诗/poet.tang.4000.json','["山郡不溝郭，荒居無翳壅。", "愛人忠主利，善守閉爲勇。", "苟非小勤瘁，安得期逸寵。", "版築恐土疎，襄城嫌役重。", "藩柵聊可固，筠篁近易奉。", "差池截浦沙，繚繞緣隈壠。", "矗似長雲亙，森如高戟聳。", "預絕豺狼憂，知免牛羊恐。", "閭里寬矯步，榛叢恣踏踵。", "始果遊處心，終日成閑拱。"]'),
('c80d0a74-4216-4d8d-bd22-5ea0c0f80da6','遊洞庭湖湘','張說','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','緬邈洞庭岫，葱蒙水霧色。',192,'全唐诗/poet.tang.4000.json','["緬邈洞庭岫，葱蒙水霧色。", "宛在太湖中，可望不可即。", "剖竹守窮渚，開門對奇域。", "城池自縶籠，纓綬爲徽纆。", "靡日不思往，經時始願克。", "飛棹越溟波，維舟恣攀陟。", "䆗窱入雲步，崎嶇倚松息。", "巖壇有鶴過，壁字無人識。", "滴石香乳溜，垂崖靈草植。", "玩幽輕霧阻，討異忘曛逼。", "寒沙際水平，霜樹籠煙直。", "空宮聞莫覩，地道窺難測。", "此處學金丹，何人生羽翼。", "誰傳九光要，幾拜三仙職。", "紫氣徒想像，清潭長眇默。", "霓裳若有來，覯我雲峰側。"]'),
('a2593aea-05b8-4084-8c9a-2ee94666b503','㴩湖山寺','張說','唐','唐诗','tang','','[]','楚老遊山寺，提攜觀畫壁。',48,'全唐诗/poet.tang.4000.json','["楚老遊山寺，提攜觀畫壁。", "揚袂指辟支，睩眄相鬬鬩。", "險哉透撞兒，千金賭一擲。", "成敗身自受，傍人那歎息。"]'),
('4a122ff7-9cd2-4a88-a56e-903bcb04d374','出湖寄趙冬曦','張說','唐','唐诗','tang','','[]','西泛平湖盡，參差入亂山。',72,'全唐诗/poet.tang.4000.json','["西泛平湖盡，參差入亂山。", "東瞻岳陽郡，汗漫太虛間。", "窘步同行樂，遒文互屢看。", "山戍上雲桂，江亭臨水關。", "川途倏忽間，風景依如昨。", "湘浦未賜環，荆門猶主諾。"]'),
('10a33e04-a84e-4026-ba8f-a90d76a57370','岳陽早霽南樓','張說','唐','唐诗','tang','','[]','山水佳新霽，南樓玩初旭。',96,'全唐诗/poet.tang.4000.json','["山水佳新霽，南樓玩初旭。", "夜來枝半紅，雨後洲全綠。", "四運相終始，萬形紛代續。", "適臨青草湖，再變黃鸎曲。", "地穴穿東武，江流下西蜀。", "歌聞枉渚邅，舞見長沙促。", "心阻意徒馳，神和生自足。", "白髪悲上春，知常謝先欲。"]'),
('e5e1f77b-4c7a-48a7-a9e6-3dcfa180614f','岳陽石門墨山二山相連有禪堂觀天下絕境','張說','唐','唐诗','tang','','[]','囷輪江上山，近在華容縣。',192,'全唐诗/poet.tang.4000.json','["囷輪江上山，近在華容縣。", "常涉巴丘首，天晴遙可見。", "佳遊屢前諾，芳月愆幽眷。", "及此符守移，歡言臨道便。", "既攜賞心客，復有送行掾。", "竹徑入陰窅，松蘿上空蒨。", "草共林一色，雲與峰萬變。", "探窺石門斷，緣越沙澗轉。", "兩山勢爭雄，峰巘相顧眄。", "藥妙靈仙寶，境華巖壑選。", "清都西淵絕，金地東敞宴。", "池果接園畦，風煙邇臺殿。", "高尋去石頂，曠覽天宇遍。", "千山紛滿目，百川豁對面。", "騎來雲氣迎，人去鳥聲戀。", "長揖桃源士，舉世同企羨。"]'),
('361a5653-9ee7-4b32-a978-c8e6db62ada6','和尹懋秋夜遊㴩湖','張說','唐','唐诗','tang','','[]','坐嘯人事閑，佳遊野情發。',48,'全唐诗/poet.tang.4000.json','["坐嘯人事閑，佳遊野情發。", "山門送落照，湖口昇微月。", "林尋猿狖居，水戲黿鼉穴。", "朔風吹飛雁，芳草亦云歇。"]'),
('e8357820-f27b-43b5-afa8-49b4cedc8fcd','五君詠五首 魏齊公元忠','張說','唐','唐诗','tang','','[]','齊公生人表，逈天聞鶴唳。',60,'全唐诗/poet.tang.4000.json','["齊公生人表，逈天聞鶴唳。", "清論早揣摩，玄心晚超詣。", "入相廊廟靜，出軍沙漠霽。", "見深呂祿憂，舉後陳平計。", "甘心除君惡，足以報先帝。"]'),
('1a40eebd-96b4-4237-b027-4cae2004a6b3','五君詠五首 蘇許公瓌','張說','唐','唐诗','tang','','[]','許公信國楨，克美具瞻情。',60,'全唐诗/poet.tang.4000.json','["許公信國楨，克美具瞻情。", "百事資朝問，三章廣世程。", "處高心不有，臨節自爲名。", "朱戶傳新戟，青松拱舊塋。", "淒涼丞相府，餘慶在玄成。"]'),
('a33908b4-132e-4ba6-ba47-47e8f1eff7a6','五君詠五首 李趙公嶠','張說','唐','唐诗','tang','','[]','李公實神敏，才華乃天授。',60,'全唐诗/poet.tang.4000.json','["李公實神敏，才華乃天授。", "睦親何用心，處貴不忘舊。", "故事遵臺閣，新詩冠宇宙。", "在人忠所奉，惡我誠將宥。", "南浦去莫歸，嗟嗟蔑孫秀。"]'),
('bae92855-1fd2-456c-8629-8196e08c3bb2','五君詠五首 郭代公元振','張說','唐','唐诗','tang','','[]','代公舉鵬翼，懸飛摩海霧。',60,'全唐诗/poet.tang.4000.json','["代公舉鵬翼，懸飛摩海霧。", "志康天地屯，適與雲雷遇。", "興喪一言決，安危萬心注。", "大勳書王府，舛命淪江路。", "勢傾北夏門，哀靡東平樹。"]'),
('9a386a8b-1b68-4f67-b803-3ef00e53e0e1','五君詠五首 趙耿公彥昭','張說','唐','唐诗','tang','','[]','耿公山嶽秀，才傑心亦妙。',60,'全唐诗/poet.tang.4000.json','["耿公山嶽秀，才傑心亦妙。", "鷙鳥峻標立，哀玉扣清調。", "協贊休明啓，恩華日月照。", "何意瑤臺雲，風吹落江徼。", "湘流下潯陽，灑淚一投弔。"]'),
('ddbe3a60-c682-4fb0-b8ce-0fdfec2771de','遊龍山靜勝寺','張說','唐','唐诗','tang','','[]','每上襄陽樓，遙望龍山樹。',120,'全唐诗/poet.tang.4000.json','["每上襄陽樓，遙望龍山樹。", "鬱茀吐岡嶺，微蒙在煙霧。", "下車歲已成，飾馬閑餘步。", "苦霜裛野草，愛日揚江煦。", "雲對石上塔，風吹松下路。", "禪室宴三空，神祠同六趣。", "兒童共戲謔，猿鳥相驚顧。", "南識桓公臺，北望先賢墓。", "世上人何在，時聞心不住。", "但傳無盡燈，可使有情悟。"]'),
('657d18af-6eb4-4ba2-80ce-7cdc1799c2fd','一柱觀','張說','唐','唐诗','tang','','[]','舊說江陵觀，初疑神化來。',48,'全唐诗/poet.tang.4000.json','["舊說江陵觀，初疑神化來。", "空山結雲閣，綺靡隨風回。", "奈何任一柱，斯焉容衆材。", "奇功非長世，今餘草露臺。"]'),
('2bbffd2b-2798-4ee4-a6e8-cdc7c4a397eb','登九里臺是樊姬墓','張說','唐','唐诗','tang','','[]','楚國所以霸，樊姬有力焉。',120,'全唐诗/poet.tang.4000.json','["楚國所以霸，樊姬有力焉。", "不懷沈尹祿，誰諳叔敖賢。", "萬化茫無在，孤墳獨巋然。", "北分陽臺陌，南識郢城阡。", "漠漠渚宮樹，蒼蒼雲夢田。", "登高形勝出，訪古令名傳。", "自我來符守，因君樹蕙荃。", "詩書將變俗，絺纊忽彌年。", "志闡三折後，愁值二毛前。", "佇立帝京路，遙心寄此篇。"]'),
('3082e5bf-5125-4d43-915c-1d7d2bf68124','過懷王墓','張說','唐','唐诗','tang','','[]','咿嚘不可信，以此敗懷王。',48,'全唐诗/poet.tang.4000.json','["咿嚘不可信，以此敗懷王。", "客死嶢關路，返葬岐江陽。", "啼狖抱山月，飢狐獵野霜。", "一聞懷沙事，千載盡悲涼。"]'),
('5dcf5826-9304-4226-b3ed-dc7b8441915d','聞雨','張說','唐','唐诗','tang','','[]','多雨絕塵事，寥寥入太玄。',84,'全唐诗/poet.tang.4000.json','["多雨絕塵事，寥寥入太玄。", "城陰疎復合，簷滴斷還連。", "念我勞造化，從來五十年。", "誤將心徇物，近得還自然。", "閑居草木侍，虛室鬼神憐。", "有時進美酒，有時泛清絃。", "聲真不世識，心醉豈言詮。"]'),
('5e191ee2-2b77-42ef-b87f-c3bb7b5fce7c','夜坐','張說','唐','唐诗','tang','','[]','懷哉四壁時，未有五都價。',48,'全唐诗/poet.tang.4000.json','["懷哉四壁時，未有五都價。", "百金誰見許，斗酒難爲貰。", "落花生芳春，孤月皎清夜。", "復逢利交客，題戶遙相謝。"]'),
('c5d3a2e5-947b-4eba-85c9-5e49f43d3555','山夜聞鐘','張說','唐','唐诗','tang','','[]','夜臥聞夜鐘，夜靜山更響。',60,'全唐诗/poet.tang.4000.json','["夜臥聞夜鐘，夜靜山更響。", "霜風吹寒月，䆗窱虛中上。", "前聲既舂容，後聲復晃盪。", "聽之如可見，尋之定無像。", "信知本際空，徒掛生滅想。"]'),
('2cb7d9eb-2369-4396-b3c3-3c548d8794c0','冬日見牧牛人擔青草歸','張說','唐','唐诗','tang','','[]','塞上綿應折，江南草可結。',48,'全唐诗/poet.tang.4000.json','["塞上綿應折，江南草可結。", "欲持梅嶺花，遠競榆關雪。", "日月無他照，山川何頓別。", "苟齊兩地心，天問將安說。"]'),
('dc2a3e30-d72c-4a8c-a301-96569da934fb','詠鏡','張說','唐','唐诗','tang','','[]','寶鏡如明月，出自秦宮樣。',60,'全唐诗/poet.tang.4000.json','["寶鏡如明月，出自秦宮樣。", "隱起雙蟠龍，銜珠儼相向。", "常恐君不察，匣中委清量。", "積翳掩菱花，虛心蔽塵狀。", "倘蒙羅袖拂，光生玉臺上。"]'),
('80a30e12-c8ac-4c7c-b944-ce1dfc63bee4','詠瓢','張說','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','美酒酌懸瓢，真淳好相映。',48,'全唐诗/poet.tang.4000.json','["美酒酌懸瓢，真淳好相映。", "蝸房卷墮首，鶴頸抽長柄。", "雅色素而黃，虛心輕且勁。", "豈無雕刻者，貴此成天性。"]'),
('b8282e05-ec11-4727-8d44-a4672dbdfcc3','雜詩四首 一','張說','唐','唐诗','tang','','[]','抱薰心常焦，舉斾心常搖。',36,'全唐诗/poet.tang.4000.json','["抱薰心常焦，舉斾心常搖。", "天長地自久，歡樂能幾朝。", "君看西陵樹，歌舞爲誰嬌。"]'),
('6676180c-9b9d-445d-9d5d-8f2ff0c33e64','雜詩四首 二','張說','唐','唐诗','tang','','[]','山閑苦積雨，木落悲時遽。',72,'全唐诗/poet.tang.4000.json','["山閑苦積雨，木落悲時遽。", "賞心凡幾人，良辰在何處？", "觸石滿堂侈，灑我終夕慮。", "客鳥懷主人，銜花未能去。", "剖珠貴分明，琢玉思堅貞。", "要君意如此，終始莫相輕。"]'),
('916ae490-eeab-4edd-b5a0-d536cdc7ad23','雜詩四首 三','張說','唐','唐诗','tang','','[]','問子青霞意，何事留朱軒。',96,'全唐诗/poet.tang.4000.json','["問子青霞意，何事留朱軒。", "自言心遠俗，未始迹辭喧。", "過蒙良時幸，側息吏途煩。", "簪纓非宿好，文史棄前言。", "夕臥北窗下，夢歸南山園。", "白雲慙幽谷，清風愧泉源。", "十年茲賞廢，佳期今復存。", "掛冠謝朝侶，星駕別君門。"]'),
('1a46aec5-3803-4201-8a36-846c9ebe322b','雜詩四首 四','張說','唐','唐诗','tang','','[]','默念羣疑起，玄通百慮清。',48,'全唐诗/poet.tang.4000.json','["默念羣疑起，玄通百慮清。", "初心滅陽豔，復見湛虛明。", "悟滅心非盡，求虛見後生。", "應將無住法，修到不成名。"]'),
('a1242e5b-90ef-4695-9465-4cc397a9da17','和張監遊終南','張說','唐','唐诗','tang','','[]','宿懷終南意，及此語雲峰。',48,'全唐诗/poet.tang.4000.json','["宿懷終南意，及此語雲峰。", "夜聞竹澗靜，曉望林嶺重。", "春煙生古石，時鳥戲幽松。", "豈無山中賞，但畏心莫從。"]'),
('652a7480-573a-4c70-8677-0f61c119258c','古泉驛','張說','唐','唐诗','tang','','[]','昔聞陳仲子，守義辭三公。',60,'全唐诗/poet.tang.4000.json','["昔聞陳仲子，守義辭三公。", "身賃妻織屨，樂亦在其中。", "豈無窮賤苦，羞與傾巧同。", "長白臨河上，於陵入濟東。", "我行弔遺跡，感歎古泉空。"]'),
('3727470f-9fc9-4e4d-a691-d085e8409404','河上公','張說','唐','唐诗','tang','','[]','尊師厭塵去，精魄知何明。',48,'全唐诗/poet.tang.4000.json','["尊師厭塵去，精魄知何明。", "形氣不復生，弟子空傷情。", "濟北神如在，淮南藥未成。", "共期終莫遂，寥落兩無成。"]'),
('490ecb5d-a36a-4da8-a551-995f68a8f781','奉和聖製初入秦川路寒食應制','張說','唐','唐诗','tang','','[]','上陽柳色喚春歸，臨渭桃花拂水飛。',160,'全唐诗/poet.tang.4000.json','["上陽柳色喚春歸，臨渭桃花拂水飛。", "總爲朝廷巡幸去，頓教京洛少光輝。", "昨從分陝山南口，馳道依依漸花柳。", "入關正投寒食前，還京遂落清明後。", "路上天心重豫遊，御前恩賜特風流。", "便幕那能鏤雞子，行宮善巧帖毛毬。", "渭橋南渡花如撲，麥隴青青斷人目。", "漢家行樹直新豐，秦地驪山抱溫谷。", "香池春溜水初平，預歡浴日照京城。", "今歲隨宜過寒食，明年陪宴作清明。"]'),
('d32edeb8-6be5-4eb3-8be8-caa63f7eb089','時樂鳥篇','張說','唐','唐诗','tang','','[]','舊傳南海出靈禽，時樂名聞不可尋。',160,'全唐诗/poet.tang.4000.json','["舊傳南海出靈禽，時樂名聞不可尋。", "形貌乍同鸚鵡類，精神別稟鳳皇心。", "千年待聖方輕舉，萬里呈才無伴侶。", "紅茸糅繡好毛衣，清泠謳鵶好言語。", "內人試取御衣牽，啄手暝聲不許前。", "心願陽烏恆保日，志嫌陰鶴欲凌天。", "天情玩訝良無已，察圖果見祥經裏。", "本持符瑞驗明王，還用文章比君子。", "自憐弱羽詎堪珍，喜共華篇來示人。", "人見嚶嚶報恩鳥，多慙碌碌具官臣。"]'),
('020271e2-92e8-4e27-a788-9a32dbef1fd6','安樂郡主花燭行','張說','唐','唐诗','tang','','[]','青宮朱邸翊皇闈，玉葉瓊蕤發紫微。',336,'全唐诗/poet.tang.4000.json','["青宮朱邸翊皇闈，玉葉瓊蕤發紫微。", "姬姜本來舅甥國，卜筮俱道鳳皇飛。", "星昴殷冬獻吉日，夭桃穠李遙相匹。", "鸞車鳳傳王子來，龍樓月殿天孫出。", "平臺火樹連上陽，紫炬紅輪十二行。", "丹爐飛鐵馳炎焰，炎霞爍電吐明光。", "綠軿紺幰紛如霧，節鼓清笳前啓路。", "城隅靡靡稍東還，橋上鱗鱗轉南渡。", "五方觀者聚中京，四合塵煙漲洛城。", "商女香車珠結網，天人寶馬玉繁纓。", "百壺淥酒千斤肉，大道連延障錦軸。", "先祝聖人壽萬年，復禱宜家承百祿。", "珊瑚刻盤青玉尊，因之假道入梁園。", "梁園山竹凝雲漢，仰望高樓在天半。", "翠幕蘭堂蘇合薰，珠簾掛戶水波紋。", "別起芙蓉織成帳，金鏤鴛鴦兩相向。", "罽茵飾地承琱履，花燭分階移錦帳。", "織女西垂隱燭臺，雙童連縷合歡杯。", "藹藹綺庭嬪從列，娥娥紅粉扇中開。", "黃金兩印雙花綬，富貴婚姻古無有。", "清歌棠棣美王姬，流化邦人正夫婦。"]'),
('4298afa3-c537-4947-9430-68f5a2348abb','離會曲','張說','唐','唐诗','tang','','[]','何處送客洛橋頭，洛水泛泛中行舟。',48,'全唐诗/poet.tang.4000.json','["何處送客洛橋頭，洛水泛泛中行舟。", "可憐河樹葉萎蕤，關關河鳥聲相思。", "街鼓喧喧日將夕，去棹歸軒兩相迫。"]'),
('af126201-9a4d-428b-bd37-7e951d5eae31','鄴都引','張說','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','君不見魏武草創爭天祿，羣雄睚眦相馳逐。',99,'全唐诗/poet.tang.4000.json','["君不見魏武草創爭天祿，羣雄睚眦相馳逐。", "晝攜壯士破堅陣，夜接詞人賦華屋。", "都邑繚繞西山陽，桑榆汗漫漳河曲。", "城郭爲虛人代改，但有西園明月在。", "鄴傍高冢多貴臣，娥眉𥊑睩共灰塵。", "試上銅臺歌舞處，唯有秋風愁殺人。"]'),
('bc42d018-5e64-4501-be9b-0fa22cd98573','城南亭作','張說','唐','唐诗','tang','','[]','珂馬朝歸連萬石，矟門洞啓親迎客。',130,'全唐诗/poet.tang.4000.json','["珂馬朝歸連萬石，矟門洞啓親迎客。", "北堂珍重琥珀酒，庭前列肆茱萸席。", "長袖遲回意緒多，清商緩轉[目]騰波。", "舊傳比翼侯家舞，新出將雛主第歌。", "漢家絳灌餘兵氣，晉代浮虛安足貴。", "正逢天下金鏡清，偏加日飲醇醪意。", "誰復遨遊不復歸，閑庭莫畏不芳菲。", "會待城南春色至，竟將花柳拂羅衣。"]'),
('1616dac6-2614-4e48-a757-43d7ff1ad31b','同趙侍御乾湖作','張說','唐','唐诗','tang','','[]','江南湖水咽山川，春江溢入共湖連。',208,'全唐诗/poet.tang.4000.json','["江南湖水咽山川，春江溢入共湖連。", "氣色紛淪橫罩海，波濤鼓怒上漫天。", "鱗宗殼族嬉爲府，弋叟罛師利焉聚。", "欹帆側柁弄風口，赴險臨深繞灣浦。", "一灣一浦悵邅迴，千曲千溠怳迷哉。", "乍見靈妃含笑往，復聞遊女怨歌來。", "暑來寒往運洄洑，潭生水落移陵谷。", "雲間墜翮散泥沙，波上浮查棲樹木。", "昨暮飛霜下北津，今朝行雁度南濱。", "處處溝洚清源竭，年年舊葦白頭新。", "天地盈虛尚難保，人間倚伏何須道。", "秋月皛皛泛澄瀾，冬景青青步纖草。", "念君宿昔觀物變，安得躊躕不衰老。"]'),
('b47d109f-2493-47bf-8dbe-442c5edb625f','巡邊在河北作','張說','唐','唐诗','tang','','[]','去年六月西河西，今年六月北河北。',64,'全唐诗/poet.tang.4000.json','["去年六月西河西，今年六月北河北。", "沙場磧路何爲爾，重氣輕生知許國。", "人生在世能幾時，壯年征戰髪如絲。", "會待安邊報明主，作頌封山也未遲。"]'),
('1519da86-7f1b-4f2b-8f2d-43b1def6ebe6','贈崔二安平公樂世詞','張說','唐','唐诗','tang','','[]','十五紅粧侍綺樓，朝承握槊夜藏鉤。',80,'全唐诗/poet.tang.4000.json','["十五紅粧侍綺樓，朝承握槊夜藏鉤。", "君臣一意金門寵，兄弟雙飛玉殿遊。", "寧知宿昔恩華樂，變作瀟湘離別愁。", "地濕莓苔生舞袖，江聲怨歎入箜篌。", "自憐京兆雙眉嫵，會待南來五馬留。"]'),
('38bd00a3-d714-42b6-900b-6927d205d0e5','送尹補闕元凱琴歌','張說','唐','唐诗','tang','','[]','鳳哉鳳哉！啄琅玕。',106,'全唐诗/poet.tang.4000.json','["鳳哉鳳哉！啄琅玕。", "飲瑤池，棲崑崙之山哉。", "中國有聖人，感和氣。", "飛來飛來，自歌自舞。", "先王冊府，麒鱗之臺。", "羇雌衆雛故山曲，其鳴喈喈。", "其鳴喈喈，欲往銜之歘去來。", "去別鸞鳳心徘徊，明年阿閣梧桐花葉開。", "羣飛鳳歸來，羣飛鳳歸來。"]'),
('1db523ba-e9d5-4ff6-be82-eb84617d064a','送考功武員外學士使嵩山署舍利塔','張說','唐','唐诗','tang','','[]','懷玉泉，戀仁者，寂滅真心不可見。',112,'全唐诗/poet.tang.4000.json','["懷玉泉，戀仁者，寂滅真心不可見。", "空留影塔嵩巖下，寶王四海轉千輪。", "金曇百粒送分身，山中二月娑羅會。", "虛唄遙遙愁思人，我念過去微塵劫。", "與子禪門同正法，雖在神仙蘭省間。", "常持清淨蓮花葉，來亦好，去亦好。", "了觀車行馬不移，當見菩提離煩惱。"]'),
('e4460d2c-7917-4469-8b05-9c74d892acc2','遙同蔡起居偃松篇','張說','唐','唐诗','tang','','[]','清都衆木總榮芬，傳道孤松最出羣。',80,'全唐诗/poet.tang.4000.json','["清都衆木總榮芬，傳道孤松最出羣。", "名接天庭長景色，氣連宮闕借氛氳。", "懸池的的停華露，偃蓋重重拂瑞雲。", "不借流膏助仙鼎，願將楨幹捧明君。", "莫比冥靈楚南樹，朽老江邊代不聞。"]'),
('9c849dec-be6c-4ac3-a4e0-f1630382f983','奉和聖製登驪山矚眺應制','張說','唐','唐诗','tang','','[]','寒山上半空，臨眺盡寰中。',48,'全唐诗/poet.tang.4000.json','["寒山上半空，臨眺盡寰中。", "是日巡遊處，晴光遠近同。", "川明分渭水，樹暗辨新豐。", "巖壑清音暮，天歌起大風。"]'),
('d34e11c4-2cd3-4bba-aa49-a7c7cbd2b263','奉和聖製幸白鹿觀應制','張說','唐','唐诗','tang','','[]','洞府寒山曲，天遊日旰迴。',48,'全唐诗/poet.tang.4000.json','["洞府寒山曲，天遊日旰迴。", "披雲看石鏡，拂雪上金臺。", "竹徑龍驂下，松庭鶴轡來。", "雙童還獻藥，五色耀仙材。"]'),
('e768ab09-3e55-4536-bbbf-7056e742df09','奉和聖製送金城公主適西蕃應制','張說','唐','唐诗','tang','','[]','青海和親日，潢星出降時。',48,'全唐诗/poet.tang.4000.json','["青海和親日，潢星出降時。", "戎王子壻寵，漢國舅家慈。", "春野開離讌，雲天起別詞。", "空彈馬上曲，詎減鳳樓思。"]'),
('6af6e859-f802-42c8-bbe6-3b4a7c29c6ed','奉和同皇太子過慈恩寺應制二首 一','張說','唐','唐诗','tang','','[]','翼翼宸恩永，煌煌福地開。',48,'全唐诗/poet.tang.4000.json','["翼翼宸恩永，煌煌福地開。", "離光升寶殿，震氣繞香臺。", "上界幡花合，中天伎樂來。", "願君無量壽，仙樂屢徘徊。"]'),
('59d4c272-ef65-45c4-828a-cd6d774c044e','奉和同皇太子過慈恩寺應制二首 二','張說','唐','唐诗','tang','','[]','朗朗神居峻，軒軒瑞象威。',48,'全唐诗/poet.tang.4000.json','["朗朗神居峻，軒軒瑞象威。", "聖君成願果，太子拂天衣。", "至樂三靈會，深仁四皓歸。", "還聞渦水曲，更繞白雲飛。"]'),
('4f44d4ff-b703-48b0-b9c1-33cb0ee89291','侍宴武三思山第應制賦得風字','張說','唐','唐诗','tang','','[]','梁王池館好，曉日鳳樓通。',48,'全唐诗/poet.tang.4000.json','["梁王池館好，曉日鳳樓通。", "竹町羅千衞，蘭筵降兩宮。", "清歌芳樹下，妙舞落花中。", "臣覺筵中聽，還如大國風。"]'),
('de32b002-29b2-40b4-a0bc-d5f8c6bed778','奉和聖製過寧王宅應制','張說','唐','唐诗','tang','','[]','進酒忘憂觀，簫韶喜降臨。',48,'全唐诗/poet.tang.4000.json','["進酒忘憂觀，簫韶喜降臨。", "帝堯敦族禮，王季友兄心。", "竹院龍鳴笛，梧宮鳳遶林。", "大風將小雅，一字盡千金。"]'),
('33036605-ce3a-4a5c-b40d-b46716dbbad4','奉和聖製同玉真公主過大哥山池題石壁應制','張說','唐','唐诗','tang','','[]','綠竹初成苑，丹砂欲化金。',48,'全唐诗/poet.tang.4000.json','["綠竹初成苑，丹砂欲化金。", "乘龍與驂鳳，歌吹滿山林。", "爽氣凝情逈，寒光映浦深。", "忘憂題此觀，爲樂賞同心。"]'),
('6407377d-1574-4304-99f6-789b048ae451','奉和聖製賜王公千秋鏡應制','張說','唐','唐诗','tang','','[]','寶鏡頒神節，凝規寫聖情。',48,'全唐诗/poet.tang.4000.json','["寶鏡頒神節，凝規寫聖情。", "千秋題作字，長壽帶爲名。", "月向天邊下，花從日裏生。", "不承懸象意，誰辨照心明。"]'),
('f47ce43e-7f0e-48fa-b586-da5ba8b68fc8','奉和聖製經鄒魯祭孔子應制','張說','唐','唐诗','tang','','[]','孔聖家鄒魯，儒風藹典墳。',48,'全唐诗/poet.tang.4000.json','["孔聖家鄒魯，儒風藹典墳。", "龍驂廻舊宅，鳳德詠餘芬。", "入室神如在，升堂樂似聞。", "懸知一王法，今日待明君。"]'),
('75055ddf-124c-4628-9ee3-75914bc7dea1','侍宴蘘荷亭應制','張說','唐','唐诗','tang','','[]','回鑾青嶽觀，帳殿紫煙峰。',48,'全唐诗/poet.tang.4000.json','["回鑾青嶽觀，帳殿紫煙峰。", "仙路迎三鳥，雲衢駐兩龍。", "園林看化塔，壇墠識餘封。", "山外聞簫管，還如天上逢。"]'),
('26b90d94-8519-4966-9993-2808a4dc2f24','侍宴滻水賦得濃字','張說','唐','唐诗','tang','','[]','千行發御柳，一葉下仙筇。',48,'全唐诗/poet.tang.4000.json','["千行發御柳，一葉下仙筇。", "青浦宸遊至，朱城佳氣濃。", "雲霞交暮色，草樹喜春容。", "藹藹天旗轉，清笳入九重。"]'),
('98b9c819-c287-4a62-b844-f08172081922','奉和聖製同劉晃喜雨應制','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','青氣含春雨，知從岱嶽來。',48,'全唐诗/poet.tang.4000.json','["青氣含春雨，知從岱嶽來。", "行雲避師出，灑雨待車廻。", "厭浥塵清道，空濛柳映臺。", "最宜三五夜，晴月九重開。"]'),
('747c9605-90bf-4d94-ad6c-ad75a674f482','奉和聖製觀拔河俗戲應制','張說','唐','唐诗','tang','','[]','今歲好拖鉤，橫銜敞御樓。',48,'全唐诗/poet.tang.4000.json','["今歲好拖鉤，橫銜敞御樓。", "長繩繫日住，貫索挽河流。", "鬬力頻催鼓，爭都更上籌。", "春來百種戲，天意在宜秋。"]'),
('81c35fe3-c3aa-41d9-ab4f-b2dcc6b588cf','奉和聖製途次陝州應制','張說','唐','唐诗','tang','','[]','周召嘗分陝，詩書空復傳。',48,'全唐诗/poet.tang.4000.json','["周召嘗分陝，詩書空復傳。", "何如萬乘睠，追賞二南篇。", "郡帶洪河側，宮臨大道邊。", "洛城將日近，佳氣滿山川。"]'),
('09003398-8839-4c09-a6ce-a5730b4e1838','奉和聖製野次喜雪應制','張說','唐','唐诗','tang','','[]','寒更玉漏催，曉色御前開。',48,'全唐诗/poet.tang.4000.json','["寒更玉漏催，曉色御前開。", "泱漭雲陰積，氤氳風雪廻。", "山知銀作甕，宮見璧成臺。", "欲驗豐年象，飄搖仙藻來。"]'),
('5c3a45f6-f45a-4e0a-a8a4-aabfba6ac1de','奉和聖製溫泉言志應制','張說','唐','唐诗','tang','','[]','溫谷媚新豐，驪山橫半空。',48,'全唐诗/poet.tang.4000.json','["溫谷媚新豐，驪山橫半空。", "湯池薰水殿，翠木暖煙宮。", "起疾逾仙藥，無私合聖功。", "始知堯舜德，心與萬人同。"]'),
('731f0cd1-37cc-40e9-bd76-b2c75ff08f00','皇帝降誕日集賢殿賜宴','張說','唐','唐诗','tang','','[]','仲秋金帝起，五日土行昭。',48,'全唐诗/poet.tang.4000.json','["仲秋金帝起，五日土行昭。", "瑞表壬寅露，光傳甲子宵。", "陰風吹大澤，夢日照昌朝。", "不獨華封老，千年喜祝堯。"]'),
('632a1b6e-2fbe-487e-9648-e79134ff15f4','晦日詔宴永穆公主亭子賦得流字','張說','唐','唐诗','tang','','[]','堂邑山林美，朝恩晦日遊。',48,'全唐诗/poet.tang.4000.json','["堂邑山林美，朝恩晦日遊。", "園亭含淑氣，竹樹遶春流。", "舞席千花妓，歌船五彩樓。", "羣歡與王澤，歲歲滿皇州。"]'),
('408d5a1a-2138-4212-9d31-8f86d17d38b1','恩制賜食於麗正殿書院宴賦得林字','張說','唐','唐诗','tang','','[]','東壁圖書府，西園翰墨林。',48,'全唐诗/poet.tang.4000.json','["東壁圖書府，西園翰墨林。", "誦詩聞國政，講易見天心。", "位竊和羹重，恩叨醉酒深。", "緩歌春興曲，情竭爲知音。"]'),
('56f2a004-7042-4a89-9cda-c9e238b1cc5b','羽林恩召觀御書王太尉碑','張說','唐','唐诗','tang','','[]','隴首名公石，來承聖札歸。',48,'全唐诗/poet.tang.4000.json','["隴首名公石，來承聖札歸。", "魚龍生意態，鉤劒動鋩輝。", "字得神明保，詞慙少女徽。", "誰家羽林將，又逐鳳書飛。"]'),
('18b9bb50-2d2a-46be-bff0-31d7061c0399','東都酺宴四首 一','張說','唐','唐诗','tang','','[]','重華昇寶曆，軒帝眇閑居。',48,'全唐诗/poet.tang.4000.json','["重華昇寶曆，軒帝眇閑居。", "政成天子孝，俗返上皇初。", "忘味因觀樂，歡心寄合酺。", "自憐疲馬意，戀戀主恩餘。"]'),
('73298021-0132-4783-806e-fe1e8eb036fc','東都酺宴四首 二','張說','唐','唐诗','tang','','[]','朱城塵曀滅，翠幕景情開。',48,'全唐诗/poet.tang.4000.json','["朱城塵曀滅，翠幕景情開。", "震震靈鼉起，翔翔舞鳳來。", "雕盤裝草樹，綺乘結樓臺。", "共喜光華日，酣歌捧玉杯。"]'),
('db1ed665-4598-4165-a6ed-c2c027ef6fe8','東都酺宴四首 三','張說','唐','唐诗','tang','','[]','曉月調金闕，朝暾對玉盤。',48,'全唐诗/poet.tang.4000.json','["曉月調金闕，朝暾對玉盤。", "爭馳羣鳥散，鬬伎百花團。", "遇聖人知幸，承恩物自歡。", "洛橋將舉燭，醉舞拂歸鞍。"]'),
('b6e88877-e4fb-4912-a6d4-c3c9ca45e84d','東都酺宴四首 四','張說','唐','唐诗','tang','','[]','愷宴惟今席，餘歡殊未窮。',48,'全唐诗/poet.tang.4000.json','["愷宴惟今席，餘歡殊未窮。", "入雲歌嫋嫋，向日伎叢叢。", "駛管催酣興，留關待曲終。", "長安若爲樂，應與萬方同。"]'),
('97d8ec10-5701-49f4-911d-e0bf0ff0b179','道家四首奉敕撰 一','張說','唐','唐诗','tang','','[]','金壇啓曙闈，真氣肅微微。',48,'全唐诗/poet.tang.4000.json','["金壇啓曙闈，真氣肅微微。", "落月銜仙竇，初霞拂羽衣。", "香隨龍節下，雲逐鳳簫飛。", "暫住蓬萊戲，千年始一歸。"]'),
('8b52608e-68e4-4ff7-aca2-f385ac7eb4cc','道家四首奉敕撰 二','張說','唐','唐诗','tang','','[]','窈窕流精觀，深沈紫翠庭。',48,'全唐诗/poet.tang.4000.json','["窈窕流精觀，深沈紫翠庭。", "金匳調上藥，寶案讀仙經。", "作賦看神雨，乘槎辨客星。", "秪應謝人俗，輕舉托雲軿。"]'),
('1b1933b1-1971-4c5a-b8c7-c9fcd9531464','道家四首奉敕撰 三','張說','唐','唐诗','tang','','[]','金爐承道訣，玉牒啓玄機。',48,'全唐诗/poet.tang.4000.json','["金爐承道訣，玉牒啓玄機。", "雲逐笙歌度，星流宮殿飛。", "乘風嬉浩蕩，窺月弄光輝。", "唯有三山鶴，應同千載歸。"]'),
('1fe376a0-6337-4ef8-b2ba-7f8d80ecc10b','道家四首奉敕撰 四','張說','唐','唐诗','tang','','[]','道記開中籙，真官表上清。',48,'全唐诗/poet.tang.4000.json','["道記開中籙，真官表上清。", "焚香三鳥至，煉藥九仙成。", "天上靈書下，空中妙伎迎。", "迎來出煙霧，渺渺戲蓬瀛。"]'),
('6a9b373c-d05e-40bb-9723-4e79166c8557','鳳樓尋勝地','張說','唐','唐诗','tang','','[]','西掖持醇酒，東山就白雲。',48,'全唐诗/poet.tang.4000.json','["西掖持醇酒，東山就白雲。", "開軒綠池映，命席紫蘭芬。", "舞度花爲伴，鶯來管作羣。", "太平多樂事，春物共氛氳。"]'),
('57cb7c60-6ef4-4ba3-be91-13b1a5a9c3d5','幽州夜飲','張說','唐','唐诗','tang','','["\u5199\u666f", "\u8fb9\u585e"]','涼風吹夜雨，蕭瑟動寒林。',48,'全唐诗/poet.tang.4000.json','["涼風吹夜雨，蕭瑟動寒林。", "正有高堂宴，能忘遲暮心。", "軍中宜劒舞，塞上重笳音。", "不作邊城將，誰知恩遇深。"]'),
('b26d418d-e816-4ef1-bfeb-5266aa57eb74','崔禮部園亭得深字','張說','唐','唐诗','tang','','[]','窈窕留清館，虛徐步晚陰。',48,'全唐诗/poet.tang.4000.json','["窈窕留清館，虛徐步晚陰。", "水連伊闕近，樹接夏陽深。", "柳蔓憐垂拂，藤梢愛上尋。", "訝君軒蓋侶，非復俗人心。"]'),
('2274cb47-305e-49bb-90c3-2f7d45153bdd','送鄭大夫惟忠從公主入蕃','張說','唐','唐诗','tang','','[]','鳳吹遙將斷，龍旗送欲還。',48,'全唐诗/poet.tang.4000.json','["鳳吹遙將斷，龍旗送欲還。", "傾都邀節使，傳酌緩離顏。", "春磧沙連海，秋城月對關。", "和戎因賞魏，定遠莫辭班。"]'),
('42417af2-2744-4dc2-9f2b-f1f2579009d3','送崔二長史日知赴潞州','張說','唐','唐诗','tang','','[]','東山懷臥理，南省悵悲翁。',48,'全唐诗/poet.tang.4000.json','["東山懷臥理，南省悵悲翁。", "共見前途促，何知後會同。", "莫輕一筵宴，明日半成空。", "況爾新離闕，思歸迷夢中。"]'),
('a6eaa0da-11c3-44cf-9234-36e91ea5d8a8','同賀八送兗公赴荆州','張說','唐','唐诗','tang','','[]','疇昔同聲友，騫飛出鳳池。',48,'全唐诗/poet.tang.4000.json','["疇昔同聲友，騫飛出鳳池。", "風雲一蕩薄，日月屢參差。", "此別黃葉下，前期安可知。", "誰憐楚南樹，不爲歲寒移。"]'),
('43da0758-7295-4538-aa20-35af9e371ee3','餞唐州高使君','張說','唐','唐诗','tang','','[]','常時好閑獨，朋舊少相過。',48,'全唐诗/poet.tang.4000.json','["常時好閑獨，朋舊少相過。", "及爾宣風去，方嗟別日多。", "淮流春晼晚，江海路蹉跎。", "百歲屢分散，歡言復幾何。"]'),
('4caa7c43-48aa-47ab-8d24-941e2db79553','送王晙自羽林赴永昌令','張說','唐','唐诗','tang','','[]','將星移北洛，神雨避東京。',48,'全唐诗/poet.tang.4000.json','["將星移北洛，神雨避東京。", "爲負剛腸譽，還追強項名。", "白雲向伊闕，黃葉散昆明。", "多謝弦歌宰，稀聞桴鼓聲。"]'),
('46adbad6-193a-4a69-bd5e-f0252646b181','同王僕射山亭餞岑廣武羲得言字','張說','唐','唐诗','tang','','[]','聞道長岑令，奮翼宰旅門。',48,'全唐诗/poet.tang.4000.json','["聞道長岑令，奮翼宰旅門。", "長安東陌上，送客滿朱軒。", "琴爵留佳境，山池借好園。", "茲遊恨不見，別後綴離言。"]'),
('9322de4f-e476-4bc0-909a-a2b8736211c3','送任御史江南發糧以賑河北百姓','張說','唐','唐诗','tang','','[]','河朔人無歲，荆南義廩開。',48,'全唐诗/poet.tang.4000.json','["河朔人無歲，荆南義廩開。", "將興汎舟役，必仗濟川才。", "夜月臨江浦，春雲歷楚臺。", "調飢坐相望，繡服幾時回。"]'),
('35ea4a2f-60f9-445b-ad9e-c54c15b11ca9','送王尚一嚴嶷二侍御赴司馬都督軍','張說','唐','唐诗','tang','','[]','漢掖通沙塞，邊兵護草腓。',48,'全唐诗/poet.tang.4000.json','["漢掖通沙塞，邊兵護草腓。", "將行司馬令，助以鐵冠威。", "白露鷹初下，黃塵騎欲飛。", "明年春酒熟，留酌二星歸。"]'),
('847ecb84-d347-4e13-a810-528db3163dfd','送李問政河北簡兵','張說','唐','唐诗','tang','','[]','斗酒貽朋愛，躊躕出御溝。',48,'全唐诗/poet.tang.4000.json','["斗酒貽朋愛，躊躕出御溝。", "依然四牡別，更想八龍遊。", "密親仕燕冀，連年邇寇讐。", "因君閱河朔，垂淚語幽州。"]'),
('2d80cf61-ce91-4f3c-9c49-01ef44427e14','送薛植入京','張說','唐','唐诗','tang','','[]','青組言從史，鴻都忽見求。',48,'全唐诗/poet.tang.4000.json','["青組言從史，鴻都忽見求。", "款言人向老，飲別歲方秋。", "髣髴長安陌，平生是舊遊。", "何時復相遇，宛在水中流。"]'),
('57b351f8-4e44-4109-9e3f-47464b6c740f','相州前池別許鄭二判官景先神力','張說','唐','唐诗','tang','','[]','數步圓塘水，雙鴻戢羽儀。',48,'全唐诗/poet.tang.4000.json','["數步圓塘水，雙鴻戢羽儀。", "一飛喬木上，一返故林垂。", "澹泊含秋景，虛明抱夜規。", "無因留絕翰，雲海意差池。"]'),
('b169d271-062d-4ba5-b8e4-e8a620a6f804','岳州宴別潭州王熊二首 一','張說','唐','唐诗','tang','','[]','絲管清且哀，一曲傾一杯。',48,'全唐诗/poet.tang.4000.json','["絲管清且哀，一曲傾一杯。", "氣將然諾重，心向友朋開。", "古木無生意，寒雲若死灰。", "贈君芳杜草，爲植建章臺。"]'),
('9b51df46-0dc4-4f8a-b960-cf66c4a3adec','岳州宴別潭州王熊二首 二','張說','唐','唐诗','tang','','[]','縉雲連省閣，溝水遽西東。',48,'全唐诗/poet.tang.4000.json','["縉雲連省閣，溝水遽西東。", "然諾心猶在，榮華歲不同。", "孤城臨楚塞，遠樹入秦宮。", "誰念三千里，江潭一老翁。"]'),
('3f848ccb-ab8f-4b0d-8492-9241874c340f','廣州蕭都督入朝過岳州宴餞得冬字','張說','唐','唐诗','tang','','[]','孤城抱大江，節使往朝宗。',48,'全唐诗/poet.tang.4000.json','["孤城抱大江，節使往朝宗。", "果是臺中舊，依然水上逢。", "京華遙比日，疲老颯如冬。", "竊羨能言鳥，銜恩向九重。"]'),
('35484a7d-55ec-479c-a90e-31084ead58a2','岳州別姚司馬紹之制許歸侍','張說','唐','唐诗','tang','','[]','和玉悲無已，長沙宦不成。',48,'全唐诗/poet.tang.4000.json','["和玉悲無已，長沙宦不成。", "天從扇枕願，人遂倚門情。", "方外懷司馬，江東憶步兵。", "問君棲泊處，空嶺夜猿驚。"]'),
('da7d6df5-d65e-4a4b-ba4c-f86f19e929a6','送岳州李十從軍桂州','張說','唐','唐诗','tang','','[]','送客之江上，其人美且才。',48,'全唐诗/poet.tang.4000.json','["送客之江上，其人美且才。", "風波萬里闊，故舊十年來。", "劒拔蛟隨斷，弓張鳥自摧。", "陽橋書落落，驛馬定先回。"]'),
('b9ccaa26-8551-45a7-a699-c78736e20720','岳州別趙國公王十一琚入朝','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','昔濫貂蟬長，同承雨露霏。',48,'全唐诗/poet.tang.4000.json','["昔濫貂蟬長，同承雨露霏。", "今參魚鱉守，望美洞庭歸。", "浦樹懸秋影，江雲燒落輝。", "離魂似征帆，恆往帝鄉飛。"]'),
('30f5195f-65b7-410f-973a-6cdb95070def','岳州別子均','張說','唐','唐诗','tang','','[]','離筵非燕喜，別酒正銷魂。',48,'全唐诗/poet.tang.4000.json','["離筵非燕喜，別酒正銷魂。", "念汝猶童孺，嗟予隔遠藩。", "津亭拔心草，江路斷腸猿。", "他日將何見，愁來獨倚門。"]'),
('e755ba23-405e-42fa-afbe-a514a2b9b807','端州別高六戩','張說','唐','唐诗','tang','','[]','異壤同羈竄，途中喜共過。',48,'全唐诗/poet.tang.4000.json','["異壤同羈竄，途中喜共過。", "愁多時舉酒，勞罷或長歌。", "南海風潮壯，西江瘴癘多。", "於焉復分手，此別傷如何。"]'),
('91ab2824-2a44-4aaf-9ae2-5df8dbc96753','南中別蔣五岑向青州','張說','唐','唐诗','tang','','[]','老親依北海，賤子棄南荒。',48,'全唐诗/poet.tang.4000.json','["老親依北海，賤子棄南荒。", "有淚皆成血，無聲不斷腸。", "此中逢故友，彼地送還鄉。", "願作楓林葉，隨君度洛陽。"]'),
('e9732735-65bf-471f-bdb0-2fd5a4a765b7','南中別陳七李十','張說','唐','唐诗','tang','','[]','二年共遊處，一旦各西東。',48,'全唐诗/poet.tang.4000.json','["二年共遊處，一旦各西東。", "請君聊駐馬，看我轉征蓬。", "畫鷁愁南海，離駒思北風。", "何時似春雁，雙入上林中。"]'),
('9134a60e-1366-424b-baa3-634f3ddbbd52','南中別王陵成崇','張說','唐','唐诗','tang','','[]','握手與君別，歧路贈一言。',48,'全唐诗/poet.tang.4000.json','["握手與君別，歧路贈一言。", "曹卿禮公子，楚媼饋王孫。", "倏爾生六翮，翻飛戾九門。", "常懷客鳥意，會答主人恩。"]'),
('b8a3e739-43a9-4425-b2d1-0d8350ba852b','嶺南送使','張說','唐','唐诗','tang','','[]','秋雁逢春返，流人何日歸？',48,'全唐诗/poet.tang.4000.json','["秋雁逢春返，流人何日歸？", "將余去國淚，灑子入鄉衣。", "飢狖啼相聚，愁猿喘更飛。", "南中不可問，書此示京畿。"]'),
('5b15384f-f05f-4b0e-a131-af5e4162d3a4','幽州別陰長河行先','張說','唐','唐诗','tang','','[]','惠好交情重，辛勤世事多。',48,'全唐诗/poet.tang.4000.json','["惠好交情重，辛勤世事多。", "荆南久爲別，薊北遠來過。", "寄目雲中鳥，留歡酒上歌。", "影移春復間，遲暮兩如何。"]'),
('f8665b35-36e5-4230-9d54-234c61e341a0','和朱使欣道峽似巫山之作','張說','唐','唐诗','tang','','[]','江如曉天淨，石似暮霞張。',48,'全唐诗/poet.tang.4000.json','["江如曉天淨，石似暮霞張。", "征帆一流覽，宛若巫山陽。", "楚客思歸路，秦人謫異鄉。", "猿鳴孤月夜，再使淚沾裳。"]'),
('83214349-d778-44de-9f0f-5b3d627ebad3','和朱使欣二首 一','張說','唐','唐诗','tang','','[]','南土多爲寇，西江盡畏途。',48,'全唐诗/poet.tang.4000.json','["南土多爲寇，西江盡畏途。", "山行阻篁竹，水宿礙萑蒲。", "使越才應有，征蠻力豈無。", "空傳人贈劒，不見虎銜珠。"]'),
('0362b9af-d549-4eaf-8361-0f2f531ee392','和朱使欣二首 二','張說','唐','唐诗','tang','','[]','江勢連山遠，天涯此夜愁。',48,'全唐诗/poet.tang.4000.json','["江勢連山遠，天涯此夜愁。", "霜空極天靜，寒月帶江流。", "思起南征棹，文高北望樓。", "自憐如墜葉，泛泛侶仙舟。"]'),
('9fae120f-15c9-4eef-82a9-f7ca563e06a1','過庾信宅','張說','唐','唐诗','tang','','[]','蘭成追宋玉，舊宅偶詞人。',48,'全唐诗/poet.tang.4000.json','["蘭成追宋玉，舊宅偶詞人。", "筆湧江山氣，文驕雲雨神。", "包胥非救楚，隨會反留秦。", "獨有東陽守，來嗟古樹春。"]'),
('05133f97-474d-4030-91f6-fdc78b04afcc','盧巴驛聞張御史張判官欲到不得待留贈之','張說','唐','唐诗','tang','','[]','旅竄南方遠，傳聞北使來。',48,'全唐诗/poet.tang.4000.json','["旅竄南方遠，傳聞北使來。", "舊庭知玉樹，合浦識珠胎。", "白髮因愁改，丹心托夢廻。", "皇恩若再造，爲憶不然灰。"]'),
('66c5487f-370a-4f0b-8395-ce185814ac2a','南中贈高六戩','張說','唐','唐诗','tang','','[]','北極辭明代，南溟宅放臣。',48,'全唐诗/poet.tang.4000.json','["北極辭明代，南溟宅放臣。", "丹誠由義盡，白髮帶愁新。", "鳥墜炎洲氣，花飛洛水春。", "平生歌舞席，誰憶不歸人。"]'),
('c5033e04-6379-4c84-a7ad-6a387748cee9','岳州山城','張說','唐','唐诗','tang','','[]','山城豐日暇，閉戶見天心。',48,'全唐诗/poet.tang.4000.json','["山城豐日暇，閉戶見天心。", "東曠迎朝色，西樓引夕陰。", "書觀千載近，學靜二毛深。", "忽有南風至，吹君堂上琴。"]'),
('0bc309e8-0d5f-462b-ae8a-30f4d2801bbc','和尹懋秋夜遊㴩湖','張說','唐','唐诗','tang','','[]','㴩湖佳可遊，既近復能幽。',48,'全唐诗/poet.tang.4000.json','["㴩湖佳可遊，既近復能幽。", "林裏棲精舍，山間轉去舟。", "雁飛江月冷，猿嘯野風秋。", "不是迷鄉客，尋奇處處留。"]'),
('d5181d49-2b38-40ca-8f28-2a1b3c02810d','與趙冬曦尹懋子均登南樓','張說','唐','唐诗','tang','','[]','危樓瀉洞湖，積水照城隅。',48,'全唐诗/poet.tang.4000.json','["危樓瀉洞湖，積水照城隅。", "命駕邀漁火，通家引鳳雛。", "山晴紅蘂匝，洲曉綠苗鋪。", "舉目思鄉縣，春光定不殊。"]'),
('367e8d94-9363-42df-8d87-3d4f2a20898b','遊㴩湖上寺','張說','唐','唐诗','tang','','[]','湖上奇峰積，山中芳樹春。',48,'全唐诗/poet.tang.4000.json','["湖上奇峰積，山中芳樹春。", "何知絕世境，來遇賞心人。", "清舊巖前樂，呦嚶鳥獸馴。", "靜言觀聽裏，萬法自成輪。"]'),
('0d490872-2d79-4a7e-98c2-c444c94cb7cf','晦日','張說','唐','唐诗','tang','','[]','晦日嫌春淺，江浦看湔衣。',48,'全唐诗/poet.tang.4000.json','["晦日嫌春淺，江浦看湔衣。", "道傍花欲合，枝上鳥猶稀。", "共憶浮橋晚，無人不醉歸。", "寄書題此日，雁過洛陽飛。"]'),
('ae708f30-8b96-4973-9d9c-f674eb603572','湘州九日城北亭子','張說','唐','唐诗','tang','','[]','西楚茱萸節，南淮戲馬臺。',48,'全唐诗/poet.tang.4000.json','["西楚茱萸節，南淮戲馬臺。", "寧知沅水上，復有菊花杯。", "亭帳憑高出，親朋自遠來。", "短歌將急景，同使興情催。"]'),
('44d2e0d8-114b-4364-9c08-6372c05deb75','翻著葛巾呈趙尹','張說','唐','唐诗','tang','','[]','昔日接㒿倒，今我葛巾翻。',48,'全唐诗/poet.tang.4000.json','["昔日接㒿倒，今我葛巾翻。", "宿酒何時醒，形骸不復存。", "忽聞有嘉客，躧步出閑門。", "桃花春徑滿，誤識武陵源。"]'),
('d6aed324-262c-4917-a86c-d9defc45ad3e','戲題草樹','張說','唐','唐诗','tang','','[]','忽驚石榴樹，遠出渡江來。',48,'全唐诗/poet.tang.4000.json','["忽驚石榴樹，遠出渡江來。", "戲問芭蕉葉，何愁心不開。", "微霜拂宮桂，淒吹掃庭槐。", "榮盛更如此，慙君獨見哀。"]'),
('56354da7-a86d-4fff-b5e6-68ee489e3ae6','岳州贈廣平公宋大夫','張說','唐','唐诗','tang','','[]','亞相本時英，歸來復國楨。',50,'全唐诗/poet.tang.4000.json','["亞相本時英，歸來復國楨。", "朝推長孺直，野慕隱之清。", "傳節還閩嶂，皇華入漢京。", "寧思江上老，歲[晏]獨無成。"]'),
('380f90d8-c49d-4796-b4eb-9325ec1ae51a','和魏僕射還鄉','張說','唐','唐诗','tang','','[]','富貴還鄉國，光華滿舊林。',48,'全唐诗/poet.tang.4000.json','["富貴還鄉國，光華滿舊林。", "秋風樹不靜，君子歎何深。", "故老空懸劒，鄰交日散金。", "衆芳搖落盡，獨有歲寒心。"]'),
('02fc6b63-398c-4824-b91d-88e95d3900cb','和張監觀赦','張說','唐','唐诗','tang','','[]','日御臨雙闕，天街儼百神。',48,'全唐诗/poet.tang.4000.json','["日御臨雙闕，天街儼百神。", "雷茲作解氣，歲復建寅春。", "喜候開星驛，歡聲發市人。", "金環能作賦，來入管弦聲。"]'),
('0f9a37b3-d2f3-4cab-82ec-42cbdf9009d2','寄天台司馬道士','張說','唐','唐诗','tang','','[]','世上求真客，天台去不還。',48,'全唐诗/poet.tang.4000.json','["世上求真客，天台去不還。", "傳聞有仙要，夢寐在茲山。", "朱闕青霞斷，瑤堂紫月閑。", "何時枉飛鶴，笙吹接人間。"]'),
('0a9887e7-a451-4c8a-958f-e6fb492b059d','下江南向夔州','張說','唐','唐诗','tang','','[]','天明江霧歇，洲浦棹歌來。',48,'全唐诗/poet.tang.4000.json','["天明江霧歇，洲浦棹歌來。", "綠水逶迤去，青山相向開。", "城臨蜀帝祀，雲接楚王臺。", "舊知巫山上，遊子共徘徊。"]'),
('9c2ee474-431f-4932-b0a0-8d2eca3e3c5b','還至端州驛前與高六別處','張說','唐','唐诗','tang','','[]','舊館分江日，悽然望落暉。',48,'全唐诗/poet.tang.4000.json','["舊館分江日，悽然望落暉。", "相逢傳旅食，臨別換征衣。", "昔記山川是，今傷人代非。", "往來皆此路，生死不同歸。"]'),
('633b6184-f88c-45d4-9d7a-0a73a584c4f2','四月一日過江赴荆州','張說','唐','唐诗','tang','','[]','春色沅湘盡，三年客始回。',48,'全唐诗/poet.tang.4000.json','["春色沅湘盡，三年客始回。", "夏雲隨北帆，同日過江來。", "水漫荆門出，山平郢路開。", "比肩羊叔子，千載豈無才。"]'),
('1758b317-c423-47ff-9925-1aca2c0018a9','湘州北亭','張說','唐','唐诗','tang','','[]','人務南亭少，風煙北院多。',48,'全唐诗/poet.tang.4000.json','["人務南亭少，風煙北院多。", "山花迷徑路，池水拂藤蘿。", "萍散魚時躍，林幽鳥任歌。", "悠然白雲意，乘興抱琴過。"]'),
('831d51fb-3169-467e-b8f8-5010bf9d0aa6','荆州亭入朝','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','巫山雲雨峽，湘水洞庭波。',48,'全唐诗/poet.tang.4000.json','["巫山雲雨峽，湘水洞庭波。", "九辨人猶擯，三秋鴈始過。", "旃裘吳地盡，髫薦楚言多。", "不果朝宗願，其如江漢何。"]'),
('80d7b7e6-9fc1-489b-9c46-a72cb9868fdb','岳州守歲','張說','唐','唐诗','tang','','[]','除夜清樽滿，寒庭燎火多。',48,'全唐诗/poet.tang.4000.json','["除夜清樽滿，寒庭燎火多。", "舞衣連臂拂，醉坐合聲歌。", "至樂都忘我，冥心自委和。", "今年只如此，來歲知如何。"]'),
('10a46b89-ddd7-4e66-8ad4-acf1e2bca7d4','詠塵','張說','唐','唐诗','tang','','[]','仙浦生羅襪，神京染素衣。',48,'全唐诗/poet.tang.4000.json','["仙浦生羅襪，神京染素衣。", "裨山期益峻，照日幸增輝。", "夕伴龍媒合，朝遊鳳輦歸。", "獨憐范甑下，思繞畫梁飛。"]'),
('716debdd-daf8-4993-9547-7b88ff246619','闕題','張說','唐','唐诗','tang','','[]','婚禮知無賀，承家歎有輝。',48,'全唐诗/poet.tang.4000.json','["婚禮知無賀，承家歎有輝。", "親迎驥子躍，吉兆鳳雛飛。", "溫席開華扇，梁門換褧衣。", "遙思桃李日，應賦採蘋歸。"]'),
('ddd610ff-0140-4d56-978f-2b14de7f1ce6','深渡驛','張說','唐','唐诗','tang','','[]','旅泊青山夜，荒庭白露秋。',48,'全唐诗/poet.tang.4000.json','["旅泊青山夜，荒庭白露秋。", "洞房懸月影，高枕聽江流。", "猿響寒巖樹，螢飛古驛樓。", "他鄉對搖落，倂覺起離憂。"]'),
('f30037f0-0219-46eb-a376-2143c22cf226','惠文太子挽歌二首 一','張說','唐','唐诗','tang','','[]','碣館英靈在，瑤山美諡尊。',48,'全唐诗/poet.tang.4000.json','["碣館英靈在，瑤山美諡尊。", "剪桐悲曩戲，攻玉愴新恩。", "宮仗傳馳道，朝衣送國門。", "千秋穀門外，明月照西園。"]'),
('d85f2427-bdca-4033-8bbf-b4cf2debc7b4','惠文太子挽歌二首 二','張說','唐','唐诗','tang','','[]','梁國深文雅，淮王愛道仙。',48,'全唐诗/poet.tang.4000.json','["梁國深文雅，淮王愛道仙。", "帝歡同宴日，神奪上賓年。", "旒旐飛行樹，帷宮宿野煙。", "指言君愛弟，揮淚滿山川。"]'),
('99e401c1-6bb0-42fb-accc-789d8445dd89','節義太子楊妃挽歌二首 一','張說','唐','唐诗','tang','','[]','西華三公族，東闈五可才。',48,'全唐诗/poet.tang.4000.json','["西華三公族，東闈五可才。", "玉環初受慶，金玦反逢灾。", "桂殿花空落，桐園月自開。", "朝雲將暮雨，長繞望思臺。"]'),
('4f4a4baf-acda-4286-9b8e-3442a2208daf','節義太子楊妃挽歌二首 二','張說','唐','唐诗','tang','','[]','昔日三朝路，逶迤四望車。',48,'全唐诗/poet.tang.4000.json','["昔日三朝路，逶迤四望車。", "繡腰長命綺，隱髻連枝花。", "今春戾園樹，索然無歲華。", "共傷千載後，惟號一王家。"]'),
('9fe43f0a-2fae-408e-ba7f-a28867154a48','韋譙公挽歌二首 一','張說','唐','唐诗','tang','','[]','五瑞分王國，雙珠映后家。',48,'全唐诗/poet.tang.4000.json','["五瑞分王國，雙珠映后家。", "文飛書上鳳，武結笥中蛇。", "出豫榮前馬，迴鸞喪後車。", "衮衣將錫命，泉路有光華。"]'),
('2f02e3d7-6f8b-449b-b638-6ca1ebdb645a','韋譙公挽歌二首 二','張說','唐','唐诗','tang','','[]','國騁雙騏驥，庭儀兩鳳皇。',48,'全唐诗/poet.tang.4000.json','["國騁雙騏驥，庭儀兩鳳皇。", "將星連相位，玉樹伴金鄉。", "歌舞侯家豔，軒裘戚里光。", "安知杜陵下，碑版已相望。"]'),
('25f360d9-fbcf-4ef8-b887-44f20f394df6','右丞相蘇公挽歌二首 一','張說','唐','唐诗','tang','','[]','王宰丹青化，春卿禮樂才。',48,'全唐诗/poet.tang.4000.json','["王宰丹青化，春卿禮樂才。", "緇衣傳舊職，華衮贈新哀。", "路泣羣官送，山嘶駟馬廻。", "佳辰無白日，賓閣有青苔。"]'),
('99a9936c-251a-4570-869c-d27d9ccde5d5','右丞相蘇公挽歌二首 二','張說','唐','唐诗','tang','','[]','門歌出野田，冠帶寢窮泉。',48,'全唐诗/poet.tang.4000.json','["門歌出野田，冠帶寢窮泉。", "萬事皆身外，平生尚目前。", "西垣紫泥綍，東岳白雲篇。", "自惜同聲處，從今遂絕弦。"]'),
('2985672d-34c2-4224-9006-61772e1f5b7d','崔尚書挽詞','張說','唐','唐诗','tang','','[]','相宅隆坤寶，承家占海封。',48,'全唐诗/poet.tang.4000.json','["相宅隆坤寶，承家占海封。", "庭中男執雁，門外女乘龍。", "鳴玉遊三省，摐金侍九重。", "一朝賓客散，留劒在青松。"]'),
('1d4ffa6b-ecd0-4c9a-82c0-464dae572bfa','右侍郎集賢院學士徐公挽詞二首 一','張說','唐','唐诗','tang','','[]','才美臨淄北，名高淮海東。',36,'全唐诗/poet.tang.4000.json','["才美臨淄北，名高淮海東。", "羽儀三省遍，漁獵五車通。", "玉殿孤新榜，珠英落舊叢。"]'),
('289a1980-a537-48ab-bd28-8f16368277bc','右侍郎集賢院學士徐公挽詞二首 二','張說','唐','唐诗','tang','','[]','歎息書林友，才華天下選。',48,'全唐诗/poet.tang.4000.json','["歎息書林友，才華天下選。", "並賦三陽宮，集詩集賢殿。", "具物衣如在，咄嗟長不見。", "既哀薤露詞，豈忘平生眷。"]'),
('dd4f7b09-d23a-46b6-90f9-c6c1dd2ceb48','崔司業挽歌二首 一','張說','唐','唐诗','tang','','[]','海岱英靈氣，膠庠禮樂資。',48,'全唐诗/poet.tang.4000.json','["海岱英靈氣，膠庠禮樂資。", "風流滿天下，人物擅京師。", "疾起揚雄賦，魂遊謝客詩。", "從今好文主，遺恨不同時。"]'),
('71b62c64-fd71-4f74-af58-7fdc4bd8a035','崔司業挽歌二首 二','張說','唐','唐诗','tang','','[]','象設存華館，威儀下墓田。',48,'全唐诗/poet.tang.4000.json','["象設存華館，威儀下墓田。", "鳳池傷舊草，麟史泣遺編。", "帷蓋墟煙沒，干旌隴日懸。", "古來埋玉樹，流恨滿山川。"]'),
('3804fdf5-85f5-447b-8637-abb3630009f2','李工部挽歌三首 一','張說','唐','唐诗','tang','','[]','錦帳爲郎日，金門待詔時。',48,'全唐诗/poet.tang.4000.json','["錦帳爲郎日，金門待詔時。", "楊宮先上賦，柏殿幾連詩。", "瞬息琴歌斷，淒涼簫挽悲。", "那堪霸陵岸，回首望京師。"]'),
('6e4061d4-62c7-4d83-a110-62c949eb5be6','李工部挽歌三首 二','張說','唐','唐诗','tang','','[]','宅兆西陵上，平生雅志從。',48,'全唐诗/poet.tang.4000.json','["宅兆西陵上，平生雅志從。", "城臨丹闕近，山望白雲重。", "會葬知元伯，看碑識蔡邕。", "無由接神理，揮涕向青松。"]'),
('7fce41df-6ee8-4dae-b8e6-846a6a7651a1','李工部挽歌三首 三','張說','唐','唐诗','tang','','[]','常時好賓客，永日對弦歌。',48,'全唐诗/poet.tang.4000.json','["常時好賓客，永日對弦歌。", "是日歸泉下，傷心無奈何。", "墓庭人已散，祭處鳥來過。", "碑石生苔蘚，榮名豈復多。"]'),
('e0a82f01-5e36-40d9-a73c-da9112eaffe3','贈工部尚書馮公挽歌三首 一','張說','唐','唐诗','tang','','[]','忠鯁難爲事，平生盡畏途。',48,'全唐诗/poet.tang.4000.json','["忠鯁難爲事，平生盡畏途。", "如弦心自直，秀木勢恆孤。", "詔葬南陵道，神遊北斗樞。", "貴門傳萬石，餘慶在雙珠。"]'),
('ac6a73d5-8d2a-47a2-8c79-99359b13ce5b','贈工部尚書馮公挽歌三首 二','張說','唐','唐诗','tang','','[]','爵位題龍旐，威儀出鳳城。',48,'全唐诗/poet.tang.4000.json','["爵位題龍旐，威儀出鳳城。", "路傍人泣送，門外馬嘶迎。", "萬事非吾有，千悲是世情。", "昔焉稱夏日，今也謚冬卿。"]'),
('436eb066-ab58-4779-bb03-7919b4f66201','贈工部尚書馮公挽歌三首 三','張說','唐','唐诗','tang','','[]','窅然長夜臺，舉世可哀哉。',48,'全唐诗/poet.tang.4000.json','["窅然長夜臺，舉世可哀哉。", "泉戶一朝閉，松風四面來。", "石碑填駮蘚，珠服聚塵埃。", "誰言遼東鶴，千年往復廻。"]'),
('39148525-f5ba-45a7-a457-f2a67bbd5ffe','徐高御挽歌','張說','唐','唐诗','tang','','[]','蒲密遙千載，鳴琴始一追。',48,'全唐诗/poet.tang.4000.json','["蒲密遙千載，鳴琴始一追。", "公卿傳世範，仁義續靈基。", "不待南遊祿，何先北帝期。", "玉棺從此閉，金鼎代相欺。"]'),
('be118625-70d0-41ac-a76d-b4811a9208cb','奉和聖製春日幸望春宮應制','張說','唐','唐诗','tang','','[]','別館芳菲上苑東，飛花澹蕩御筵紅。',64,'全唐诗/poet.tang.4000.json','["別館芳菲上苑東，飛花澹蕩御筵紅。", "城臨渭水天河靜，闕對南山雨露通。", "繞殿流鶯凡幾樹，當蹊亂蝶許多叢。", "春園既醉心和樂，共識皇恩造化同。"]'),
('e5dee431-e8d1-49ce-ba8f-5ce10b4af5e7','侍宴隆慶池應制','張說','唐','唐诗','tang','','[]','靈池月滿直城隈，黻帳天臨御路開。',64,'全唐诗/poet.tang.4000.json','["靈池月滿直城隈，黻帳天臨御路開。", "東沼初陽疑吐出，南山曉翠若浮來。", "魚龍百戲紛容與，鳧鷁雙舟較泝洄。", "願似金隄青草馥，長承瑤水白雲杯。"]'),
('6bf840dc-3998-4f70-aecc-033e36f0f619','奉和聖製春日出苑應制','張說','唐','唐诗','tang','','[]','禁林豔裔發青陽，春望逍遙出畫堂。',64,'全唐诗/poet.tang.4000.json','["禁林豔裔發青陽，春望逍遙出畫堂。", "雨洗亭臯千畝綠，風吹梅李一園香。", "鶴飛不去隨青管，魚躍翻來入綵航。", "睿賞歡承天保定，遒文更覩日重光。"]'),
('dbc7d36b-792f-44e1-9e97-cad3f39947b7','扈從溫泉宮獻詩','張說','唐','唐诗','tang','','[]','溫泉啓蟄氣氛氳，渭浦歸鴻日數羣。',64,'全唐诗/poet.tang.4000.json','["溫泉啓蟄氣氛氳，渭浦歸鴻日數羣。", "騎仗聯聯環北極，鳴笳步步引南熏。", "松間彩殿籠佳氣，山上朱旗繞瑞雲。", "不知遠夢華胥國，何如親奉帝堯君。"]'),
('7986eede-077b-4351-8589-a8ceb6b7104e','三月三日詔宴定昆池宮莊賦得筵字','張說','唐','唐诗','tang','','[]','鳳皇樓下對天泉，鸚鵡洲中匝管弦。',64,'全唐诗/poet.tang.4000.json','["鳳皇樓下對天泉，鸚鵡洲中匝管弦。", "舊識平陽佳麗地，今逢上巳盛明年。", "舟將水動千尋日，幕共林橫兩岸煙。", "不降玉人觀禊飲，誰令醉舞拂賓筵。"]'),
('8b8aca24-fba7-4b5b-8f05-97a9f0e4eb0f','先天應令','張說','唐','唐诗','tang','','[]','三陽麗景早芳辰，四序嘉園物候新。',64,'全唐诗/poet.tang.4000.json','["三陽麗景早芳辰，四序嘉園物候新。", "梅花百般障行路，垂柳千條暗迴津。", "鳥驚直爲飛風葉，魚躍都由怯岸人。", "唯願聖主南山壽，何愁不賞萬年春。"]'),
('d2f1b1a1-703e-42fa-9754-35a1c8f2fb7b','舞馬千秋萬歲樂府詞三首 一','張說','唐','唐诗','tang','','[]','金天誕聖千秋節，玉醴還分萬壽觴。',64,'全唐诗/poet.tang.4000.json','["金天誕聖千秋節，玉醴還分萬壽觴。", "試聽紫騮歌樂府，何如騄驥舞華岡。", "連鶱勢出魚龍變，躞蹀驕生鳥獸行。", "歲歲相傳指樹日，翩翩來伴慶雲翔。"]'),
('546c301e-b8a4-4333-9b5e-20bc82180d86','舞馬千秋萬歲樂府詞三首 二','張說','唐','唐诗','tang','','[]','聖皇至德與天齊，天馬來儀自海西。',64,'全唐诗/poet.tang.4000.json','["聖皇至德與天齊，天馬來儀自海西。", "腕足徐行拜兩膝，繁驕不進踏千蹄。", "髬髵奮鬣時蹲踏，鼓怒驤身忽上躋。", "更有銜杯終宴曲，垂頭掉尾醉如泥。"]'),
('904f6a28-a66b-4a94-850a-1d9f03f65ab1','舞馬千秋萬歲樂府詞三首 三','張說','唐','唐诗','tang','','[]','遠聽明君愛逸才，玉鞭金翅引龍媒。',64,'全唐诗/poet.tang.4000.json','["遠聽明君愛逸才，玉鞭金翅引龍媒。", "不因茲白人間有，定是飛黃天上來。", "影弄日華相照耀，噴含雲色且裴徊。", "莫言闕下桃花舞，別有河中蘭葉開。"]'),
('796b97c1-a1bf-4fb7-bd0e-b48141358668','同趙侍御巴陵早春作','張說','唐','唐诗','tang','','[]','江上春來早可觀，巧將春物妬餘寒。',64,'全唐诗/poet.tang.4000.json','["江上春來早可觀，巧將春物妬餘寒。", "水苔共繞留烏石，花鳥爭開鬬鴨欄。", "佩勝芳辰日漸暖，然燈美夜月初圓。", "意隨北雁雲飛去，直待南州蕙草殘。"]'),
('cf457d67-27e9-41b1-9fb0-27cf241502c6','㴩湖山寺','張說','唐','唐诗','tang','','[]','空山寂歷道心生，虛谷迢遙野鳥聲。',64,'全唐诗/poet.tang.4000.json','["空山寂歷道心生，虛谷迢遙野鳥聲。", "禪室從來塵外賞，香臺豈是世中情。", "雲間東嶺千尋出，樹裏南湖一片明。", "若使巢由知此意，不將蘿薜易簪纓。"]'),
('406985ef-4d98-470b-8ff4-93a9335892ca','幽州新歲作','張說','唐','唐诗','tang','','[]','去歲荆南梅似雪，今年薊北雪如梅。',64,'全唐诗/poet.tang.4000.json','["去歲荆南梅似雪，今年薊北雪如梅。", "共知人事何常定，且喜年華去復來。", "邊鎮戍歌連夜動，京城燎火徹明開。", "遙遙西向長安日，願上南山壽一杯。"]'),
('24f05767-bc92-4dfb-8abb-59c60be53882','扈從幸韋嗣立山莊應制','張說','唐','唐诗','tang','','[]','寒灰飛玉琯，湯井駐金輿。',96,'全唐诗/poet.tang.4000.json','["寒灰飛玉琯，湯井駐金輿。", "既得方明相，還尋大隗居。", "懸泉珠貫下，列帳錦屏舒。", "騎遠林逾密，笳繁谷自虛。", "門旗塹複磴，殿幕裹通渠。", "舞鳳迎公主，雕龍賦婕妤。", "地幽天賞洽，酒樂御筵初。", "菲才叨侍從，連藻媿應徐。"]'),
('5550ac21-e186-4317-ae8f-7bd85c4a2ccc','奉和聖製喜雪應制','張說','唐','唐诗','tang','','[]','聖德與天同，封巒欲報功。',72,'全唐诗/poet.tang.4000.json','["聖德與天同，封巒欲報功。", "詔書期日下，靈感應時通。", "觸石雲呈瑞，含花雪告豐。", "積如沙照月，散似麵從風。", "舞集仙臺上，歌流帝樂中。", "遙知百神喜，灑路待行宮。"]'),
('3156c1e6-f199-45fb-b87b-37cfefaf84e1','奉和聖製寒食作應制','張說','唐','唐诗','tang','','[]','寒食春過半，花穠鳥復嬌。',72,'全唐诗/poet.tang.4000.json','["寒食春過半，花穠鳥復嬌。", "從來禁火日，會接清明朝。", "鬬敵雞殊勝，爭毬馬絕調。", "晴空數雲點，香樹百風搖。", "改木迎新燧，封田表舊燒。", "皇情愛嘉節，傳曲與簫韶。"]'),
('aa6f5d77-cfd5-420f-a6fa-1d0a5cc4fa1b','奉和聖製賜崔日知往潞州應制','張說','唐','唐诗','tang','','[]','聖情留曩鎮，佳氣翊興王。',72,'全唐诗/poet.tang.4000.json','["聖情留曩鎮，佳氣翊興王。", "增戟雄都府，高車轉太常。", "川橫八練闊，山帶五龍長。", "連帥初恩命，天人舊紀綱。", "餞塗飛御藻，闔境自生光。", "明主徵循吏，何年下鳳皇。"]'),
('0408bd50-a69b-4161-b507-70bc87699e38','春晚侍宴麗正殿探得開字','張說','唐','唐诗','tang','','[]','聖政惟稽古，賓門引上才。',72,'全唐诗/poet.tang.4000.json','["聖政惟稽古，賓門引上才。", "坊因購書立，殿爲集賢開。", "髦彥星辰下，仙章日月回。", "字如龍負出，韻是鳳銜來。", "庭柳餘春駐，宮鶯早夏催。", "喜承芸閣宴，幸奉柏梁杯。"]'),
('5441029e-e14b-4109-9ec1-8245c15d8b0f','奉和聖製花蕚樓下宴應制','張說','唐','唐诗','tang','','[]','萬心翹樂宴，三舍緩昌時。',72,'全唐诗/poet.tang.4000.json','["萬心翹樂宴，三舍緩昌時。", "山接夏雲險，臺留春日遲。", "節移芳未歇，興隔賞仍追。", "醉後傳嘉惠，樓前舞聖慈。", "皇恩與時合，天意若人期。", "故發前旬雨，新垂湛露詩。"]'),
('c4929ef3-9b06-4638-a965-b76109edd2f6','奉和聖製度蒲關應制','張說','唐','唐诗','tang','','[]','蒲坂橫臨晉，華芝曉望秦。',72,'全唐诗/poet.tang.4000.json','["蒲坂橫臨晉，華芝曉望秦。", "關城雄地險，橋路扼天津。", "樓映行宮日，隄含宮樹春。", "黃雲隨寶鼎，紫氣逐真人。", "東詠唐虞跡，西觀周漢塵。", "山河非國寶，明主愛忠臣。"]'),
('21cc6cd3-4c8a-4aa1-bd43-4e827ab52e42','奉和聖製途經華嶽應制','張說','唐','唐诗','tang','','["\u534e\u5c71"]','西嶽鎮皇京，中峰入太清。',74,'全唐诗/poet.tang.4000.json','["西嶽鎮皇京，中峰入太清。", "玉鑾重嶺應，緹[騎]薄雲迎。", "霽日懸高掌，寒空類削成。", "軒遊會神處，漢幸望仙情。", "舊廟青林古，新碑綠字生。", "羣臣願封岱，還駕勒鴻名。"]'),
('bac5c501-71e2-4249-90b3-3f1923527877','奉和聖製過王濬墓應制','張說','唐','唐诗','tang','','[]','牛斗三分國，龍驤一統年。',72,'全唐诗/poet.tang.4000.json','["牛斗三分國，龍驤一統年。", "智高寧受制，風急肯廻船。", "有策擒吳嚭，無言讓范宣。", "援孤因勢屈，功重爲讒偏。", "舊迹灰塵散，枯墳故老傳。", "百代逢明主，何辭死道邊。"]'),
('34afa291-66ce-4c8f-8ad6-94e64adb721c','奉和聖製經河上公廟應制','張說','唐','唐诗','tang','','[]','河上無名老，知非漢代人。',72,'全唐诗/poet.tang.4000.json','["河上無名老，知非漢代人。", "先探道德要，留待聖明辰。", "玄妙爲天下，清虛用谷神。", "化將和氣一，風與太初鄰。", "靈廟觀遺像，仙歌入至真。", "皇心齊萬物，何處不同塵。"]'),
('8a0fe809-af8c-48c6-b28d-fd5613e48125','奉和聖製幸鳳湯泉應制','張說','唐','唐诗','tang','','[]','周狩聞岐禮，秦都辨雍名。',72,'全唐诗/poet.tang.4000.json','["周狩聞岐禮，秦都辨雍名。", "獻禽天子孝，存老聖皇情。", "溫潤宜冬幸，遊畋樂歲成。", "湯雲出水殿，暖氣入山營。", "坎意無私潔，乾心稱物平。", "帝歌流樂府，溪谷也增榮。"]'),
('ab02dc3e-1178-4cc6-b8dd-025035177173','恩賜樂遊園宴','張說','唐','唐诗','tang','','[]','漢苑佳遊地，軒庭近侍臣。',72,'全唐诗/poet.tang.4000.json','["漢苑佳遊地，軒庭近侍臣。", "共持榮幸日，來賞豔陽春。", "饌玉頒王篚，摐金下帝鈞。", "池臺草色徧，宮觀柳條新。", "花綬光連榻，朱顏暢飲醇。", "聖朝多樂事，天意每隨人。"]'),
('ac0456de-cb76-4033-81a3-6a5df94c3dd2','三月二十日詔宴樂遊園賦得風字','張說','唐','唐诗','tang','','[]','樂遊形勝地，表裏望郊宮。',72,'全唐诗/poet.tang.4000.json','["樂遊形勝地，表裏望郊宮。", "北闕連天頂，南山對掌中。", "皇恩貸芳月，旬宴美成功。", "魚戲芙蓉水，鶯啼楊柳風。", "春光看欲暮，天澤戀無窮。", "長袖招斜日，留光待曲終。"]'),
('48b333cc-6dd5-4809-bd21-81ab59b81716','赴集賢院學士上賜宴應制得輝字','張說','唐','唐诗','tang','','[]','侍帝金華講，千齡道固稀。',72,'全唐诗/poet.tang.4000.json','["侍帝金華講，千齡道固稀。", "位將賢士設，書共學徒歸。", "首命深燕隗，通經淺漢韋。", "列筵榮賜食，送客愧儒衣。", "賀燕窺簷下，遷鶯入殿飛。", "欲知朝野慶，文教日光輝。"]'),
('66978161-9cb0-4c2b-8c0b-1f86394c4ce9','端午三殿侍宴應制探得魚字','張說','唐','唐诗','tang','','[]','小暑夏弦應，徽音商管初。',84,'全唐诗/poet.tang.4000.json','["小暑夏弦應，徽音商管初。", "願齎長命縷，來續大恩餘。", "三殿褰珠箔，羣官上玉除。", "助陽嘗麥彘，順節進龜魚。", "甘露垂天酒，芝花捧御書。", "合丹同蝘蜓，灰骨共蟾蜍。", "今日傷蛇意，銜珠遂闕如。"]'),
('6872be3d-cd6b-4609-b54a-e481006f6cf6','奉和聖製春中興慶宮酺宴應制','張說','唐','唐诗','tang','','[]','千齡逢啓聖，萬域共來威。',96,'全唐诗/poet.tang.4000.json','["千齡逢啓聖，萬域共來威。", "慶接郊禋後，酺承農事稀。", "御樓橫廣路，天樂下重闈。", "鸞鳳調歌曲，虹霓動舞衣。", "合聲雲上聚，連步月中歸。", "物覩恩無外，神和道入微。", "鎬京陪樂飲，柏殿奉文飛。", "徒竭秋雲影，何資春日暉。"]'),
('92eb245c-24b2-4d9b-ae54-3482880121f0','奉和聖製千秋節宴應制','張說','唐','唐诗','tang','','[]','五德生王者，千齡啓聖人。',96,'全唐诗/poet.tang.4000.json','["五德生王者，千齡啓聖人。", "赤光來照夜，黃雲上覆晨。", "海縣銜恩久，朝章獻舞新。", "高居帝座出，夾道衆官陳。", "槊杖洗清景，磬管凝秋旻。", "珠囊含瑞露，金鏡抱仙輪。", "何歲無鄉飲，何田不報神。", "薰歌與名節，傳代幸羣臣。"]'),
('d0eeec37-c3fc-4537-911b-3cf28df7ebaf','奉和聖製太行山中言志應制','張說','唐','唐诗','tang','','[]','六龍鳴玉鑾，九折步雲端。',96,'全唐诗/poet.tang.4000.json','["六龍鳴玉鑾，九折步雲端。", "河絡南浮近，山經北上難。", "羽儀映松雪，戈甲帶春寒。", "百谷晨笳動，千巖曉仗攢。", "皇心感韶節，敷藻念人安。", "既立省方館，復建禮神壇。", "扈蹕參天老，承榮忝夏官。", "長勤百年意，思見一勝殘。"]'),
('0a31d196-ce21-429e-8779-20a2b779cffe','奉和御製與宋璟源乾曜同日上官命宴東堂賜詩應制','張說','唐','唐诗','tang','','[]','大塊鎔羣品，經生偶聖時。',96,'全唐诗/poet.tang.4000.json','["大塊鎔羣品，經生偶聖時。", "猥承三事命，虛忝百僚師。", "右揆謀華碩，前星傅重資。", "連騫求舊禮，濫典樂賢詩。", "賜釜同榮拜，摐金宴宰司。", "菊花吹御酒，蘭葉捧天詞。", "寶歷休明盛，頹年晷漏衰。", "少留青史筆，未敢赤松期。"]'),
('9cb69c41-9772-4ca3-895d-1cba459143f4','奉和聖製暇日與兄弟同遊興慶宮作應制','張說','唐','唐诗','tang','','[]','漢武橫汾日，周王宴鎬年。',120,'全唐诗/poet.tang.4000.json','["漢武橫汾日，周王宴鎬年。", "何如造區夏，復此睦親賢。", "巢鳳新成閣，飛龍舊躍泉。", "棣華歌尚在，桐葉戲仍傳。", "禁籞氛埃隔，平臺景物連。", "聖慈良有裕，王道固無偏。", "問俗兆人阜，觀風五教宣。", "獻圖開益地，張樂奏鈞天。", "侍酒衢樽滿，詢芻諫鼓懸。", "永言形友愛，萬國共周旋。"]'),
('bc82492a-347d-4f10-a71e-a6352b980dd8','奉和聖製送王晙巡邊應制','張說','唐','唐诗','tang','','[]','六月歌周雅，三邊遣夏卿。',120,'全唐诗/poet.tang.4000.json','["六月歌周雅，三邊遣夏卿。", "欲施攻戰法，先作簡稽行。", "禮樂知謀帥，春秋識用兵。", "一勞堪定國，萬里即長城。", "策有和戎利，威傳破虜名。", "軍前雨灑道，樓上月臨營。", "別藻瑤華降，同衣錦襮榮。", "關山由義近，戎馬爲恩輕。", "絲竹路傍散，風雲馬上生。", "朝廷謂吉甫，邦國望君平。"]'),
('1cbf7e5a-61ed-4f6e-b9c0-7b58a2c066d1','將赴朔方軍應制','張說','唐','唐诗','tang','','[]','禮樂逢明主，韜鈐用老臣。',120,'全唐诗/poet.tang.4000.json','["禮樂逢明主，韜鈐用老臣。", "恭憑神武策，遠御鬼方人。", "供帳榮恩餞，山川喜詔巡。", "天文日月麗，朝賦管弦新。", "幼志傳三略，衰材謝六鈞。", "膽由忠作伴，心固道爲鄰。", "漢保河南地，胡清塞北塵。", "連年大軍後，不日小康辰。", "劒舞輕離別，歌酣忘苦辛。", "從來思博望，許國不謀身。"]'),
('2a2e5449-302c-4739-932b-407dc9f89bc5','奉和聖製爰因巡省途次舊居應制','張說','唐','唐诗','tang','','[]','葱鬱興王郡，殷憂啓聖圖。',144,'全唐诗/poet.tang.4000.json','["葱鬱興王郡，殷憂啓聖圖。", "周成會西土，漢武幸南都。", "歲卜鑾輿邁，農祠鴈政敷。", "武威稜外域，文教靡中區。", "警蹕干戈捧，朝宗萬玉趨。", "舊藩人事革，新化國容殊。", "壁有真龍畫，庭餘鳴鳳梧。", "叢觴祝堯壽，合鼎獻湯廚。", "陽樂寒初變，春恩蟄更蘇。", "三耆頒命服，五稔復田輸。", "君賦大風起，人歌湛露濡。", "從臣觀玉葉，方願紀靈符。"]'),
('873123a2-3936-4271-8564-43d88d124a5b','宿直溫泉宮羽林獻詩','張說','唐','唐诗','tang','','[]','冬狩美秦正，新豐樂漢行。',60,'全唐诗/poet.tang.4000.json','["冬狩美秦正，新豐樂漢行。", "星陳玄武閣，月對羽林營。", "寒木羅霜仗，空山響夜更。", "恩深靈液暖，節勁古松貞。", "文武皆王事，輸心不爲名。"]'),
('aec65055-96a1-418f-a7e6-ad6fcfc0630a','玄武門侍射','張說','唐','唐诗','tang','','[]','射觀通玄闕，兵欄闢御筵。',72,'全唐诗/poet.tang.4000.json','["射觀通玄闕，兵欄闢御筵。", "雕弧月半上，畫的暈重圓。", "羿后神幽贊，靈王法暗傳。", "貫心精四返，飲羽妙三聯。", "雪鶴來銜箭，星麟下集弦。", "一逢軍宴洽，萬慶武功宣。"]'),
('595957c3-e3a1-475c-a24e-6bdfee3569de','扈從南出雀鼠谷','張說','唐','唐诗','tang','','[]','豫動三靈贊，時巡四海威。',72,'全唐诗/poet.tang.4000.json','["豫動三靈贊，時巡四海威。", "陝關凌曙出，平路半春歸。", "霍鎮迎雲罕，汾河送羽旂。", "山南柳半密，谷北草全稀。", "遲日宜華蓋，和風入袷衣。", "上林千里近，應見百花飛。"]'),
('83ecf712-eb17-4d6c-9240-b7f4856e725e','洛橋北亭詔餞諸刺史','張說','唐','唐诗','tang','','[]','離亭拂御溝，別曲舞船樓。',72,'全唐诗/poet.tang.4000.json','["離亭拂御溝，別曲舞船樓。", "詔餞朝廷牧，符分海縣憂。", "股肱還入郡，父母更臨州。", "扇逐仁風傳，車隨霖雨流。", "恩光水上溢，榮色柳間浮。", "預待羣方最，三公不遠求。"]'),
('6aa8dde6-7163-4287-b30e-2bacd113924d','東都酺宴','張說','唐','唐诗','tang','','[]','堯舜傳天下，同心致太平。',120,'全唐诗/poet.tang.4000.json','["堯舜傳天下，同心致太平。", "吾君內舉聖，遠合至公情。", "錫命承丕業，崇親享大名。", "二天資廣運，兩曜益齊明。", "道暢昆蟲樂，恩深朽蠹榮。", "皇輿久西幸，留鎮在東京。", "合宴千官入，分曹百戲呈。", "樂來嫌景遽，酒著訝寒輕。", "喜氣連雲閣，歡呼動洛城。", "人間知幾代，今日見河清。"]'),
('1cae151d-99d7-4a50-a9f2-0d142c7f5a61','奉酬韋祭酒嗣立偶遊龍門北溪忽懷驪山別業呈諸留守之作','張說','唐','唐诗','tang','','[]','石澗泉虛落，松崖路曲迴。',120,'全唐诗/poet.tang.4000.json','["石澗泉虛落，松崖路曲迴。", "聞君北溪下，想像南山隈。", "近念鼎湖別，遙思雲嶂陪。", "不同奇覯往，空覩斯文來。", "歲後寒初變，春前芳未開。", "黃蕤嫋岸柳，紫蕚折村梅。", "盡室茲遊玩，盈門幾樂哉。", "嗟留洛陽陌，夢詣建章臺。", "野失巢由性，朝非元凱才。", "布懷欽遠迹，幽意日塵埃。"]'),
('ec7fe3b3-c036-4fa2-82e4-e5a015475df3','奉酬韋祭酒自湯還都經龍門北溪莊見貽之作','張說','唐','唐诗','tang','','[]','聞君湯井至，瀟灑憇郊林。',120,'全唐诗/poet.tang.4000.json','["聞君湯井至，瀟灑憇郊林。", "拂曙攜清賞，披雲覯綠岑。", "歡言遊覽意，款曲望歸心。", "是日期佳客，同山忽異尋。", "桃花迂路轉，楊柳間門深。", "泛舟伊水漲，繫馬香樹陰。", "繁弦弄水族，嬌吹狎沙禽。", "春滿汀色媚，景斜嵐氣侵。", "懷仁殊未遠，重德匪專臨。", "來藻敷幽思，連詞報所欽。"]'),
('cc52f325-9edf-4fe3-ad7a-6261535df837','酬崔光祿冬日述懷贈答','張說','唐','唐诗','tang','','[]','徐陳嘗並作，枚馬亦同時。',264,'全唐诗/poet.tang.4000.json','["徐陳嘗並作，枚馬亦同時。", "各負當朝譽，俱承明主私。", "夫君邁前侶，觀國騁奇姿。", "山似鳴威鳳，泉如出寶龜。", "才雄子雲筆，學廣仲舒帷。", "紫綬拂三寺，朱門臨九逵。", "昔我含香日，聯爾縉雲司。", "朝攜蘭省步，夕退竹林期。", "中路一分手，數載來何遲。", "求友還相得，羣英復在茲。", "留臺少人務，方駕遞尋追。", "涉玩懷同賞，霑芳憶共持。", "迎賓南澗飲，載妓東城嬉。", "春郊綠畝秀，秋澗白雲滋。", "名畫披人物，良書討滯疑。", "興來光不惜，歡往迹如遺。", "歲晏罷行樂，層城間所思。", "夜魂燈處厭，朝髪鏡前衰。", "忽枉崔駰什，兼流韋孟詞。", "曲高彌寡和，主善代爲師。", "齊戒觀華玉，留連歎色絲。", "終慙起予者，何足與言詩。"]'),
('da06a8dc-4ab5-452f-8722-b3598aa961eb','同劉給事城南宴集','張說','唐','唐诗','tang','','[]','水竹幽閑地，簪纓近侍臣。',72,'全唐诗/poet.tang.4000.json','["水竹幽閑地，簪纓近侍臣。", "雍容乘暇日，瀟灑出囂塵。", "樹對思朋鳥，池深入養鱗。", "管弦高逐吹，歌舞妙含春。", "老子叨專席，歡邀隔縉紳。", "此中情不淺，遙寄賞心人。"]'),
('a5383bba-c471-4356-855c-86d8e484de01','溫泉馮劉二監客舍觀妓','張說','唐','唐诗','tang','','[]','溫谷寒林薄，羣遊樂事多。',72,'全唐诗/poet.tang.4000.json','["溫谷寒林薄，羣遊樂事多。", "佳人蹀駿馬，乘月夜相過。", "秀色然紅黛，嬌香發綺羅。", "鏡前鸞對舞，琴裏鳳傳歌。", "妬寵傾新意，銜恩奈老何。", "爲君留上客，歡笑斂雙蛾。"]'),
('1a591aab-55b1-42d4-b988-5d97e6765026','寄許八','張說','唐','唐诗','tang','','[]','萬類春皆樂，徂顏獨不怡。',72,'全唐诗/poet.tang.4000.json','["萬類春皆樂，徂顏獨不怡。", "年來人更老，花發意先衰。", "乳鵲穿壇畫，巢蜂觸網絲。", "平生美容色，宿昔影中疑。", "遠道何由夢，同心在者誰。", "西風欲誰語，憫默遂無詞。"]'),
('e335dccd-55a2-4885-8c2a-baf7553ce7aa','送蘇合宮頲','張說','唐','唐诗','tang','','[]','都邑羣方首，商泉舊俗訛。',72,'全唐诗/poet.tang.4000.json','["都邑羣方首，商泉舊俗訛。", "變風須愷悌，成化佇弦歌。", "疇昔珪璋友，雍容文雅多。", "振纓遊省闥，鏘玉宰京河。", "別曲鸞初下，行軒雉尚過。", "百壺非餞意，流詠在人和。"]'),
('67c119ce-2f92-439d-b771-c0d91f2224f0','送喬安邑備','張說','唐','唐诗','tang','','[]','書閣移年歲，文明難復辭。',72,'全唐诗/poet.tang.4000.json','["書閣移年歲，文明難復辭。", "歡言冬雪滿，恨別夏雲滋。", "外尹方爲政，高明自不欺。", "老人驂馭往，童子狎雛嬉。", "日茂西河俗，寂寥東觀期。", "遙懷秀才令，京洛見新詩。"]'),
('2a0f3ede-d7f5-4f17-8a82-5cdb15699ada','送趙二尚書彥昭北伐','張說','唐','唐诗','tang','','[]','虜地河冰合，邊城備此時。',72,'全唐诗/poet.tang.4000.json','["虜地河冰合，邊城備此時。", "兵連紫塞路，將舉白雲司。", "提劒榮中貴，銜珠盛出師。", "日華光組練，風色焰旌旗。", "投筆尊前起，橫戈馬上辭。", "梅花吹別引，楊柳賦歸詩。"]'),
('3634f7ff-333d-49cf-a3d8-509be0fc8ea0','石門別楊六欽望','張說','唐','唐诗','tang','','[]','燕人同竄越，萬里自相哀。',60,'全唐诗/poet.tang.4000.json','["燕人同竄越，萬里自相哀。", "影響無期會，江山此地來。", "暮年傷泛梗，累日慰寒灰。", "潮水東南落，浮雲西北回。", "俱看石門遠，倚棹兩悲哉。"]'),
('2b4d3049-52ed-4354-a03d-8e01c9a2ca54','南中送北使二首 一','張說','唐','唐诗','tang','','[]','傳聞合浦葉，曾向洛陽飛。',60,'全唐诗/poet.tang.4000.json','["傳聞合浦葉，曾向洛陽飛。", "何日南風至，還隨北使歸。", "紅顏渡嶺歇，白首對秋衰。", "高歌何由見，層堂不可違。", "誰憐炎海曲，淚盡血沾衣。"]'),
('798dd3aa-d668-407d-af17-9bc0c998ec6a','南中送北使二首 二','張說','唐','唐诗','tang','','[]','待罪居重譯，窮愁暮雨秋。',132,'全唐诗/poet.tang.4000.json','["待罪居重譯，窮愁暮雨秋。", "山臨鬼門路，城繞瘴江流。", "人事今如此，生涯尚可求。", "逢君入鄉縣，傳我念京周。", "別恨歸途遠，離言暮景遒。", "夷歌翻下淚，蘆酒未消愁。", "聞有胡兵急，深懷漢國羞。", "和親先是詐，款塞果爲讐。", "釋繫應分爵，蠲徒幾復侯。", "廉頗誠未老，孫叔宜無謀。", "若道馮唐事，皇恩尚可收。"]'),
('863e2d68-af9b-41ce-a110-ba80ee8a2bc0','送趙順直郎中赴安西副大都督','張說','唐','唐诗','tang','','[]','絕鎮功難立，懸軍命匪輕。',96,'全唐诗/poet.tang.4000.json','["絕鎮功難立，懸軍命匪輕。", "復承遷相後，彌重任賢情。", "將起神仙地，才稱禮樂英。", "長心堪繫虜，短語足論兵。", "日授休門法，星教置陣名。", "龍泉恩已著，燕頷相終成。", "月窟窮天遠，河源入塞清。", "老天操別翰，承旨頌升平。"]'),
('a5b2259e-8988-4ec4-8bd1-31e12a2a6c2d','送宋休遠之蜀任','張說','唐','唐诗','tang','','[]','求友殊損益，行道異窮申。',96,'全唐诗/poet.tang.4000.json','["求友殊損益，行道異窮申。", "綴我平生氣，吐贈薄遊人。", "結恩事明主，忍愛遠辭親。", "色麗成都俗，膏腴蜀水濱。", "如何從宦子，堅白共緇磷。", "日月千齡旦，河山萬族春。", "懷鉛書瑞府，橫草事邊塵。", "不及安人吏，能令王化淳。"]'),
('7093fd5c-e451-48e4-b4ff-f462c22a8f17','岳州別梁六入朝','張說','唐','唐诗','tang','','[]','遠蒞長沙渚，欣逢賈誼才。',108,'全唐诗/poet.tang.4000.json','["遠蒞長沙渚，欣逢賈誼才。", "江山疲應接，風日復晴開。", "江樹雲間斷，湘山水上來。", "近洲朝鷺集，古戍夜猿哀。", "岸杼含蒼捄，河蒲秀紫臺。", "月餘偏地賞，心盡故人杯。", "自我違京洛，嗟君此泝洄。", "容華因別老，交舊與年頹。", "夢見長安陌，朝宗實盛哉。"]'),
('dc9f8eae-15d1-4281-9c51-9f5b69f576e4','相州冬日早衙','張說','唐','唐诗','tang','','[]','城外宵鐘斂，閨中曙火殘。',72,'全唐诗/poet.tang.4000.json','["城外宵鐘斂，閨中曙火殘。", "朝光曜庭雪，宿凍聚池寒。", "正色臨廳事，疑詞定筆端。", "除苛囹圄息，伐枳吏人寬。", "河內功猶淺，淮陽疾未安。", "鏡中星髪變，頓使世情闌。"]'),
('4bc82e62-b5ca-4442-b12f-559b3425b1d4','岳州西城','張說','唐','唐诗','tang','','[]','水國何遼曠，風波遂極天。',96,'全唐诗/poet.tang.4000.json','["水國何遼曠，風波遂極天。", "西江三紀合，南浦二湖連。", "危堞臨清境，煩憂暫豁然。", "九圍觀掌內，萬象閱眸前。", "日去長沙渚，山橫雲夢田。", "汀葭變秋色，津樹入寒煙。", "潛穴探靈詭，浮生揖聖仙。", "至今人不見，跡滅事空傳。"]'),
('141c2c9c-d642-4188-b7fc-0939eceed0e8','岳州觀競渡','張說','唐','唐诗','tang','','[]','畫作飛鳧艇，雙雙競拂流。',72,'全唐诗/poet.tang.4000.json','["畫作飛鳧艇，雙雙競拂流。", "低裝山色變，急棹水華浮。", "土尚三閭俗，江傳二女遊。", "齊歌迎孟姥，獨舞送陽侯。", "鼓發南湖溠，標爭西驛樓。", "並驅常詫速，非畏日光遒。"]'),
('192c44aa-ba73-4533-8289-991da168a7ba','對酒行巴陵作','張說','唐','唐诗','tang','','[]','留侯封萬戶，園令壽千金。',72,'全唐诗/poet.tang.4000.json','["留侯封萬戶，園令壽千金。", "本爲成王業，初由賦上林。", "繁榮安足恃，霜露遞相尋。", "鳥哭楚山外，猿啼湘水陰。", "夢中城闕近，天畔海雲深。", "空對忘憂酌，離憂不去心。"]'),
('ca7a85bf-1dd4-47a5-87b6-010e77b5b017','岳州宴姚紹之','張說','唐','唐诗','tang','','[]','杞梓滯江濱，光華向日新。',72,'全唐诗/poet.tang.4000.json','["杞梓滯江濱，光華向日新。", "難兄金作友，媚子玉爲人。", "山水含秋興，池亭借善鄰。", "簷松風送靜，院竹鳥來馴。", "翠斝吹黃菊，琱盤鱠紫鱗。", "緩歌將醉舞，爲拂繡衣塵。"]'),
('d1b80b56-eedc-418a-aeb2-30ed70563622','岳州九日宴道觀西閣','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','搖落長年歎，蹉跎遠宦心。',120,'全唐诗/poet.tang.4000.json','["搖落長年歎，蹉跎遠宦心。", "北風嘶代馬，南浦宿陽禽。", "佳此黃花酌，酣餘白首吟。", "涼雲霾楚望，濛雨蔽荆岑。", "登眺思清景，誰將眷濁陰。", "釣歌出江霧，樵唱入山林。", "魚以嘉名采，木爲美材侵。", "大道由中悟，逍遙匪外尋。", "參佐多君子，詞華妙賞音。", "留題洞庭觀，望古意何深。"]'),
('f1f01288-1b08-48a8-8a82-2ef23fac71b7','岳州作','張說','唐','唐诗','tang','','[]','水國生秋草，離居再及瓜。',72,'全唐诗/poet.tang.4000.json','["水國生秋草，離居再及瓜。", "山川臨洞穴，風日望長沙。", "物土南州異，關河北信賒。", "日昏聞怪鳥，地熱見修虵。", "遠人夢歸路，瘦馬嘶去家。", "正有江潭月，徘徊戀九華。"]'),
('362ff17d-e5ce-45cb-b273-c23651772264','遊洞庭湖','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','平湖曉望分，仙嶠氣氛氳。',84,'全唐诗/poet.tang.4000.json','["平湖曉望分，仙嶠氣氛氳。", "鼓枻乘清渚，尋峰弄白雲。", "江寒天一色，日靜水重紋。", "樹坐參猿嘯，沙行入鷺羣。", "緣源斑篠密，罥徑綠蘿紛。", "洞穴傳虛應，楓林覺自熏。", "雙童有靈藥，願取獻明君。"]'),
('0133ca9a-89ec-4317-87c0-4f9ab2af8ee4','巴丘春作','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','日出洞庭水，春山挂斷霞。',72,'全唐诗/poet.tang.4000.json','["日出洞庭水，春山挂斷霞。", "江涔相映發，卉木共紛華。", "湘戍南浮闊，荆關北望賒。", "湖陰窺魍魎，丘勢辨巴蛇。", "島戶巢爲館，漁人艇作家。", "自憐心問景，三歲客長沙。"]'),
('80dc2409-d246-45b6-a2ed-85e575ab7bdf','岳州夜坐','張說','唐','唐诗','tang','','[]','炎洲苦三伏，永日臥孤城。',72,'全唐诗/poet.tang.4000.json','["炎洲苦三伏，永日臥孤城。", "賴此閑庭夜，蕭條夜月明。", "獨歌還太息，幽感見餘聲。", "江近鶴時呌，山深猿屢鳴。", "息心觀有欲，棄知返無名。", "五十知天命，吾其達此生。"]'),
('fb99e167-6931-4251-9270-0b0bf5616302','別㴩湖','張說','唐','唐诗','tang','','[]','念別㴩湖去，浮舟更一臨。',72,'全唐诗/poet.tang.4000.json','["念別㴩湖去，浮舟更一臨。", "千峰出浪險，萬木抱煙深。", "南郡延恩渥，東山戀宿心。", "露花香欲醉，時鳥囀餘音。", "涉趣皆留賞，無奇不徧尋。", "莫言山水間，幽意在鳴琴。"]'),
('a1f2c713-612e-4d82-8dd7-8c8d2804ea5a','伯奴邊見歸田賦因投趙侍御','張說','唐','唐诗','tang','','[]','爾家歎窮鳥，吾族賦歸田。',84,'全唐诗/poet.tang.4000.json','["爾家歎窮鳥，吾族賦歸田。", "莫道榮枯異，同嗟世網牽。", "黃陵浮汨渚，青草會湘川。", "去國逾三歲，茲山老二年。", "寒鴞鳴舍下，昏虎臥籬前。", "客淚堪斑竹，離亭欲贈荃。", "放言久無次，觸興感成篇。"]'),
('642951c0-7c42-4816-b704-bed74f385bd9','清遠江峽山寺','張說','唐','唐诗','tang','','[]','流落經荒外，逍遙此梵宮。',84,'全唐诗/poet.tang.4000.json','["流落經荒外，逍遙此梵宮。", "雲峰吐月白，石壁淡烟紅。", "寶塔靈仙湧，懸龕造化功。", "天香涵竹氣，虛唄引松風。", "簷牖飛花入，廊房激水通。", "猿鳴知谷靜，魚戲辨江空。", "靜默將何貴，惟應心境同。"]'),
('9786bece-644a-42cc-9835-826a4ba3af3c','春雨早雷','張說','唐','唐诗','tang','','[]','東北春風至，飄飄帶雨來。',72,'全唐诗/poet.tang.4000.json','["東北春風至，飄飄帶雨來。", "拂黃先變柳，點素早驚梅。", "樹藹懸書閣，煙含作賦臺。", "河魚未上凍，江蟄已聞雷。", "美人宵夢著，金屏曙不開。", "無緣一啓齒，空酌萬年杯。"]'),
('ac03285d-80c4-472f-8d6e-959166125761','聞雨','張說','唐','唐诗','tang','','[]','窮冬萬花匝，永夜百憂攢。',60,'全唐诗/poet.tang.4000.json','["窮冬萬花匝，永夜百憂攢。", "危戍臨江火，空齋入雨寒。", "斷猿知屢別，嘶鴈覺虛彈。", "心對爐灰死，顏隨庭樹殘。", "舊恩懷未報，傾膽鏡中看。"]'),
('120201c1-1410-4a74-9e69-72d689f979de','赦歸在道中作','張說','唐','唐诗','tang','','[]','陳焦心息盡，死意不期生。',60,'全唐诗/poet.tang.4000.json','["陳焦心息盡，死意不期生。", "何幸光華旦，流人歸上京。", "愁將網共解，服與代俱明。", "復是三階正，還逢四海平。", "誰能定禮樂，爲國著功成。"]'),
('4ca392e5-dfb8-4386-921c-0b6dc6abf9a0','喜度嶺','張說','唐','唐诗','tang','','[]','東漢興唐曆，南河復禹謀。',144,'全唐诗/poet.tang.4000.json','["東漢興唐曆，南河復禹謀。", "寧知瘴癘地，生入帝皇州。", "雷雨蘇蟲蟄，春陽放鷽鳩。", "洄沿炎海畔，登降閩山陬。", "嶺路分中夏，川源得上流。", "見花便獨笑，看草即忘憂。", "自始居重譯，天星已再周。", "鄉關絕歸望，親戚不相求。", "棄杖枯還植，窮鱗涸更浮。", "道消黃鶴去，運啓白駒留。", "江妾晨炊黍，津童夜櫂舟。", "盛明良可遇，莫後洛城遊。"]'),
('079ce365-2d9b-4ca8-a8d0-6610c9552857','奉和聖製潼關口號應制','張說','唐','唐诗','tang','','[]','天德平無外，關門東復西。',24,'全唐诗/poet.tang.4000.json','["天德平無外，關門東復西。", "不將千里隔，何用一丸泥。"]'),
('6748a93d-2047-4c93-a2bf-b0a63186ceb8','奉蕭令嵩酒幷詩','張說','唐','唐诗','tang','','[]','樂奏天恩滿，杯來秋興高。',24,'全唐诗/poet.tang.4000.json','["樂奏天恩滿，杯來秋興高。", "更蒙蕭相國，對席飲醇醪。"]'),
('ac670df7-5a42-46d9-b756-a99da3f90ff1','奉宇文黃門融酒','張說','唐','唐诗','tang','','[]','聖德垂甘露，天章下大風。',24,'全唐诗/poet.tang.4000.json','["聖德垂甘露，天章下大風。", "又乘黃閣賞，願作黑頭公。"]'),
('ad46b11e-f3a1-4a89-942b-3e9e8f96c0bc','奉裴中書光庭酒','張說','唐','唐诗','tang','','[]','西掖恩華降，南宮命席闌。',24,'全唐诗/poet.tang.4000.json','["西掖恩華降，南宮命席闌。", "詎知雞樹後，更接鳳池歡。"]'),
('038112c9-7c9c-4cf5-9511-85b6032a011f','清夜酌','張說','唐','唐诗','tang','','[]','秋陰士多感，雨息夜無塵。',24,'全唐诗/poet.tang.4000.json','["秋陰士多感，雨息夜無塵。", "清樽宜明月，復有平生人。"]'),
('491c51fa-7f8f-4a59-b9c2-aedaf2b3add9','醉中作','張說','唐','唐诗','tang','','[]','醉後樂無極，彌勝未醉時。',24,'全唐诗/poet.tang.4000.json','["醉後樂無極，彌勝未醉時。", "動容皆是舞，出語總成詩。"]'),
('298eebb4-4352-4e21-9c0e-257c570c1e43','送梁知微渡海東','張說','唐','唐诗','tang','','[]','今日此相送，明年此相待。',24,'全唐诗/poet.tang.4000.json','["今日此相送，明年此相待。", "天上客星回，知君渡東海。"]'),
('d506b4fe-8601-4518-a5c9-2f5fede55b71','寄劉道士舃','張說','唐','唐诗','tang','','[]','真人降紫氣，邀我丹田宮。',24,'全唐诗/poet.tang.4000.json','["真人降紫氣，邀我丹田宮。", "遠寄雙飛舄，飛飛不礙空。"]'),
('94c1c696-51ac-40ad-acd2-ffb47f654b8d','書香能和尚塔','張說','唐','唐诗','tang','','[]','大師捐世去，空餘法力在。',24,'全唐诗/poet.tang.4000.json','["大師捐世去，空餘法力在。", "遠寄無礙香，心隨到南海。"]'),
('5227d95f-56ff-4728-82a5-aeacff85383a','被使在蜀','張說','唐','唐诗','tang','','[]','即今三伏盡，尚自在臨邛。',24,'全唐诗/poet.tang.4000.json','["即今三伏盡，尚自在臨邛。", "歸途千里外，秋月定相逢。"]'),
('558ffb46-5d66-4900-a1a9-08faaa1114de','正朝摘梅','張說','唐','唐诗','tang','','[]','蜀地寒猶暖，正朝發早梅。',24,'全唐诗/poet.tang.4000.json','["蜀地寒猶暖，正朝發早梅。", "偏驚萬里客，已復一年來。"]'),
('5c206849-80c6-4994-a9bb-8dde5aa5cd18','蜀道後期','張說','唐','唐诗','tang','','["\u6292\u60c5", "\u79cb\u98ce"]','客心爭日月，來往預期程。',24,'全唐诗/poet.tang.4000.json','["客心爭日月，來往預期程。", "秋風不相待，先至洛陽城。"]'),
('7448d60f-4828-410b-be11-d9b5c5f0163a','廣州江中作','張說','唐','唐诗','tang','','[]','去國年方晏，愁心轉不堪。',24,'全唐诗/poet.tang.4000.json','["去國年方晏，愁心轉不堪。", "離人與江水，終日向西南。"]'),
('f3c77faa-1a12-435b-9e98-6d864de22597','江中誦經','張說','唐','唐诗','tang','','[]','實相歸懸解，虛心暗在通。',24,'全唐诗/poet.tang.4000.json','["實相歸懸解，虛心暗在通。", "澄江明月內，應是色成空。"]'),
