('c35271cf-b6d2-4618-85fb-085966fdab8d','襄陽路逢寒食','張說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','去年寒食洞庭波，今年寒食襄陽路。',32,'全唐诗/poet.tang.4000.json','["去年寒食洞庭波，今年寒食襄陽路。", "不辭著處尋山水，秪畏還家落春暮。"]'),
('0f6dc36a-219d-4c16-909c-e27d6af78407','詠方圓動靜示李泌','張說','唐','唐诗','tang','','[]','方如棋局，圓如棋子。',20,'全唐诗/poet.tang.4000.json','["方如棋局，圓如棋子。", "動如棋生，靜如棋死。"]'),
('d05891a1-7d4b-4589-997f-54624d59456d','和尹懋登南樓','張均','唐','唐诗','tang','','[]','客來已兩春，更瞻韶光早。',48,'全唐诗/poet.tang.4000.json','["客來已兩春，更瞻韶光早。", "花鳥既環合，江山復駢抱。", "樓形寫北潭，堞勢凌青島。", "白雲謝歸鴈，馳懷洛陽道。"]'),
('183a10e7-fb03-47fc-9c8b-6353795dbdd1','江上逢春','張均','唐','唐诗','tang','','[]','離憂耿未和，春慮忽蹉跎。',48,'全唐诗/poet.tang.4000.json','["離憂耿未和，春慮忽蹉跎。", "擇木猿知去，尋泥燕獨過。", "驚花飜霽日，垂柳拂煙波。", "激意屢怡賞，無如鄉念何。"]'),
('e27eea95-87c4-4875-bc83-ab64f9766158','九日巴丘登高','張均','唐','唐诗','tang','','[]','客心驚暮序，賓鴈下滄洲。',48,'全唐诗/poet.tang.4000.json','["客心驚暮序，賓鴈下滄洲。", "共賞重陽節，言尋戲馬遊。", "湖風扶戍柳，江雨暗山樓。", "且酌東籬酒，聊祛南國憂。"]'),
('68353013-d25d-4a71-afd9-d0e5d88e5e1c','和尹懋秋夜遊㴩湖二首 一','張均','唐','唐诗','tang','','[]','遠水沈西日，寒沙聚夜鷗。',48,'全唐诗/poet.tang.4000.json','["遠水沈西日，寒沙聚夜鷗。", "平湖乘月滿，飛棹接星流。", "黃葉鳴淒吹，蒼葭掃暗洲。", "願移滄浦賞，歸待潁川遊。"]'),
('3d7f64dc-3b06-46d2-8616-18435b5e44c9','和尹懋秋夜遊㴩湖二首 二','張均','唐','唐诗','tang','','[]','灣潭幽意深，杳靄涌寒岑。',48,'全唐诗/poet.tang.4000.json','["灣潭幽意深，杳靄涌寒岑。", "石痕秋水落，嵐氣夕陽沈。", "澄徹天爲底，淵玄月作心。", "青溪非大隱，歸弄白雲潯。"]'),
('491c8a76-3c01-4b0b-9184-a2b95f1fb7de','岳陽晚景','張均','唐','唐诗','tang','','[]','晚景寒鵶集，秋風旅鴈歸。',48,'全唐诗/poet.tang.4000.json','["晚景寒鵶集，秋風旅鴈歸。", "水光浮日出，霞彩暎江飛。", "洲白蘆花吐，園紅柿葉稀。", "長沙卑溼地，九月未成衣。"]'),
('d04f138b-14ce-4b40-9d78-ef385648a345','流合浦嶺外作','張均','唐','唐诗','tang','','[]','瘴江西去火爲山，炎徼南窮鬼作關。',32,'全唐诗/poet.tang.4000.json','["瘴江西去火爲山，炎徼南窮鬼作關。", "從此更投人境外，生涯應在有無間。"]'),
('491b140f-eff7-4107-892e-b8f40570cecd','奉和岳州山城','張垍','唐','唐诗','tang','','[]','郡館臨清賞，開扃坐白雲。',48,'全唐诗/poet.tang.4000.json','["郡館臨清賞，開扃坐白雲。", "訟虛棠戶曙，觀靜竹簷曛。", "懸榻迎賓下，趨庭學禮聞。", "風傳琴上意，遙向日華紛。"]'),
('35d4384e-fcc6-4588-b532-52566c856488','偶遊龍門北溪忽懷驪山別業因以言志示弟淑奉呈諸大僚','韋嗣立','唐','唐诗','tang','','[]','幽谷杜陵邊，風煙別幾年。',120,'全唐诗/poet.tang.4000.json','["幽谷杜陵邊，風煙別幾年。", "偶來伊水曲，溪嶂覺依然。", "傍浦憐芳樹，尋崖愛綠泉。", "嶺雲隨馬足，山鳥向人前。", "地合心俱靜，言因理自玄。", "短才叨重寄，尸祿愧妨賢。", "每挹挂冠侶，思從初服旋。", "稻粱仍欲報，歲月坐空捐。", "助岳無纖塊，輸溟謝末涓。", "還悟北轅失，方求南澗田。"]'),
('76d4eee0-1214-4964-a126-490d1fb54268','奉和九日幸臨渭亭登高應制得深字','韋嗣立','唐','唐诗','tang','','[]','層觀遠沈沈，鸞旗九日臨。',48,'全唐诗/poet.tang.4000.json','["層觀遠沈沈，鸞旗九日臨。", "帷宮壓水岸，步輦入煙岑。", "枝上萸新採，樽中菊始斟。", "願陪歡樂事，長與歲時深。"]'),
('667e8b3a-fdbc-45c6-ab3e-04dd6f31bfe4','奉和張岳州王潭州別詩二首 一','韋嗣立','唐','唐诗','tang','','[]','茂先王佐才，作牧楚江隈。',48,'全唐诗/poet.tang.4000.json','["茂先王佐才，作牧楚江隈。", "登樓正欲賦，復遇仲宣來。", "黃鵠飛將遠，雕龍文爲開。", "寧知昔聯事，聽曲有餘哀。"]'),
('dcd40c3f-9460-4f6a-99bb-45809579fb32','奉和張岳州王潭州別詩二首 二','韋嗣立','唐','唐诗','tang','','[]','昔時陪二賢，纓冕會神仙。',48,'全唐诗/poet.tang.4000.json','["昔時陪二賢，纓冕會神仙。", "一去馳江海，相逢共播遷。", "無因千里駕，忽覩四愁篇。", "覽諷歡何已，歡終徒愴然。"]'),
('ef539abc-b6bf-49fc-a49a-be7df5eb902e','奉和初春幸太平公主南莊應制','韋嗣立','唐','唐诗','tang','','[]','主第巖扃架鵲橋，天門閶闔降鸞鑣。',64,'全唐诗/poet.tang.4000.json','["主第巖扃架鵲橋，天門閶闔降鸞鑣。", "歷亂旌旗轉雲樹，參差臺榭入煙霄。", "林間花雜平陽舞，谷裏鶯和弄玉簫。", "已陪沁水追歡日，行奉茅山訪道朝。"]'),
('8461b4b5-f9b8-416f-b654-04824aa9a0e4','自湯還都經龍門北溪贈張左丞崔禮部崔光祿','韋嗣立','唐','唐诗','tang','','[]','栖閑有愚谷，好事枉朝軒。',120,'全唐诗/poet.tang.4000.json','["栖閑有愚谷，好事枉朝軒。", "樹接前驅擁，巖傳後騎喧。", "褰簾出野院，植杖候柴門。", "既拂林下席，仍攜池上樽。", "深期契幽賞，實謂展歡言。", "末眷誠未易，佳遊時更敦。", "俄看嘯儔侶，各已共飛鶱。", "延睇盡朝日，長懷通夜魂。", "空聞岸竹動，徒見浦花繁。", "多愧春鶯曲，相求意獨存。"]'),
('f5ccb8b1-eba5-4084-ae01-bf5aa91a077e','酬崔光祿冬日述懷贈答','韋嗣立','唐','唐诗','tang','','[]','亭伯負高名，羽儀稱上京。',264,'全唐诗/poet.tang.4000.json','["亭伯負高名，羽儀稱上京。", "魏珠能燭乘，秦璧許連城。", "六月飛將遠，三冬學已精。", "洛陽推賈誼，江夏貴黃瓊。", "推演中都術，旋參河尹聲。", "累遷登御府，移拜踐名卿。", "庭聚歌鍾麗，門羅棨戟榮。", "鸚杯飛廣席，獸火列前楹。", "散誕林園意，殷勤敬愛情。", "無容抱衰疾，良宴每招迎。", "契得心逾重，言忘道益真。", "相勗忠義節，共談詞賦英。", "雕蟲曾靡棄，白鳳已先鳴。", "光接神愈駭，音來味不成。", "短歌甘自思，鴻藻彌難清。", "東里方希潤，西河敢竊明。", "厚誣空見迫，喪德豈無誠。", "端守宮闈地，寒煙朝暮平。", "顧才無術淺，懷器識憂盈。", "月下對雲闕，風前聞夜更。", "昌年雖共偶，歡會此難幷。", "爲憐漳浦曲，沈痼有劉楨。"]'),
('d677ca21-32b3-44c8-8c78-bafc28276100','上巳日祓禊渭濱應制','韋嗣立','唐','唐诗','tang','','[]','乘春祓禊逐風光，扈蹕陪鑾渭渚傍。',32,'全唐诗/poet.tang.4000.json','["乘春祓禊逐風光，扈蹕陪鑾渭渚傍。", "還笑當時水濱老，衰年八十待文王。"]'),
('cec3eb9f-1bb9-4494-b72e-998ee1bf70bf','奉酬韋祭酒偶遊龍門北溪忽懷驪山別業因以言志示弟淑奉呈諸大僚之作','魏奉古','唐','唐诗','tang','','[]','有美朝爲貴，幽尋地自偏。',120,'全唐诗/poet.tang.4000.json','["有美朝爲貴，幽尋地自偏。", "踐臨伊水汭，想望灞池邊。", "是遇皆新賞，茲遊若舊年。", "藤蘿隱路接，楊柳御溝聯。", "道愜神情王，機忘俗理捐。", "遂初誠已重，兼濟實爲賢。", "跡是東山戀，心惟北闕懸。", "顧慙經拾紫，多謝賦思玄。", "未躧中林步，空承麗藻傳。", "陽春和已寡，扣寂竟徒然。"]'),
('1ee8d5c4-8293-4940-8222-1576d891ed4d','奉酬韋祭酒偶遊龍門北溪忽懷驪山別業因以言志示弟淑並呈諸大僚之作','崔日知','唐','唐诗','tang','','[]','夙齡秉微尚，中年忽有鄰。',120,'全唐诗/poet.tang.4000.json','["夙齡秉微尚，中年忽有鄰。", "以茲山水癖，遂得狎通人。", "迨我咸京道，聞君別業新。", "巖前窺石鏡，河畔踏芳茵。", "既憐伊浦綠，復憶灞池春。", "連詞謝家子，同歡冀野賓。", "趣閑魚共樂，情洽鳥來馴。", "詎念昔遊者，祇命獨留秦。", "蕭條穎陽戀，沖漠漢陰真。", "無由陪勝躅，空此翫書筠。"]'),
('e31ab924-a0c9-410d-9a90-7b36deef7918','冬日述懷奉呈韋祭酒張左丞蘭臺名賢','崔日知','唐','唐诗','tang','','[]','弱齡好經籍，披卷即怡然。',264,'全唐诗/poet.tang.4000.json','["弱齡好經籍，披卷即怡然。", "覃精四十載，馳騁數千言。", "孔壁採遺篆，周韋考絕編。", "袁公論劒術，孫子敘兵篇。", "魯史君臣道，姬書日月懸。", "從師改炎燠，負笈遍山川。", "上異西河夏，中非北海玄。", "光榮拾青紫，名價接通賢。", "既重萬鍾樂，寧思二頃田。", "長戟同分虎，高冠亞附蟬。", "晚懷重虛曠，養志息雕鐫。", "登高慚思拙，匠物謝情妍。", "不慕張平子，寧希王仲宣。", "誰謂登龍日，翻成刻鵠年。", "循循勞善誘，軋軋思微牽。", "琢磨才既竭，鑽仰德彌堅。", "朽木誠爲諭，捫心徒自憐。", "終期吞鳥夢，振翼上雲煙。", "賦成先擲地，詞高直掞天。", "更執摳衣禮，仍開函丈筵。", "霧披槐市藹，水靜璧池圓。", "願逐從風葉，飛舞翰林前。"]'),
('81232f93-42d2-47be-a714-1cfac8a255f0','奉酬韋嗣立祭酒偶遊龍門北溪忽懷驪山別業因以言志示弟淑奉呈諸大僚之作','崔泰之','唐','唐诗','tang','','[]','關塞臨伊水，驪山枕灞川。',122,'全唐诗/poet.tang.4000.json','["關塞臨伊水，驪山枕灞川。", "俱臨隱路側，同在帝城邊。", "謝公兼出處，攜妓翫林泉。", "鳴騶噴梅雪，飛蓋曳松煙。", "聞琴幽谷裏，看[弈]古巖前。", "落日低幃帳，歸雲繞管弦。", "叨榮慚北闕，微尚愛東田。", "寂寞灰心盡，蕭條塵事捐。", "朝思登嶃絕，夜夢弄潺湲。", "宿懷南澗意，況覩北谿篇。"]'),
('aaeee0c3-dc64-4c33-9013-4b5d5823491c','同光祿弟冬日述懷','崔泰之','唐','唐诗','tang','','[]','吾族白眉良，才華動洛陽。',264,'全唐诗/poet.tang.4000.json','["吾族白眉良，才華動洛陽。", "觀光初入仕，應宿始爲郎。", "飛螢翫書籍，白鳳吐文章。", "海卿逾往雅，河尹冠前張。", "擇材綏鄢郢，殊化被江湘。", "高樓臨廣陌，甲第敞通莊。", "列館邙山下，疏亭洛水傍。", "昌年賞豐陌，暇日悅林塘。", "衣冠皆秀彥，羅綺盡名倡。", "隔岸聞歌度，臨池見舞行。", "門庭寒變色，棨戟日生光。", "窮陰方靉靆，殺氣正蒼茫。", "感時興盛作，晚歲共多傷。", "積德韋丞相，通神張子房。", "吟草徧簪紱，逸韻合宮商。", "功名守留省，濫迹在文昌。", "家園遙可見，臺寺近相望。", "無庸乘侍謁，有暇共翱翔。", "棣華依雁序，竹葉拂鸞觴。", "水坐憐秋月，山行弄晚芳。", "恩華慙服冕，友愛勗垂堂。", "無由報天德，相顧詠時康。"]'),
('c3a4bc98-2179-44ff-9655-2a6155043226','奉和聖製送張尚書巡邊','崔泰之','唐','唐诗','tang','','[]','南庭胡運盡，北斗將星飛。',120,'全唐诗/poet.tang.4000.json','["南庭胡運盡，北斗將星飛。", "旗鼓臨沙漠，旌旄出洛畿。", "關山遶玉塞，烽火映金微。", "屢獻帷謀策，頻承廟勝威。", "躞蹀臨河騎，逶迤度隴旂。", "地脈平千古，天聲振九圍。", "車馬生邊氣，戈鋋駐落暉。", "夏近蓬猶轉，秋深草木腓。", "餞送紆天什，恩榮賜御衣。", "佇勒燕然頌，鳴騶計日歸。"]'),
('517d08ab-c3fd-4d70-8a6b-7c0c52922a88','春夜寓直鳳閣懷羣公','魏知古','唐','唐诗','tang','','[]','拜門傳漏晚，寓直索居時。',48,'全唐诗/poet.tang.4000.json','["拜門傳漏晚，寓直索居時。", "昔重安仁賦，今稱伯玉詩。", "鴛池滿不溢，雞樹久逾滋。", "夙夜懷山甫，清風詠所思。"]'),
('513e1820-323e-405a-a3d5-6db10b3403b4','奉和春日途中喜雨應詔','魏知古','唐','唐诗','tang','','[]','皇輿向洛城，時雨應天行。',60,'全唐诗/poet.tang.4000.json','["皇輿向洛城，時雨應天行。", "麗日登巖送，陰雲出野迎。", "濯枝林杏發，潤葉渚蒲生。", "絲入綸言喜，花依錦字明。", "微臣忝東觀，載筆佇西成。"]'),
('a704799c-a4ca-455d-b356-6c7a41cf53e3','從獵渭川獻詩','魏知古','唐','唐诗','tang','','[]','嘗聞夏太康，五弟訓禽荒。',120,'全唐诗/poet.tang.4000.json','["嘗聞夏太康，五弟訓禽荒。", "我后來冬狩，三驅盛禮張。", "順時鷹隼擊，講事武功揚。", "奔走未及去，翾飛豈暇翔。", "非熊從渭水，瑞翟想陳倉。", "此欲誠難縱，茲遊不可常。", "子雲陳羽獵，僖伯諫漁棠。", "得失鑒齊楚，仁思念禹湯。", "雍熙亮在宥，亭毒匪多傷。", "辛甲今爲史，虞箴遂孔彰。"]'),
('14b5cbcd-8b87-46b2-b526-b4bdcfadb0ac','玄元觀尋李先生不遇','魏知古','唐','唐诗','tang','','[]','羽客今何在，空尋伊洛間。',48,'全唐诗/poet.tang.4000.json','["羽客今何在，空尋伊洛間。", "忽聞歸苦縣，復想入函關。", "未作千年別，猶應七日還。", "神仙不可見，寂寞返蓬山。"]'),
('31c0802f-6e2b-4b50-9374-52a8c14b78d6','招諭有懷贈同行人','李乂','唐','唐诗','tang','','[]','遠遊冒艱阻，深入勞存諭。',120,'全唐诗/poet.tang.4000.json','["遠遊冒艱阻，深入勞存諭。", "春去辭國門，秋還在邊戍。", "軒車行未返，節序催難駐。", "陌上悲轉蓬，園中想芳樹。", "蜀山自紛糾，岷水恆奔注。", "臨泛多苦懷，登攀寡歡趣。", "永夕飛淫雨，崇朝蒸毒霧。", "不求綏嶺桃，寧美邛鄉蒟。", "白浪行欲靜，驄馬何嘗驅。", "願接軺斾塵，聯翩東北騖。"]'),
('9af7cf29-11ca-43fa-8d90-ed954467f262','春日侍宴芙蓉園應制','李乂','唐','唐诗','tang','','[]','水殿臨丹籞，山樓繞翠微。',48,'全唐诗/poet.tang.4000.json','["水殿臨丹籞，山樓繞翠微。", "昔遊人託乘，今幸帝垂衣。", "澗篠緣峰合，巖花逗浦飛。", "朝來江曲地，無處不光輝。"]'),
('e90b3aa8-8ac4-4de3-947c-10ff1c29ed28','奉和登驪山高頂寓目應制','李乂','唐','唐诗','tang','','[]','崖巘萬尋懸，居高敞御筵。',48,'全唐诗/poet.tang.4000.json','["崖巘萬尋懸，居高敞御筵。", "行戈疑駐日，步輦若登天。", "城闕霧中近，關河雲外連。", "謬陪登岱駕，欣奉濟汾篇。"]'),
('34a2540b-7690-4b2b-9d18-0bbdbe31c0e7','奉和七夕兩儀殿會宴應制','李乂','唐','唐诗','tang','','[]','桂宮明月夜，蘭殿起秋風。',48,'全唐诗/poet.tang.4000.json','["桂宮明月夜，蘭殿起秋風。", "雲漢彌年阻，星筵此夕同。", "倏來疑有處，旋去已成空。", "睿作鈞天響，魂飛在夢中。"]'),
('b95c4772-cdc9-4d19-9bb7-ffdca2ca2fa3','奉和春日遊苑喜雨應詔','李乂','唐','唐诗','tang','','[]','仙蹕九成臺，香筵萬壽杯。',48,'全唐诗/poet.tang.4000.json','["仙蹕九成臺，香筵萬壽杯。", "一旬初降雨，二月早聞雷。", "葉向朝霽密，花含宿潤開。", "幸承天澤豫，無使日光催。"]'),
('c0e3f44d-76dd-46cf-90e1-67c9872da25e','奉和人日清暉閣宴羣臣遇雪應制','李乂','唐','唐诗','tang','','[]','上日登樓賞，中天御輦飛。',48,'全唐诗/poet.tang.4000.json','["上日登樓賞，中天御輦飛。", "後庭聯舞唱，前席仰恩輝。", "睿作風雲起，農祥雨雪霏。", "幸陪人勝節，長願奉垂衣。"]'),
('48d467ba-e879-49b1-a3c5-c2ef10ec33c0','陪幸臨渭亭遇雪應制','李乂','唐','唐诗','tang','','[]','青陽御紫微，白雲下彤闈。',48,'全唐诗/poet.tang.4000.json','["青陽御紫微，白雲下彤闈。", "浹壤流天霈，綿區灑帝輝。", "水如銀度燭，雲似玉披衣。", "爲得因風起，還來就日飛。"]'),
('bc6585d5-7508-4074-8f18-634d7a467edd','奉和九日侍宴應制得濃字','李乂','唐','唐诗','tang','','[]','望幸紆千乘，登高自九重。',48,'全唐诗/poet.tang.4000.json','["望幸紆千乘，登高自九重。", "臺疑臨戲馬，殿似接疏龍。", "捧篋萸香遍，稱觴菊氣濃。", "更看仙鶴舞，來此慶時雍。"]'),
('27fe9d0b-b513-45d3-b84a-f438ba9dd879','送沙門弘景道俊玄奘還荆州應制','李乂','唐','唐诗','tang','','[]','初日承歸旨，秋風起贈言。',48,'全唐诗/poet.tang.4000.json','["初日承歸旨，秋風起贈言。", "漢珠留道味，江璧返真源。", "地出南關遠，天迴北斗尊。", "寧知一柱觀，却啓四禪門。"]'),
('5618a138-258d-4ebf-8380-5e1bbd4e932b','奉和九月九日登慈恩寺浮圖應制','李乂','唐','唐诗','tang','','[]','湧塔臨玄地，高層瞰紫微。',48,'全唐诗/poet.tang.4000.json','["湧塔臨玄地，高層瞰紫微。", "鳴鑾陪帝出，攀橑翊天飛。", "慶洽重陽壽，文含列象輝。", "小臣叨載筆，欣此頌巍巍。"]'),
('b318f9fc-a9b8-438b-9c2a-34c042eb24fc','閏九月九日幸總持寺登浮圖應制','李乂','唐','唐诗','tang','','[]','清蹕幸禪樓，前驅歷御溝。',48,'全唐诗/poet.tang.4000.json','["清蹕幸禪樓，前驅歷御溝。", "還疑九日豫，更想六年遊。", "聖藻輝纓絡，仙花綴冕旒。", "所欣延億載，寧祗慶重秋。"]'),
('f65f3d6d-da62-453a-bdc1-497931bb8da0','侍宴長寧公主東莊應制','李乂','唐','唐诗','tang','','[]','紫禁乘宵動，青門訪水嬉。',48,'全唐诗/poet.tang.4000.json','["紫禁乘宵動，青門訪水嬉。", "貴遊鱣序集，仙女鳳樓期。", "合宴簪紳滿，承恩雨露滋。", "北辰還捧日，東館幸逢時。"]'),
('ffecb949-9b13-4aaa-9400-1e42b7782107','幸白鹿觀應制','李乂','唐','唐诗','tang','','["\u534e\u5c71"]','制蹕乘驪阜，迴輿指鳳京。',48,'全唐诗/poet.tang.4000.json','["制蹕乘驪阜，迴輿指鳳京。", "南山四皓謁，西嶽兩童迎。", "雲幄臨懸圃，霞杯薦赤城。", "神明近茲地，何必往蓬瀛。"]'),
('3540344f-4e27-4952-8464-5e4a5b9875c8','次蘇州','李乂','唐','唐诗','tang','','[]','洛渚問吳潮，吳門想洛橋。',48,'全唐诗/poet.tang.4000.json','["洛渚問吳潮，吳門想洛橋。", "夕煙楊柳岸，春水木蘭橈。", "城邑南樓近，星辰北斗遙。", "無因生羽翼，輕舉托還飆。"]'),
('c59bd532-32fd-4f64-afd1-a3ad470fc2a7','寄胡皓時在南中','李乂','唐','唐诗','tang','','[]','徭役苦流滯，風波限泝洄。',48,'全唐诗/poet.tang.4000.json','["徭役苦流滯，風波限泝洄。", "江流通地骨，山道繞天台。", "有鳥圖南去，無人見北來。", "閉門滄海曲，雲霧待君開。"]'),
('4cc497ec-2a0e-4ecf-8b26-f4ff4da2344d','餞許州宋司馬赴任','李乂','唐','唐诗','tang','','[]','展驥旌時傑，談雞美代賢。',48,'全唐诗/poet.tang.4000.json','["展驥旌時傑，談雞美代賢。", "暫離仙掖務，追送近郊筵。", "地慘金商節，人康璧假田。", "從來昆友事，咸以佩刀傳。"]'),
('60b41f31-8852-4bbc-b5b5-41ef9cfaf507','餞唐州高使君赴任','李乂','唐','唐诗','tang','','[]','淮源之水清，可以濯君纓。',48,'全唐诗/poet.tang.4000.json','["淮源之水清，可以濯君纓。", "彼美稱才傑，親人佇政聲。", "歲寒疇曩意，春晚別離情。", "終歎臨岐遠，行看擁傳榮。"]'),
('b1357578-718a-485c-a9be-fb0223213615','哭僕射鄂公楊再思','李乂','唐','唐诗','tang','','[]','端揆凝邦績，台階闡國猷。',48,'全唐诗/poet.tang.4000.json','["端揆凝邦績，台階闡國猷。", "方崇大廈棟，忽逝巨川舟。", "白日銘安在，清風頌獨留。", "死生恩命畢，零落掩山丘。"]'),
('27637fd6-64db-4794-a8c8-fb4a2a9e8d66','故趙王屬贈黃門侍郎上官公挽詞','李乂','唐','唐诗','tang','','[]','暮歸泉壤隔，朝發城池戀。',48,'全唐诗/poet.tang.4000.json','["暮歸泉壤隔，朝發城池戀。", "漢畤結愁陰，秦陵下悲霰。", "駸駸百駟馳，憫憫羣龍餞。", "石馬徒自施，玉人終不見。"]'),
('4a5969e0-ce97-44ac-b004-fb626e8b6a7e','淮陽公主挽歌','李乂','唐','唐诗','tang','','[]','玉顏生漢渚，湯沐榮天女。',48,'全唐诗/poet.tang.4000.json','["玉顏生漢渚，湯沐榮天女。", "金縷化邙塵，哀榮感路人。", "鳳皇曾作伴，螻蟻忽爲親。", "疇日成蹊處，穠華不復春。"]'),
('079828a5-83da-4191-838c-a392b2f6053f','故西臺侍郎上官公挽歌','李乂','唐','唐诗','tang','','[]','宇內文儒重，朝端禮命優。',48,'全唐诗/poet.tang.4000.json','["宇內文儒重，朝端禮命優。", "立言多啓沃，論道盛謀猷。", "顧日琴安在，衝星劍不留。", "徒懷東武襚，更掩北原丘。"]'),
('563204d2-74ba-42a3-932d-24445639dc18','高安公主挽歌二首 一','李乂','唐','唐诗','tang','','[]','湯沐三千賦，樓臺十二重。',48,'全唐诗/poet.tang.4000.json','["湯沐三千賦，樓臺十二重。", "銀鑪稱貴幸，玉輦盛過逢。", "嬪則留中饋，娥輝沒下舂。", "平陽百歲後，歌舞爲誰容。"]'),
('69f97a09-1c3e-4790-a553-5d89ede4531e','高安公主挽歌二首 二','李乂','唐','唐诗','tang','','[]','賓衞儼相依，橫門啓曙扉。',48,'全唐诗/poet.tang.4000.json','["賓衞儼相依，橫門啓曙扉。", "靈陰蟾兔缺，仙影鳳皇飛。", "一水秋難渡，三泉夜不歸。", "況臨青女節，瑤草更前哀。"]'),
('e17a3540-79d9-4a1f-8a45-7b0c81370181','奉和初春幸太平公主南莊應制','李乂','唐','唐诗','tang','','[]','平陽館外有仙家，沁水園中好物華。',64,'全唐诗/poet.tang.4000.json','["平陽館外有仙家，沁水園中好物華。", "地出東郊迴日御，城臨南斗度雲車。", "風泉韻繞幽林竹，雨霰光搖雜樹花。", "已慶時來千億壽，還言日暮九重賒。"]'),
('a228aae3-e5db-4a88-b8a4-06d6e705f610','興慶池侍宴應制','李乂','唐','唐诗','tang','','[]','神池泛濫水盈科，仙蹕紆徐步輦過。',64,'全唐诗/poet.tang.4000.json','["神池泛濫水盈科，仙蹕紆徐步輦過。", "縱棹洄沿萍溜合，開軒眺賞麥風和。", "潭魚在藻供遊詠，谷鳥含櫻入賦歌。", "寄語乘槎溟海客，回頭來此問天河。"]'),
('1492d1df-92d6-4a28-8a46-829a41cf53e3','侍宴安樂公主山莊應制','李乂','唐','唐诗','tang','','[]','金輿玉輦背三條，水閣山樓望九霄。',64,'全唐诗/poet.tang.4000.json','["金輿玉輦背三條，水閣山樓望九霄。", "野外初迷七聖道，河邊忽覩二靈橋。", "懸冰滴滴依虬箭，清吹泠泠雜鳳簫。", "回晚平陽歌舞合，前溪更轉木蘭橈。"]'),
('4a102797-0a30-48c9-91c7-815b29fe5fe4','奉和春日幸望春宮應制','李乂','唐','唐诗','tang','','[]','東城結宇敞千尋，北闕迴輿具四臨。',64,'全唐诗/poet.tang.4000.json','["東城結宇敞千尋，北闕迴輿具四臨。", "麗日祥煙承罕畢，輕荑弱草藉衣簪。", "秦商重沓雲巖近，河渭縈紆霧壑深。", "謬接鵷鴻陪賞樂，還欣魚鳥遂飛沈。"]'),
('791740b2-81d8-426a-b356-035e6f5ed5f1','人日重宴大明宮恩賜綵縷人勝應制','李乂','唐','唐诗','tang','','[]','詰旦行春上苑中，憑高却下大明宮。',64,'全唐诗/poet.tang.4000.json','["詰旦行春上苑中，憑高却下大明宮。", "千年執象寰瀛泰，七日爲人慶賞隆。", "鐵鳳曾鶱搖瑞雪，銅烏細轉入祥風。", "此時朝野歡無算，此歲雲天樂未窮。"]'),
('432cbb04-09a0-4e9e-9ae7-a56f73ce6fd9','享龍池樂第八章','李乂','唐','唐诗','tang','','[]','星分邑里四人居，水洊源流萬頃餘。',64,'全唐诗/poet.tang.4000.json','["星分邑里四人居，水洊源流萬頃餘。", "魏國君王稱象處，晉家蕃邸化龍初。", "青蒲暫似遊梁馬，綠藻還疑宴鎬魚。", "自有神靈滋液地，年年雲物史官書。"]'),
('b5eea35b-0a38-45bf-be0c-d7227e227393','奉和幸禮部尚書竇希玠宅應制','李乂','唐','唐诗','tang','','[]','家住千門側，亭臨二水傍。',72,'全唐诗/poet.tang.4000.json','["家住千門側，亭臨二水傍。", "貴遊開北地，宸眷幸西鄉。", "曳履迎中谷，鳴絲出後堂。", "浦疑觀萬象，峰似駐三光。", "草向瓊筵樂，花承繡扆香。", "聖情思舊重，留飲賦雕章。"]'),
('d91b36c5-bb4d-4138-9c84-1a99929465d0','奉和晦日幸昆明池應制','李乂','唐','唐诗','tang','','[]','玉輅尋春賞，金堤重晦遊。',72,'全唐诗/poet.tang.4000.json','["玉輅尋春賞，金堤重晦遊。", "川通黑水浸，地派紫泉流。", "晃朗扶桑出，綿聯杞樹周。", "烏疑填海處，人似隔河秋。", "劫盡灰猶識，年移石故留。", "汀洲歸棹晚，簫鼓雜汾謳。"]'),
('874a53f4-0e84-48aa-b541-6d9efa0214de','奉和幸長安故城未央宮應制','李乂','唐','唐诗','tang','','[]','鳳輦乘春陌，龍山訪故臺。',72,'全唐诗/poet.tang.4000.json','["鳳輦乘春陌，龍山訪故臺。", "北宮纔盡處，南斗獨昭回。", "肆覽飛宸札，稱觴引御杯。", "已觀蓬海變，誰厭柏梁災。", "代挹孫通禮，朝稱賈誼才。", "忝儕文雅地，先後各時來。"]'),
('b3c95c95-7e52-464f-9dd2-34233f2eddb7','陪幸韋嗣立山莊應制','李乂','唐','唐诗','tang','','[]','樞掖調梅暇，林園種槿初。',96,'全唐诗/poet.tang.4000.json','["樞掖調梅暇，林園種槿初。", "入朝榮劒履，退食偶琴書。", "地隱東巖室，天迴北斗車。", "旌門臨䆗窱，輦道屬扶疎。", "雲罕明丹谷，霜笳徹紫虛。", "水疑投石處，谿似釣璜餘。", "帝澤頒巵酒，人歡頌里閭。", "一承黃竹詠，長奉白茆居。"]'),
('250f92d6-67d8-4383-96b8-c7fdb97067a0','奉和幸望春宮送朔方軍大總管張仁亶','李乂','唐','唐诗','tang','','[]','邊郊草具腓，河塞有兵機。',72,'全唐诗/poet.tang.4000.json','["邊郊草具腓，河塞有兵機。", "上宰調梅寄，元戎細柳威。", "武貔東道出，鷹隼北庭飛。", "玉匣謀中野，金輿下太微。", "投醪銜餞酌，緝衮事征衣。", "勿謂公孫老，行聞奏凱歸。"]'),
('5278f787-c0d0-48af-8821-a43a27b1f733','奉和幸三會寺應制','李乂','唐','唐诗','tang','','[]','睿德總無邊，神臯擇勝緣。',72,'全唐诗/poet.tang.4000.json','["睿德總無邊，神臯擇勝緣。", "二儀齊法駕，三會禮香筵。", "漢闕中黃近，秦山太白連。", "臺疑觀鳥日，池似刻鯨年。", "滿月臨真境，秋風入御弦。", "小臣叨下列，持管謬窺天。"]'),
('1124caea-f531-4e63-90f8-8a19f7f49681','奉和幸大薦福寺','李乂','唐','唐诗','tang','','[]','象設隆新宇，龍潛想舊居。',72,'全唐诗/poet.tang.4000.json','["象設隆新宇，龍潛想舊居。", "碧樓披玉額，丹仗導金輿。", "代日興光近，周星掩曜初。", "空歌清沛筑，梵樂奏胡書。", "帝造環三界，天文賁六虛。", "康哉孝理日，崇德在真如。"]'),
('f7917ec7-c159-425a-bdfe-37c4e19f937a','夏日都門送司馬員外逸客孫員外佺北征','李乂','唐','唐诗','tang','','[]','日逐滋南寇，天威撫北垂。',72,'全唐诗/poet.tang.4000.json','["日逐滋南寇，天威撫北垂。", "析珪行仗節，持印且分麾。", "羽檄雙鳧去，兵車駟馬馳。", "虎旗懸氣色，龍劍抱雄雌。", "候月期戡翦，經時念別離。", "坐聞關隴外，無復引弓兒。"]'),
('d8eb4cff-a052-4634-bb6a-1285a0f124fe','元日恩賜柏葉應制','李乂','唐','唐诗','tang','','[]','勁節凌冬勁，芳心待歲芳。',24,'全唐诗/poet.tang.4000.json','["勁節凌冬勁，芳心待歲芳。", "能令人益壽，非止麝含香。"]'),
('2012f4da-450a-4ae1-b949-989f9f57e7c2','侍宴桃花園詠桃花應制','李乂','唐','唐诗','tang','','[]','綺蕚成蹊遍籞芳，紅英撲地滿筵香。',32,'全唐诗/poet.tang.4000.json','["綺蕚成蹊遍籞芳，紅英撲地滿筵香。", "莫將秋宴傳王母，來比春華奉聖皇。"]'),
('89338671-f2fe-40e2-8689-b3f72618a6aa','奉和三日祓禊渭濱','李乂','唐','唐诗','tang','','[]','上林花鳥暮春時，上巳陪遊樂在茲。',32,'全唐诗/poet.tang.4000.json','["上林花鳥暮春時，上巳陪遊樂在茲。", "此日欣逢臨渭賞，昔年空道濟汾詞。"]'),
('aa296c2c-61c4-4d34-b2e4-cf511c9ac3ab','奉和幸韋嗣立山莊侍宴應制','李乂','唐','唐诗','tang','','[]','曲榭迴廊繞澗幽，飛泉噴下溢池流。',32,'全唐诗/poet.tang.4000.json','["曲榭迴廊繞澗幽，飛泉噴下溢池流。", "祗應感發明王夢，遂得邀迎聖帝遊。"]'),
('da37f3a0-2e60-4ff7-a46e-9041ebfc392b','侍宴安樂公主新宅應制','李乂','唐','唐诗','tang','','[]','牽牛南渡象昭回，學鳳樓成帝女來。',32,'全唐诗/poet.tang.4000.json','["牽牛南渡象昭回，學鳳樓成帝女來。", "平旦鵷鸞歌舞席，方宵鸚鵡獻酬杯。"]'),
('fb3bf7ec-e1ca-42e6-b22e-f95d3aae09f9','餞唐永昌','李乂','唐','唐诗','tang','','[]','田郎才貌出咸京，潘子文華向洛城。',32,'全唐诗/poet.tang.4000.json','["田郎才貌出咸京，潘子文華向洛城。", "願以深心留善政，當令強項謝高名。"]'),
('11de58b1-2fe5-4e18-b2be-b4d062aa5d54','九日幸臨渭亭登高應制得開字','盧藏用','唐','唐诗','tang','','[]','上月重陽滿，中天萬乘來。',48,'全唐诗/poet.tang.4000.json','["上月重陽滿，中天萬乘來。", "萸依佩裏發，菊向酒邊開。", "聖澤煙雲動，宸文象緯迴。", "小臣無以荅，願奉億千杯。"]'),
('9ce559a1-f2f7-4b8a-b2e7-0dc48a07a002','奉和九月九日登慈恩寺浮圖應制','盧藏用','唐','唐诗','tang','','[]','化塔龍山起，中天鳳輦迂。',48,'全唐诗/poet.tang.4000.json','["化塔龍山起，中天鳳輦迂。", "綵旒牽畫剎，雜珮冒香萸。", "寶葉擎千座，金英漬百盂。", "秋雲飄聖藻，霄極捧連珠。"]'),
('73fd4790-64c5-45f5-bc89-e431bfc14af3','宋主簿鳴臯夢趙六予未及報而陳子云亡今追爲此詩荅宋兼貽平昔遊舊','盧藏用','唐','唐诗','tang','','[]','暮川罕停波，朝雲無留色。',288,'全唐诗/poet.tang.4000.json','["暮川罕停波，朝雲無留色。", "故人琴與詩，可存不可識。", "識心尚可親，琴詩非故人。", "鳴臯初夢趙，蜀國已悲陳。", "感化傷淪滅，魂交惜未申。", "冥期失幽報，茲理復今晨。", "前嗟成後泣，已矣將何及。", "舊感與新悲，虛懷酬昔時。", "趙侯鴻寶氣，獨負青雲姿。", "羣有含妙識，衆象懸清機。", "雄談盡物變，精義解人頤。", "在陰既獨善，幽躍自爲疑。", "踠彼千里足，傷哉一尉欺。", "陳生富清理，卓犖兼文史。", "思縟巫山雲，調逸岷江水。", "鏗鏘哀忠義，感激懷知己。", "負劒登薊門，孤遊入燕市。", "浩歌去京國，歸守西山趾。", "幽居探元化，立言見千祀。", "埋沒經濟情，良圖竟云已。", "坐憶平生遊，十載懷嵩丘。", "題書滿古壁，採藥遍巖幽。", "子微化金鼎，仙笙不可求。", "榮哉宋與陸，名宦美中州。"]'),
('cf5c5600-854d-4d08-af09-10e6593f0ace','餞唐州高使君赴任','盧藏用','唐','唐诗','tang','','[]','餞酒臨豐樹，褰帷出魯陽。',48,'全唐诗/poet.tang.4000.json','["餞酒臨豐樹，褰帷出魯陽。", "蕙蘭春已晚，桐柏路猶長。", "祖逖方城鎮，安期外氏鄉。", "從來二千石，天子命唯良。"]'),
('a94ea0f5-1cbb-430b-8005-104bfb0ffb56','餞許州宋司馬赴任','盧藏用','唐','唐诗','tang','','[]','國爲休徵選，輿因仲舉題。',48,'全唐诗/poet.tang.4000.json','["國爲休徵選，輿因仲舉題。", "山川襄野隔，朋酒灞亭暌。", "零雨征軒騖，秋風別驥嘶。", "驪歌一曲罷，愁望正淒淒。"]'),
('de105dee-10c7-4431-9132-40100fd66753','奉和立春遊苑迎春應制','盧藏用','唐','唐诗','tang','','["\u9ec4\u5c71"]','天遊龍輦駐城闉，上苑遲光晚更新。',64,'全唐诗/poet.tang.4000.json','["天遊龍輦駐城闉，上苑遲光晚更新。", "瑤臺半入黃山路，玉檻傍臨玄霸津。", "梅香欲待歌前落，蘭氣先過酒上春。", "幸預柏臺稱獻壽，願陪千畝及農晨。"]'),
('2b41bdad-7a93-4028-b579-5e19b73931fa','奉和幸安樂公主山莊應制','盧藏用','唐','唐诗','tang','','[]','皇女璚臺天漢潯，星橋月宇構山林。',64,'全唐诗/poet.tang.4000.json','["皇女璚臺天漢潯，星橋月宇構山林。", "飛蘿半拂銀題影，瀑布環流玉砌陰。", "菊浦香隨鸚鵡泛，簫樓韻逐鳳凰吟。", "瑤池駐蹕恩方久，璧月無文興轉深。"]'),
('4c5c7c3b-ac0e-4150-9baa-c9b8fc2fc060','夜宴安樂公主宅','盧藏用','唐','唐诗','tang','','[]','侯家主第一時新，上席華年不惜春。',32,'全唐诗/poet.tang.4000.json','["侯家主第一時新，上席華年不惜春。", "珠釭綴日那知夜，玉斝流霞畏底晨。"]'),
('9db45ddd-88f7-4a02-9afa-2f0bd74749a7','九月九日幸臨渭亭登高應制得涘字','岑羲','唐','唐诗','tang','','[]','重九開科曆，千齡逢聖紀。',48,'全唐诗/poet.tang.4000.json','["重九開科曆，千齡逢聖紀。", "爰豫矚秦坰，昇高臨灞涘。", "玉醴浮仙菊，瓊筵薦芳芷。", "一聞帝舜歌，歡娛良未已。"]'),
('addf6b4f-197c-43aa-bce3-4146ab380a68','奉和九月九日登慈恩寺浮屠應制','岑羲','唐','唐诗','tang','','[]','寶臺聳天外，玉輦步雲端。',48,'全唐诗/poet.tang.4000.json','["寶臺聳天外，玉輦步雲端。", "日麗重陽景，風搖季月寒。", "梵堂遙集鴈，帝樂近翔鸞。", "願獻延齡酒，長承湛露歡。"]'),
('1b67fd9d-1da5-4f3e-9c2b-93a50b2eb317','餞唐州高使君','岑羲','唐','唐诗','tang','','[]','蒼茫南塞地，明媚上春時。',48,'全唐诗/poet.tang.4000.json','["蒼茫南塞地，明媚上春時。", "目極傷千里，懷君不自持。", "征車別岐路，斜日下崦嵫。", "一歎軺軒阻，悠悠即所思。"]'),
('e1cca902-ea39-4e7e-9d74-11516c22bb46','奉和春日幸望春宮應制','岑羲','唐','唐诗','tang','','[]','和風助律應韶年，清蹕乘高入望僊。',64,'全唐诗/poet.tang.4000.json','["和風助律應韶年，清蹕乘高入望僊。", "花笑鶯歌迎帝輦，雲披日霽俯皇川。", "南山近壓仙樓上，北斗平臨御扆前。", "一奉恩榮同鎬宴，空知率舞聽薰弦。"]'),
('606697de-45c2-462c-829a-f8b443879554','奉和幸安樂公主山莊應制','岑羲','唐','唐诗','tang','','[]','銀牓重樓出霧開，金輿步輦向天來。',64,'全唐诗/poet.tang.4000.json','["銀牓重樓出霧開，金輿步輦向天來。", "泉聲迥入吹簫曲，山勢遙臨獻壽杯。", "帝女含笑流飛電，乾文動色象昭回。", "誠願北極拱堯日，微臣抃舞詠康哉。"]'),
('e8db4b79-7a2c-43cf-96ec-6721b495a216','夜宴安樂公主新宅','岑羲','唐','唐诗','tang','','[]','金牓重樓開夜扉，瓊筵愛客未言歸。',32,'全唐诗/poet.tang.4000.json','["金牓重樓開夜扉，瓊筵愛客未言歸。", "銜歡不覺銀河曙，盡醉那知玉漏稀。"]'),
('697cf483-287d-4001-86dc-63e62f421d24','儀坤廟樂章二首 一','薛稷','唐','唐诗','tang','','[]','陽靈配德，陰魄昭升。',80,'全唐诗/poet.tang.4000.json','["陽靈配德，陰魄昭升。", "堯壇鳳下，漢室龍興。", "俔天作對，前旒是凝。", "化行南國，道盛西陵。", "造舟集灌，無德而稱。", "我粢既潔，我醴既澄。", "陰陰靈廟，光靈若憑。", "德馨惟饗，孝思烝烝。"]'),
('d5f6b3aa-d7ed-4664-9a0e-63330bfc2c52','儀坤廟樂章二首 二','薛稷','唐','唐诗','tang','','[]','乾道既亨，坤元以貞。',80,'全唐诗/poet.tang.4000.json','["乾道既亨，坤元以貞。", "肅雍攸在，輔佐斯成。", "外睦九族，內光一庭。", "克生睿哲，祚我休明。", "欽若徽範，悠哉淑靈。", "建茲清宮，於彼上京。", "縮茅以獻，絜秬惟馨。", "實受其福，斯乎億齡。"]'),
('93c6c5dc-c1b3-4edf-8245-e24f38facc9b','九日幸臨渭亭登高應制得曆字','薛稷','唐','唐诗','tang','','[]','暮節乘原野，宣遊俯崖壁。',48,'全唐诗/poet.tang.4000.json','["暮節乘原野，宣遊俯崖壁。", "秋登華實滿，氣嚴鷹隼擊。", "仙菊含霜泛，聖藻臨雲錫。", "願陪九九辰，長奉千千曆。"]'),
('ba33edea-2cb2-46a8-bb0d-e2f376408d13','慈恩寺九日應制','薛稷','唐','唐诗','tang','','[]','寶宮星宿劫，香塔鬼神功。',48,'全唐诗/poet.tang.4000.json','["寶宮星宿劫，香塔鬼神功。", "王遊盛塵外，睿覽出區中。", "日宇開初景，天詞掩大風。", "微臣謝時菊，薄采入芳叢。"]'),
('1485bd4d-833c-4645-9d65-4df34eeea3df','早春魚亭山','薛稷','唐','唐诗','tang','','[]','春氣動百草，紛榮時斷續。',60,'全唐诗/poet.tang.4000.json','["春氣動百草，紛榮時斷續。", "白雲自高妙，裴回空山曲。", "陽林花已紅，寒澗苔未綠。", "伊余息人事，蕭寂無營欲。", "客行雖云遠，翫之聊自足。"]'),
('2e2f687d-be09-4cb6-b503-d8e14ac6e8ec','秋日還京陝西十里作','薛稷','唐','唐诗','tang','','[]','驅車越陝郊，北顧臨大河。',72,'全唐诗/poet.tang.4000.json','["驅車越陝郊，北顧臨大河。", "隔河望鄉邑，秋風水增波。", "西登咸陽途，日暮憂思多。", "傅巖既紆鬱，首山亦嵯峨。", "操築無昔老，採薇有遺歌。", "客遊節回換，人生知幾何。"]'),
('3713a59f-7659-4243-8c9c-b89e7d2c6620','奉和送金城公主適西蕃應制','薛稷','唐','唐诗','tang','','[]','天道寧殊俗，慈仁乃戢兵。',48,'全唐诗/poet.tang.4000.json','["天道寧殊俗，慈仁乃戢兵。", "懷荒寄赤子，忍愛鞠蒼生。", "月下瓊娥去，星分寶婺行。", "關山馬上曲，相送不勝情。"]'),
('82f686b3-963f-4162-885b-b8ea6b077698','春日登樓野望','薛稷','唐','唐诗','tang','','[]','憑軒聊一望，春色幾芬菲。',48,'全唐诗/poet.tang.4000.json','["憑軒聊一望，春色幾芬菲。", "野外煙初合，樓前花正飛。", "嬌鶯弄新響，斜日散餘暉。", "誰忍孤遊客，言念獨依依。"]'),
('44786698-7126-4848-ad0f-d10fe8643fde','餞許州宋司馬赴任','薛稷','唐','唐诗','tang','','[]','令弟與名兄，高才振兩京。',48,'全唐诗/poet.tang.4000.json','["令弟與名兄，高才振兩京。", "別序聞鴻燕，離章動鶺鴒。", "遠朋馳翰墨，勝地寫丹青。", "風月相思夜，勞望潁川星。"]'),
('ce57db7b-508f-4215-9b7e-687b108697b5','奉和聖製春日幸望春宮應制','薛稷','唐','唐诗','tang','','["\u9ec4\u5c71"]','九春風景足林泉，四面雲霞敞御筵。',64,'全唐诗/poet.tang.4000.json','["九春風景足林泉，四面雲霞敞御筵。", "花鏤黃山繡作苑，草圖玄灞錦爲川。", "飛觴競醉心迴日，走馬爭先眼著鞭。", "喜奉仙遊歸路遠，直言行樂不言旋。"]'),
('06feb2e7-1b0c-4a40-a1ba-cdbef4611a4d','奉和幸安樂公主山莊應制','薛稷','唐','唐诗','tang','','[]','主家園囿極新規，帝郊遊豫奉天儀。',64,'全唐诗/poet.tang.4000.json','["主家園囿極新規，帝郊遊豫奉天儀。", "歡宴瑤臺鎬京集，賞賜銅山蜀道移。", "曲閣交映金精板，飛花亂下珊瑚枝。", "借問今朝八龍駕，何如昔日望仙池。"]'),
('b5e058fa-f545-475e-9025-92262feaceaa','秋朝覽鏡','薛稷','唐','唐诗','tang','','[]','客心驚落木，夜坐聽秋風。',24,'全唐诗/poet.tang.4000.json','["客心驚落木，夜坐聽秋風。", "朝日看容鬢，生涯在鏡中。"]'),
('30bab7bb-ed27-48c9-87d8-c92ad3c5427b','夜宴安樂公主新宅','薛稷','唐','唐诗','tang','','[]','秦樓宴喜月裴回，妓筵銀燭滿庭開。',32,'全唐诗/poet.tang.4000.json','["秦樓宴喜月裴回，妓筵銀燭滿庭開。", "坐中香氣排花出，扇後歌聲逐酒來。"]'),
('ab3fc9e8-8150-4f38-aab2-e04d9d82d608','餞唐永昌','薛稷','唐','唐诗','tang','','[]','河洛風煙壯市朝，送君飛鳧去漸遙。',32,'全唐诗/poet.tang.4000.json','["河洛風煙壯市朝，送君飛鳧去漸遙。", "更思明年桃李月，花紅柳綠宴浮橋。"]'),
('0aaedd5d-f92c-4214-a9ba-981ec4670f6b','九日幸臨渭亭登高應制得酒字','馬懷素','唐','唐诗','tang','','[]','睿賞叶通三，宸遊契重九。',48,'全唐诗/poet.tang.4000.json','["睿賞叶通三，宸遊契重九。", "蘭將葉布席，菊用香浮酒。", "落日下桑榆，秋風歇楊柳。", "幸齊東戶慶，希薦南山壽。"]'),
('9a635c09-0e25-4b25-9817-d90768e21a8d','奉和九月九日登慈恩寺浮圖應制','馬懷素','唐','唐诗','tang','','[]','季月啓重陽，金輿陟寶坊。',48,'全唐诗/poet.tang.4000.json','["季月啓重陽，金輿陟寶坊。", "御旗橫日道，仙塔儼雲莊。", "帝蹕千官從，乾詞七曜光。", "顧慙文墨職，無以頌時康。"]'),
('d0d2fe1b-a65c-4428-a5d6-b7a66b92a1d0','奉和送金城公主適西蕃應制','馬懷素','唐','唐诗','tang','','[]','帝子今何去？重姻適異方。',48,'全唐诗/poet.tang.4000.json','["帝子今何去？重姻適異方。", "離情愴宸掖，別路遶關梁。", "望絕園中柳，悲纏陌上桑。", "空餘願黃鶴，東顧憶迴翔。"]'),
('59f4011a-af1a-46d3-889a-8291958d54ab','餞許州宋司馬赴任','馬懷素','唐','唐诗','tang','','[]','潁川開郡邑，角宿分躔野。',48,'全唐诗/poet.tang.4000.json','["潁川開郡邑，角宿分躔野。", "君非仲舉才，誰是題輿者。", "憫憫琴上鶴，蕭蕭路傍馬。", "嚴程若可留，別袂希再把。"]'),
('ae4257c5-7a2e-4422-9920-2bfafe7fa72a','餞唐州高使君赴任','馬懷素','唐','唐诗','tang','','[]','外牧資賢守，斯人奉帝俞。',48,'全唐诗/poet.tang.4000.json','["外牧資賢守，斯人奉帝俞。", "淮南膺建隼，渭北暫分符。", "坐歎煙波隔，行嗟物候殊。", "何年昇美課，迴首北城隅。"]'),
('c9a43d28-32ad-4fa2-ab8a-c13a092c21b8','奉和立春遊苑迎春應制','馬懷素','唐','唐诗','tang','','[]','玄籥飛灰出洞房，青郊迎氣肇初陽。',64,'全唐诗/poet.tang.4000.json','["玄籥飛灰出洞房，青郊迎氣肇初陽。", "仙輿暫下宜春苑，御醴行開薦壽觴。", "映水輕苔猶隱綠，緣堤弱柳未舒黃。", "唯有裁花飾簪鬢，恆隨聖藻狎年光。"]'),
('4e3abaf1-2a07-4351-8c69-4f3901e664c7','奉和聖製春日幸望春宮應制','馬懷素','唐','唐诗','tang','','[]','綵仗琱輿俯碧潯，行春御氣發皇心。',64,'全唐诗/poet.tang.4000.json','["綵仗琱輿俯碧潯，行春御氣發皇心。", "搖風細柳縈馳道，映日輕花出禁林。", "遍野園亭開帟幕，連堤草樹狎衣簪。", "謬參西掖霑堯酒，願沐南薰解舜琴。"]'),
('680ab466-cfc5-43f8-a68b-268c80d64137','奉和人日讌大明宮恩賜綵縷人勝應制','馬懷素','唐','唐诗','tang','','[]','日宇千門平旦開，天容萬象列昭回。',64,'全唐诗/poet.tang.4000.json','["日宇千門平旦開，天容萬象列昭回。", "三陽候節金爲勝，百福迎祥玉作杯。", "就暖風光偏著柳，辭寒雪影半藏梅。", "何幸得參詞賦職，自憐終乏馬卿才。"]'),
('7f83461d-c1ec-4c9d-b84f-411d40432bed','奉和幸安樂公主山莊應制','馬懷素','唐','唐诗','tang','','[]','主家臺沼勝平陽，帝幸歡娛樂未央。',64,'全唐诗/poet.tang.4000.json','["主家臺沼勝平陽，帝幸歡娛樂未央。", "掩映琱窗交極浦，參差繡戶繞迴塘。", "泉聲百處傳歌曲，樹影千重對舞行。", "聖酒一霑何以報，唯欣頌德奉時康。"]'),
('0691059d-30a9-4644-85c8-44595ec1b6c6','興慶池侍宴應制','馬懷素','唐','唐诗','tang','','[]','積水逶迤繞直城，[含]虛皎鏡有餘清。',66,'全唐诗/poet.tang.4000.json','["積水逶迤繞直城，[含]虛皎鏡有餘清。", "圖雲曲榭連緹幕，映日中塘間綵旌。", "賞洽猶聞簫管沸，歡留更睹木蘭輕。", "無勞海上尋仙客，即此蓬萊在帝京。"]'),
('0ea6e825-88dc-4019-bffb-371e2a274111','夜宴安樂公主宅','馬懷素','唐','唐诗','tang','','[]','鳳樓䆗窱凌三襲，翠幌玲瓏瞰九衢。',32,'全唐诗/poet.tang.4000.json','["鳳樓䆗窱凌三襲，翠幌玲瓏瞰九衢。", "複道中宵留宴衎，彌令上客想踟躕。"]'),
('cfb411ba-9e03-4ce3-be1d-ed44e760275d','餞唐永昌','馬懷素','唐','唐诗','tang','','[]','聞君出宰洛陽隅，賓友稱觴餞路衢。',32,'全唐诗/poet.tang.4000.json','["聞君出宰洛陽隅，賓友稱觴餞路衢。", "別後相思在何處？祗應關下望仙鳧。"]'),
('460577de-6930-4044-bded-11ae294f74d6','明冰篇','富嘉謨','唐','唐诗','tang','','[]','北陸蒼茫河海凝，南山闌干晝夜冰。',168,'全唐诗/poet.tang.4000.json','["北陸蒼茫河海凝，南山闌干晝夜冰。", "素彩峨峨明月升，深山窮谷不自見。", "安知採斵備嘉薦，陰房涸冱掩寒扇。", "陽春二月朝始暾，春光潭沱度千門。", "明冰時出御至尊，彤庭赫赫九儀備。", "腰玉煌煌千官事，明冰畢賦周在位。", "憶昨沙漠寒風漲，崑崙長河冰始壯。", "漫汗崚嶒積亭障，噰噰鳴雁江上來。", "禁苑池臺冰復開，搖青涵綠映樓臺。", "豳歌七月王風始，鑿冰藏用昭物軌，四時不忒千萬祀。"]'),
('bfe09b51-dedd-4b27-b5d3-e024ce305dca','長門怨','吳少微','唐','唐诗','tang','','[]','月出映層城，孤圓上太清。',72,'全唐诗/poet.tang.4000.json','["月出映層城，孤圓上太清。", "君王眷愛歇，枕席涼風生。", "怨咽不能寢，踟躕步前楹。", "空階白露色，百草寒蟲鳴。", "念昔金房裏，猶嫌玉座輕。", "如何嬌所誤，長夜泣恩情。"]'),
('0ba80aac-e697-4ecd-9e2d-3cb097c00e08','和崔侍御日用遊開化寺閣','吳少微','唐','唐诗','tang','','[]','左憲多才雄，故人尤鷙鶚。',108,'全唐诗/poet.tang.4000.json','["左憲多才雄，故人尤鷙鶚。", "護贈單于使，休軺太原郭。", "館次厭煩歊，清懷尋寂寞。", "西緣十里餘，北上開化閣。", "初入雲樹間，冥蒙未昭廓。", "漸出欄榥外，萬里秋景焯。", "歲晏風落山，天寒水歸壑。", "覽物頌幽景，三乘動玄鑰。", "但敷利解言，永用忘昏著。"]'),
('8859355e-9c33-4bf6-814b-c6b44117ce0c','哭富嘉謨','吳少微','唐','唐诗','tang','','[]','吾友適不死，於戲社稷臣。',120,'全唐诗/poet.tang.4000.json','["吾友適不死，於戲社稷臣。", "直祿非造利，長懷大庇人。", "乃通承明籍，遘此敦牂春。", "藥厲其可畏，皇穹故匪仁。", "疇昔與夫子，孰云異天倫。", "同病一相失，茫茫不重陳。", "子之文章在，其殆尼父新。", "鼓興斡河岳，貞詞毒鬼神。", "可悲不可朽，車輤沒荒榛。", "聖主賢爲寶，吁茲大國貧。"]'),
('91007e81-f7c8-4b65-ad34-6b675260cafa','過漢故城','吳少微','唐','唐诗','tang','','[]','大漢昔未定，強秦猶擅場。',288,'全唐诗/poet.tang.4000.json','["大漢昔未定，強秦猶擅場。", "中原逐鹿罷，高祖鬱龍驤。", "經始謀帝座，茲焉壯未央。", "規模窺棟宇，表裏浚城隍。", "羣后崇長樂，中朝增建章。", "句陳被蘭錡，樂府奏芝房。", "翡翠明珠帳，鴛鴦白玉堂。", "清晨寶鼎食，閑夜鬱金香。", "天馬來東道，佳人傾北方。", "何其赫隆盛，自謂寶靈長。", "歷數有時盡，哀平嗟不昌。", "冰堅成巨猾，火德遂頹綱。", "奧位匪虛校，貪天竟速亡。", "魂神吁社稷，豹虎鬬巖廊。", "金狄移灞岸，銅盤向洛陽。", "君王無處所，年代幾荒涼。", "宮闕誰家域，蓁蕪罥我裳。", "井田唯有草，海水變爲桑。", "昔在高門內，於今岐路傍。", "餘基不可識，古墓列成行。", "狐兔驚魍魎，鴟鳥嚇獝狂。", "空城寒日晚，平野暮雲黃。", "烈烈樊青棘，蕭蕭吹白楊。", "千秋幷萬歲，空使詠歌傷。"]'),
('57d4e416-1f13-41da-897b-7f5718a23836','古意','吳少微','唐','唐诗','tang','','[]','洛陽芳樹向春開，洛陽女兒平旦來。',188,'全唐诗/poet.tang.4000.json','["洛陽芳樹向春開，洛陽女兒平旦來。", "流車走馬紛相催，折芳瑤華向曲臺。", "曲臺自有千萬行，重花累葉間垂楊。", "北林朝日境明光，南國微風蘇合香。", "可憐窈窕女，不作邯鄲娼。", "妙舞輕迴拂長袖，高歌浩唱發清商。", "歌終舞罷歡無極，樂往悲來長歎息。", "陽春白日不少留，紅榮碧樹無顏色。", "碧樹風花先春度，珠簾粉澤無人顧。", "如何年少忽遲暮，坐見明月與白露。", "明月白露夜已寒，香衣錦帶空珊珊。", "今日陽春一妙曲，鳳皇樓上與君彈。"]'),
('76047f2a-d0f6-457f-b380-35fe7284d4ee','怨歌行','吳少微','唐','唐诗','tang','','[]','城南有怨婦，含情傍芳叢。',200,'全唐诗/poet.tang.4000.json','["城南有怨婦，含情傍芳叢。", "自謂二八時，歌舞入漢宮。", "皇恩數流眄，承幸玉堂中。", "綠柏黃花催夜酒，錦衣羅袂逐春風。", "建章西宮煥若神，燕趙美女三千人。", "君王厭德不忘新，況羣豔冶紛來陳。", "是時別君不再見，三十三春長信殿。", "長信重門晝掩關，清房曉帳幽且閑。", "綺窗蟲網氛塵色，文軒鶯對桃李顏。", "天王貴宮不貯老，浩然含淚今來還。", "自憐春色轉晚暮，試逐佳遊芳草路。", "小腰麗女奪人奇，金鞍少年曾不顧。", "歸來誰爲夫，請謝西家婦，莫辭先醉解羅襦。"]'),
('51a031cf-0f72-4576-be02-62df9cda926d','隴頭水','員半千','唐','唐诗','tang','','[]','路出金河道，山連玉塞門。',84,'全唐诗/poet.tang.4000.json','["路出金河道，山連玉塞門。", "旌旗雲裏度，楊柳曲中喧。", "喋血多壯膽，裹革無怯魂。", "嚴霜斂曙色，大明辭朝暾。", "塵銷營卒壘，沙靜都尉垣。", "霧卷白山出，風吹黃葉翻。", "將軍獻凱入，萬里絕河源。"]'),
('ed8fe393-3b9b-438f-936b-2e72c643bf1b','隴右途中遭非語','員半千','唐','唐诗','tang','','[]','趙有兩毛遂，魯聞二曾參。',84,'全唐诗/poet.tang.4000.json','["趙有兩毛遂，魯聞二曾參。", "慈母猶且惑，況在行路心。", "冠冕無醜士，賄賂成知己。", "名利我所無，清濁誰見理。", "敝服空逢春，緩帶不著身。", "出遊非懷璧，何憂乎忌人。", "正須自保愛，振衣出世塵。"]'),
('cf27e078-1669-4e63-a681-41d87d7b94d2','儀坤廟樂章','員半千','唐','唐诗','tang','','[]','孝享云畢，維徹有章。',40,'全唐诗/poet.tang.4000.json','["孝享云畢，維徹有章。", "雲感玄羽，風悽素商。", "瞻望神座，祗戀匪遑。", "禮終樂闋，肅雍鏘鏘。"]'),
('b9cecb8a-54c8-440f-a3a4-a711202850bc','銅雀妓','王適','唐','唐诗','tang','','[]','日暮銅雀迥，秋深玉座清。',36,'全唐诗/poet.tang.4000.json','["日暮銅雀迥，秋深玉座清。", "蕭森松柏望，委鬱綺羅情。", "君恩不再得，妾舞爲誰輕。"]'),
('6e773ef3-478a-4fe3-9a7c-a1ddd8a2caa7','蜀中言懷','王適','唐','唐诗','tang','','[]','獨坐年將暮，常懷志不通。',96,'全唐诗/poet.tang.4000.json','["獨坐年將暮，常懷志不通。", "有時須問影，無事却書空。", "棄置如天外，平生似夢中。", "蓬心猶是客，華髪欲成翁。", "跡滯魂逾窘，情乖路轉窮。", "別離同夜月，愁思隔秋風。", "老少悲顏駟，盈虛悟翟公。", "時來不可問，何用求童蒙。"]'),
('34c2bd65-0b20-4b61-8fe1-9c70b4e191c3','古別離','王適','唐','唐诗','tang','','[]','昔歲驚楊柳，高樓悲獨守。',112,'全唐诗/poet.tang.4000.json','["昔歲驚楊柳，高樓悲獨守。", "今年芳樹枝，孤棲怨別離。", "珠簾晝不捲，羅幔曉長垂。", "苦調琴先覺，愁容鏡獨知。", "頻年雁度無消息，罷却鴛文何用織。", "夜還羅帳空有情，春著裙腰自無力。", "青軒桃李落紛紛，紫庭蘭蕙日氛氳。", "已能顦顇今如此，更復含情一待君。"]'),
('0042a9c3-0d24-4b44-9608-732348faecf0','江上有懷','王適','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','湛湛江水見底清，荷花蓮子傍江生。',112,'全唐诗/poet.tang.4000.json','["湛湛江水見底清，荷花蓮子傍江生。", "採蓮將欲寄同心，秋風落花空復情。", "櫂歌數曲如有待，正見明月度東海。", "海上雲盡月蒼蒼，萬里分輝滿洛陽。", "洛陽閨閣夜何央，蛾眉嬋娟斷人腸。", "寂寥金屏空自掩，青熒銀燭不生光。", "應憐水宿洞庭子，今夕迢遙天一方。"]'),
('c5d08d5e-6f13-45ed-8101-98ef0419e731','江濱梅','王適','唐','唐诗','tang','','[]','忽見寒梅樹，開花漢水濱。',24,'全唐诗/poet.tang.4000.json','["忽見寒梅樹，開花漢水濱。", "不知春色早，疑是弄珠人。"]'),
('65548834-51ec-42e7-b432-ba56a19cbfcb','臨水亭','王適','唐','唐诗','tang','','[]','高館基曾山，微冪生花草。',72,'全唐诗/poet.tang.4000.json','["高館基曾山，微冪生花草。", "傍對野村樹，下臨車馬道。", "清朗悟心術，幽遐備瞻討。", "迴合峰隱雲，聯綿渚縈島。", "氣似滄洲勝，風爲青春好。", "相及盛年時，無令歎衰老。"]'),
('f06bc194-a7e1-4261-b917-b2a79f083986','長門怨','齊澣','唐','唐诗','tang','','[]','煢煢孤思逼，寂寂長門夜。',48,'全唐诗/poet.tang.4000.json','["煢煢孤思逼，寂寂長門夜。", "妾妬亦知非，君恩那不借。", "携琴就玉階，調悲聲未諧。", "將心託明月，流影入君懷。"]'),
('5fe78b47-8cb5-4763-8f7c-87662b26ccce','長門怨','齊澣','唐','唐诗','tang','','[]','宮殿沈沈月欲分，昭陽更漏不堪聞。',32,'全唐诗/poet.tang.4000.json','["宮殿沈沈月欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。"]'),
('5045c7a4-8388-47d9-b8ad-516e255c2d4f','儀坤廟樂章','祝欽明','唐','唐诗','tang','','[]','閟宮實實，清廟微微。',40,'全唐诗/poet.tang.4000.json','["閟宮實實，清廟微微。", "降格無象，馨香有依。", "式昭纂慶，方融嗣徽。", "明禋是享，神保聿歸。"]'),
('f7509608-6faf-438f-ac08-22ab7889154a','儀坤廟樂章','劉知幾','唐','唐诗','tang','','[]','妙算申帷幄，神謀出廟廷。',48,'全唐诗/poet.tang.4000.json','["妙算申帷幄，神謀出廟廷。", "兩階文物備，七德武功成。", "校獵長楊苑，屯軍細柳營。", "將軍獻凱入，歌舞溢重城。"]'),
('660de777-d35e-41d3-8996-a950d35f3fd3','儀坤廟樂章','胡雄','唐','唐诗','tang','','[]','送文迎武遞參差，一始一終光聖儀。',32,'全唐诗/poet.tang.4000.json','["送文迎武遞參差，一始一終光聖儀。", "四海生人歌有慶，千齡孝享肅無虧。"]'),
('58db30dd-65ce-4698-9114-768e30a701d4','儀坤廟樂章','張齊賢','唐','唐诗','tang','','[]','祼圭既濯，鬱鬯既陳。',40,'全唐诗/poet.tang.4000.json','["祼圭既濯，鬱鬯既陳。", "畫幕雲舉，黃流玉醇。", "儀充獻酌，禮盛衆禋。", "地察惟孝，愉焉饗親。"]'),
('ba397c45-7777-4d86-838d-9863589f93d6','儀坤廟樂章','鄭善玉','唐','唐诗','tang','','[]','酌鬱既灌，取蕭方爇。',40,'全唐诗/poet.tang.4000.json','["酌鬱既灌，取蕭方爇。", "籩豆靜器，簠簋芬飶。", "魚腊薦美，牲牷表絜。", "是戢是將，載迎載列。"]'),
('7aafe3eb-8091-43c2-ac6d-203e85b35862','儀坤廟樂章','丘悅','唐','唐诗','tang','','[]','孝哉我后，沖乎廻聖。',40,'全唐诗/poet.tang.4000.json','["孝哉我后，沖乎廻聖。", "道映重華，德輝文命。", "慕深視篋，情殷撫鏡。", "萬國移命，兆人承慶。"]'),
('74e3640a-e058-4a5d-8352-50f283397d79','芳樹','沈佺期','唐','唐诗','tang','','[]','何地早芳菲，宛在長門殿。',48,'全唐诗/poet.tang.4000.json','["何地早芳菲，宛在長門殿。", "夭桃色若綬，穠李光如練。", "啼鳥弄花疎，遊蜂飲香遍。", "歎息春風起，飄零君不見。"]'),
('7e3ef808-a4d4-4857-8842-a476aaaca79d','長安道','沈佺期','唐','唐诗','tang','','[]','秦地平如掌，層城入雲漢。',48,'全唐诗/poet.tang.4000.json','["秦地平如掌，層城入雲漢。", "樓閣九衢春，車馬千門旦。", "綠槐開復合，紅塵聚還散。", "日晚鬬雞還，經過狹斜看。"]'),
('41a65dc6-9d8b-4775-adec-d4fcfbd7799d','有所思','沈佺期','唐','唐诗','tang','','[]','君子事行役，再空芳歲期。',48,'全唐诗/poet.tang.4000.json','["君子事行役，再空芳歲期。", "美人曠延佇，萬里浮雲思。", "園槿綻紅豔，郊桑柔綠滋。", "坐看長夏晚，秋月照羅幃。"]'),
('381f86a7-ba22-4df3-92ae-f9ffb71fb927','臨高臺','沈佺期','唐','唐诗','tang','','[]','高臺臨廣陌，車馬紛相續。',48,'全唐诗/poet.tang.4000.json','["高臺臨廣陌，車馬紛相續。", "回首思舊鄉，雲山亂心曲。", "遠望河流緩，周看原野綠。", "向夕林鳥還，憂來飛景促。"]'),
('49ea924b-7908-46e4-bdfb-7a80c53bce22','鳳笙曲','沈佺期','唐','唐诗','tang','','[]','憶昔王子晉，鳳笙遊雲空。',48,'全唐诗/poet.tang.4000.json','["憶昔王子晉，鳳笙遊雲空。", "揮手弄白日，安能戀青宮。", "豈無嬋娟子，結念羅幃中。", "憐壽不貴色，身世兩無窮。"]'),
('d469f6eb-475a-4e5a-b1ac-014052ed4c61','擬古別離','沈佺期','唐','唐诗','tang','','[]','白水東悠悠，中有西行舟。',96,'全唐诗/poet.tang.4000.json','["白水東悠悠，中有西行舟。", "舟行有返櫂，水去無還流。", "奈何生別者，戚戚懷遠遊。", "遠遊誰當惜，所悲會難收。", "自君闃芳躧，青陽四五遒。", "皓月掩蘭室，光風虛蕙樓。", "相思無明晦，長歎累冬秋。", "離居久遲暮，高駕何淹留。"]'),
('cbf24b17-cb47-47c8-b196-ce479aec9cf5','辛丑歲十月上幸長安時扈從出西嶽作','沈佺期','唐','唐诗','tang','','["\u534e\u5c71"]','西鎮何穹崇，壯哉信靈造。',156,'全唐诗/poet.tang.4000.json','["西鎮何穹崇，壯哉信靈造。", "諸嶺皆峻秀，中峯特美好。", "傍見巨掌存，勢如石東倒。", "頗聞首陽去，開坼此河道。", "磅礴壓洪源，巍峨壯清昊。", "雲泉紛亂瀑，天磴屹橫抱。", "子先呼其巔，宮女世不老。", "下有府君廟，歷載傳灑掃。", "皇明應天游，十月戒豐鎬。", "微未忝閑從，兼得事蘋藻。", "宿心愛茲山，意欲拾靈草。", "陰壑已永閟，雲竇絕探討。", "芳月期來過，迴策思方浩。"]'),
('da142b5b-c436-4971-a3cb-04ded1b99ab4','和杜麟臺元志春情','沈佺期','唐','唐诗','tang','','[]','嘉樹滿中園，氛氳羅秀色。',60,'全唐诗/poet.tang.4000.json','["嘉樹滿中園，氛氳羅秀色。", "不見仙山雲，倚琴空太息。", "沈思若在夢，緘怨似無憶。", "青春坐南移，白日忽西匿。", "蛾眉返清鏡，閨中不相識。"]'),
('56d6a45a-5af7-4be8-93e7-0c0bc3cbf45d','別侍御嚴凝','沈佺期','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','七澤雲夢林，三湘洞庭水。',48,'全唐诗/poet.tang.4000.json','["七澤雲夢林，三湘洞庭水。", "自古傳剽俗，有時逋惡子。", "令君出使車，行邁方靡靡。", "靜言芟枳棘，慎勿傷蘭芷。"]'),
('6a737f68-49fd-467f-94f4-9fd5361dae18','送喬隨州侃','沈佺期','唐','唐诗','tang','','[]','結交三十載，同遊一萬里。',48,'全唐诗/poet.tang.4000.json','["結交三十載，同遊一萬里。", "情爲契闊生，心由別離死。", "拜恩前後人，從宦差池起。", "今爾歸漢東，明珠報知己。"]'),
('0742ebdb-3596-49bb-ac05-b19d047e0d44','送友人任括州','沈佺期','唐','唐诗','tang','','[]','青春浩無際，白日乃遲遲。',72,'全唐诗/poet.tang.4000.json','["青春浩無際，白日乃遲遲。", "胡爲賞心客，歎邁此芳時。", "甌粵迫茲守，京闕從此辭。", "茫茫理雲帆，草草念行期。", "紛吾結遠佩，帳餞出河湄。", "太息東流水，盈觴難再持。"]'),
('d245ffa8-eb68-49ee-b6e1-f6608fdc13f3','餞遠','沈佺期','唐','唐诗','tang','','[]','任子徇遐祿，結友開舊襟。',48,'全唐诗/poet.tang.4000.json','["任子徇遐祿，結友開舊襟。", "撰酌輟行歎，指途勤遠心。", "秋皛澄回壑，霽色肅明林。", "曖然青軒暮，浩思非所任。"]'),
('b024c8a6-7721-4908-81f1-29afb3163ae5','同工部李侍郎適訪司馬子微','沈佺期','唐','唐诗','tang','','[]','紫微降天仙，丹地投雲藻。',180,'全唐诗/poet.tang.4000.json','["紫微降天仙，丹地投雲藻。", "上言華頂事，中問長生道。", "華頂居最高，大壑朝陽早。", "長生術何妙，童顏後天老。", "清晨朝鳳京，靜夜思鴻寶。", "憑崖飲蕙氣，過澗摘靈草。", "人非冢已荒，海變田應燥。", "昔嘗遊此郡，三霜弄溟島。", "緒言霞上開，機事塵外掃。", "頃來迫世務，清曠未云保。", "崎嶇待漏恩，怵惕司言造。", "軒皇重齋拜，漢武愛祈禱。", "順風懷崆峒，承露在豐鎬。", "泠然魏輕馭，復得散幽抱。", "柱下留伯陽，儲闈登四皓。"]'),
('099c950a-b58f-48dd-ab8d-22c228b092ee','自昌樂郡泝流至白石嶺下行入郴州','沈佺期','唐','唐诗','tang','','[]','茲山界夷夏，天險橫寥廓。',192,'全唐诗/poet.tang.4000.json','["茲山界夷夏，天險橫寥廓。", "太史漏登探，文命限開鑿。", "北流自南瀉，羣峰回衆壑。", "馳波如電騰，激石似雷落。", "崖留盤古樹，澗蓄神農藥。", "乳竇何淋漓，苔蘚更彩錯。", "娟娟潭裏虹，渺渺灘邊鶴。", "歲杪應流火，天高雲物薄。", "金風吹綠梢，玉露洗紅籜。", "泝舟始興廨，登踐桂陽郭。", "匍匐緣修坂，穹窿曳長䋏。", "礙林阻往來，遇堰每前却。", "救艱不遑飯，畢昏無暇泊。", "濯溪寧足懼，磴道誰云惡。", "我行山水間，湍險皆不若。", "安能獨見聞，書此貽京洛。"]'),
('bb80e9ef-e078-4ae2-8502-7f344d5fc05d','過蜀龍門','沈佺期','唐','唐诗','tang','','[]','龍門非禹鑿，詭怪乃天功。',108,'全唐诗/poet.tang.4000.json','["龍門非禹鑿，詭怪乃天功。", "西南出巴峽，不與衆山同。", "長竇亙五里，宛轉復嵌空。", "伏湍喣潛石，瀑水生輪風。", "流水無晝夜，噴薄龍門中。", "潭河勢不測，藻葩垂彩虹。", "我行當季月，煙景共舂融。", "江關勤亦甚，巘崿意難窮。", "勢將息機事，煉藥此山東。"]'),
('d31eab78-1b8f-478b-871c-a88b09e0df70','入衞作','沈佺期','唐','唐诗','tang','','[]','淇上風日好，紛紛沿岸多。',48,'全唐诗/poet.tang.4000.json','["淇上風日好，紛紛沿岸多。", "綠芳幸未歇，泛濫此明波。", "采蘩憶幽吹，理棹想荆歌。", "鬱然懷君子，浩曠將如何。"]'),
('947651ac-32b6-4430-9031-039709b86c2d','蝴蝶二首 一','徐夤','唐','唐诗','tang','','[]','縹緲青蟲脫殼微，不堪煙重雨霏霏。',64,'全唐诗/poet.tang.40000.json','["縹緲青蟲脫殼微，不堪煙重雨霏霏。", "一枝穠豔留教住，幾處春風借與飛。", "防患每憂雞雀口，憐香偏遶綺羅衣。", "無情豈解關魂夢，莫信莊周說是非。"]'),
('b0c29180-d7e6-444c-95db-44d2d203a830','蝴蝶二首 二','徐夤','唐','唐诗','tang','','[]','拂綠穿紅麗日長，一生心事住春光。',64,'全唐诗/poet.tang.40000.json','["拂綠穿紅麗日長，一生心事住春光。", "最嫌神女來行雨，愛伴西施去採香。", "風定只應攢蘂粉，夜寒長是宿花房。", "鳴蟬性分殊迂闊，空解三秋噪夕陽。"]'),
('5a83e700-8951-469d-ba56-5be416c33d45','郡侯坐上觀琉璃瓶中遊魚','徐夤','唐','唐诗','tang','','[]','寶器一泓銀漢水，錦鱗纔動即先知。',64,'全唐诗/poet.tang.40000.json','["寶器一泓銀漢水，錦鱗纔動即先知。", "似涵明月波寧隔，欲上輕冰律未移。", "薄霧罩來分咫尺，碧綃籠處較毫釐。", "文翁未得沈香餌，擬置金盤召左慈。"]'),
('94d01774-e25a-4321-9fb0-a91a15cd1e39','翦刀','徐夤','唐','唐诗','tang','','[]','寶持多用繡爲囊，雙日交加兩鬢霜。',64,'全唐诗/poet.tang.40000.json','["寶持多用繡爲囊，雙日交加兩鬢霜。", "金匣掠平花翡翠，綠窗裁破錦鴛鴦。", "初栽連理枝猶短，誤綰同心帶不長。", "欲製緼袍先把看，質非紈綺愧銛鋩。"]'),
('341affc4-7db1-4ec9-ac5f-06aceca64739','紙被','徐夤','唐','唐诗','tang','','[]','文采鴛鴦罷合歡，細柔輕綴好魚牋。',64,'全唐诗/poet.tang.40000.json','["文采鴛鴦罷合歡，細柔輕綴好魚牋。", "一牀明月蓋歸夢，數尺白雲籠冷眠。", "披對勁風溫勝酒，擁聽寒風暖于綿。", "赤眉豪客見皆笑，却問儒生直幾錢。"]'),
('09a007ca-cb53-423d-b6c7-0e0c9db4b660','紙帳','徐夤','唐','唐诗','tang','','[]','幾笑文園四壁空，避寒深入剡藤中。',64,'全唐诗/poet.tang.40000.json','["幾笑文園四壁空，避寒深入剡藤中。", "誤懸謝守澄江練，自宿嫦娥白兔宮。", "幾疊玉山開洞壑，半巖春霧結房櫳。", "針羅截錦饒君侈，爭及蒙茸煖避風。"]'),
('71a5306f-e35c-4713-9ad4-c7e0a9fa62e6','貢餘秘色茶盞','徐夤','唐','唐诗','tang','','[]','捩翠融青瑞色新，陶成先得貢吾君。',64,'全唐诗/poet.tang.40000.json','["捩翠融青瑞色新，陶成先得貢吾君。", "功剜明月染春水，輕旋薄冰盛綠雲。", "古鏡破苔當席上，嫩荷涵露別江濆。", "中山竹葉醅初發，多病那堪中十分。"]'),
('0db00e55-df80-46b6-82ef-9290e4db7084','筍鞭','徐夤','唐','唐诗','tang','','[]','筇竹岩邊剔翠苔，錦江波冷洗瓊瑰。',64,'全唐诗/poet.tang.40000.json','["筇竹岩邊剔翠苔，錦江波冷洗瓊瑰。", "纍纍節轉蒼龍骨，寸寸珠聯巨蚌胎。", "須向廣場驅駔駿，莫從閑處撻駑駘。", "寧同晉帝環營日，拋賺中途後騎來。"]'),
('5cef1f4e-af27-46dc-bd13-474b521212a1','詠簾','徐夤','唐','唐诗','tang','','[]','素節輕盈珠影勻，何人巧思間成文。',64,'全唐诗/poet.tang.40000.json','["素節輕盈珠影勻，何人巧思間成文。", "閑垂別殿風應度，半掩行宮麝欲薰。", "繡戶遠籠寒焰重，玉樓高挂曙光分。", "無情幾恨黃昏月，纔到如鉤便墮雲。"]'),
('fbbcc453-1e0b-4a6b-acf2-8effd16dab6c','詠燈','徐夤','唐','唐诗','tang','','[]','分影由來恨不同，綠窗孤館兩何窮。',64,'全唐诗/poet.tang.40000.json','["分影由來恨不同，綠窗孤館兩何窮。", "熒煌短焰長疑暗，零落殘花旋委空。", "幾處隔簾愁夜雨，誰家當戶怯秋風。", "莫言明滅無多事，曾比人生一世中。"]'),
('742f5e6f-b1eb-46d0-b3c7-e530d3aac46d','詠扇','徐夤','唐','唐诗','tang','','[]','爲發涼飆滿玉堂，每親襟袖便難忘。',64,'全唐诗/poet.tang.40000.json','["爲發涼飆滿玉堂，每親襟袖便難忘。", "霜濃雪暗知何在，道契時來忽自揚。", "曾伴一樽臨小檻，幾遮殘日過回廊。", "漢宮如有秋風起，誰信班姬淚數行。"]'),
('c9324b0c-06db-4ba1-bb4e-3471eeab042e','詠筆二首 一','徐夤','唐','唐诗','tang','','[]','秦代將軍欲建功，截龍搜兔助英雄。',64,'全唐诗/poet.tang.40000.json','["秦代將軍欲建功，截龍搜兔助英雄。", "用多誰念毛皆拔，拋却更嫌心不中。", "史氏只應歸道直，江淹何獨偶靈通。", "班超握管不成事，投擲翻從萬里戎。"]'),
('5e9b92f4-22f9-478e-9ba1-494daf6d9a85','詠筆二首 二','徐夤','唐','唐诗','tang','','[]','君子三歸擅一名，秋毫雖細握非輕。',64,'全唐诗/poet.tang.40000.json','["君子三歸擅一名，秋毫雖細握非輕。", "軍書羽檄教誰錄，帝命王言待我成。", "勢健豈饒淝水陣，鋒銛還學歷山耕。", "毛乾時有何人潤，盡把燒焚恨始平。"]'),
('433d77c8-3db1-4309-af05-017cc063c435','詠錢','徐夤','唐','唐诗','tang','','[]','多蓄多藏豈足論，有誰還議濟王孫。',64,'全唐诗/poet.tang.40000.json','["多蓄多藏豈足論，有誰還議濟王孫。", "能於禍處翻爲福，解向讐家買得恩。", "幾怪鄧通難免餓，須知夷甫不曾言。", "朝爭暮競歸何處，盡入權門與倖門。"]'),
('9ba811e7-90f4-4d72-9ac1-e9d94d246ffd','尚書筵中詠紅手帕','徐夤','唐','唐诗','tang','','[]','鶴綾三尺曉霞濃，送與東家二八容。',64,'全唐诗/poet.tang.40000.json','["鶴綾三尺曉霞濃，送與東家二八容。", "羅帶繡裙輕好繫，藕絲紅縷細初縫。", "別來拭淚遮桃臉，行去包香墜粉胸。", "無事把將纏皓腕，爲君池上折芙蓉。"]'),
('ba028a2f-decc-4bfb-abe3-15ab300eb410','尚書新造花箋','徐夤','唐','唐诗','tang','','[]','濃染紅桃二月花，只宜神筆縱龍蛇。',64,'全唐诗/poet.tang.40000.json','["濃染紅桃二月花，只宜神筆縱龍蛇。", "淺澄秋水看雲母，碎擘輕苔間粉霞。", "寫賦好追陳后寵，題詩堪送竇滔家。", "使君即入金鑾殿，夜直無非草白麻。"]'),
('558d3007-ac7a-4a3b-9382-2a8cdec48c7e','釣車','徐夤','唐','唐诗','tang','','[]','荻灣漁客巧妝成，硾鑄銀星一點輕。',66,'全唐诗/poet.tang.40000.json','["荻灣漁客巧妝成，硾鑄銀星一點輕。", "拋過碧江鸂[鶒]岸，軋殘金井轆轤聲。", "軸磨騂角冰光滑，輪卷春絲水面平。", "把向嚴灘尋轍迹，漁臺基在輾難傾。"]'),
('7569631f-f6d7-44a3-afc1-1232f89d2347','柳','徐夤','唐','唐诗','tang','','[]','漠漠金條引線微，年年先翠報春歸。',64,'全唐诗/poet.tang.40000.json','["漠漠金條引線微，年年先翠報春歸。", "解籠飛靄延芳景，不逐亂花飄夕暉。", "啼鳥噪蟬堪悵望，舞煙搖水自因依。", "五株名顯陶家後，見說辭榮種者稀。"]'),
('a59429c9-5135-438d-ba1b-6463f8f1fc50','愁','徐夤','唐','唐诗','tang','','[]','夜長偏覺漏聲遲，往往隨歌慘翠眉。',64,'全唐诗/poet.tang.40000.json','["夜長偏覺漏聲遲，往往隨歌慘翠眉。", "黃葉落催砧杵日，子規啼破夢魂時。", "明妃去泣千行淚，蔡琰歸梳兩鬢絲。", "四皓入山招不得，無家歸客最堪欺。"]'),
('2e92f082-c8a6-4012-9ef8-b9d1f738d50c','草','徐夤','唐','唐诗','tang','','[]','廢苑荒堦伴綠苔，恩疎長信恨難開。',64,'全唐诗/poet.tang.40000.json','["廢苑荒堦伴綠苔，恩疎長信恨難開。", "姑蘇麋鹿食思食，楚澤王孫來不來。", "色嫩似將藍汁染，葉齊如把翦刀裁。", "燕昭沒後多卿士，千載流芳郭隗臺。"]'),
('ba1b61cb-3102-490f-babe-eca519dd4aed','螢','徐夤','唐','唐诗','tang','','[]','月墜西樓夜影空，透簾穿幕達房櫳。',64,'全唐诗/poet.tang.40000.json','["月墜西樓夜影空，透簾穿幕達房櫳。", "流光堪在珠璣列，爲火不生榆柳中。", "一一照通黃卷字，輕輕化出綠蕪叢。", "欲知應候何時節，六月初迎大暑風。"]'),
('0df790bb-c6f4-41f1-9215-3c3b08fe9702','水','徐夤','唐','唐诗','tang','','[]','火性何如水性柔，西來東出幾時休。',64,'全唐诗/poet.tang.40000.json','["火性何如水性柔，西來東出幾時休。", "莫言通海能通漢，雖解浮舟也覆舟。", "湘浦暮沈堯女怨，汾河秋泛漢皇愁。", "洪波激湍歸何處，二月桃花滿眼流。"]'),
('9b75ba23-d671-4e34-a122-d418f6196cea','苔','徐夤','唐','唐诗','tang','','[]','印留麋鹿野禽蹤，岩壁漁磯幾處逢。',64,'全唐诗/poet.tang.40000.json','["印留麋鹿野禽蹤，岩壁漁磯幾處逢。", "金谷曉凝花影重，章華春映柳陰濃。", "石橋羽客遺前迹，陳閣才人沒舊容。", "歸去掃除階砌下，蘚痕殘綠一重重。"]'),
('9fe7f7a5-d731-4c61-a355-d372e2503401','曉','徐夤','唐','唐诗','tang','','[]','水盡銅龍滴漸微，景陽鍾動夢魂飛。',64,'全唐诗/poet.tang.40000.json','["水盡銅龍滴漸微，景陽鍾動夢魂飛。", "潼關雞唱促歸騎，金殿燭殘求御衣。", "窗下寒機猶自織，梁間棲燕欲雙飛。", "羲和晴聳扶桑轡，借與寰瀛看早暉。"]'),
('059c7799-21ec-43fc-b21f-96d763b83f58','別','徐夤','唐','唐诗','tang','','[]','酒盡歌終問後期，泛萍浮梗不勝悲。',64,'全唐诗/poet.tang.40000.json','["酒盡歌終問後期，泛萍浮梗不勝悲。", "東門匹馬夜歸處，南浦片帆飛去時。", "賦罷江淹吟更苦，詩成蘇武思何遲。", "可憐范陸分襟後，空折梅花寄所思。"]'),
('1309b952-d792-4b93-805e-6808995b66cb','夜','徐夤','唐','唐诗','tang','','[]','日墜虞淵燭影開，沈沈煙霧壓浮埃。',64,'全唐诗/poet.tang.40000.json','["日墜虞淵燭影開，沈沈煙霧壓浮埃。", "剡川雪滿子猷去，漢殿月生王母來。", "簷挂蛛絲應漸織，風吹螢火不成灰。", "愁人莫道何時旦，自有鐘鳴漏滴催。"]'),
('a638f6e8-ba9f-48fa-ba33-e23c8e4d71b2','雨','徐夤','唐','唐诗','tang','','[]','引電隨龍密又輕，酒桮閑噀得嘉名。',64,'全唐诗/poet.tang.40000.json','["引電隨龍密又輕，酒桮閑噀得嘉名。", "千山草木如雲暗，陸地波瀾接海平。", "灑竹幾添春睡重，滴簷偏遣夜愁生。", "陰妖冷孽成何怪，敢蔽高天日月明。"]'),
('8964b7f8-ac21-4c55-96db-49c87448374c','萍','徐夤','唐','唐诗','tang','','[]','爲實隨流瑞色新，泛風縈草護遊鱗。',64,'全唐诗/poet.tang.40000.json','["爲實隨流瑞色新，泛風縈草護遊鱗。", "密行碧水澄涵月，澁滯輕橈去採蘋。", "比物何名腰下劍，無根堪並鏡中身。", "平湖春渚知何限，撥破閑投獨繭綸。"]'),
('250b1806-8ee3-450e-8c86-906e9ef8dce9','恨','徐夤','唐','唐诗','tang','','[]','事與時違不自由，如燒如刺寸心頭。',64,'全唐诗/poet.tang.40000.json','["事與時違不自由，如燒如刺寸心頭。", "烏江項籍忍歸去，雁塞李陵長繫留。", "燕國飛霜將破夏，漢宮紈扇豈禁秋。", "須知入骨難銷處，莫比人間取次愁。"]'),
('7a59df1c-4d29-4b51-9735-18f6d19735f5','鴻','徐夤','唐','唐诗','tang','','[]','行如兄弟影連空，春去秋來燕不同。',64,'全唐诗/poet.tang.40000.json','["行如兄弟影連空，春去秋來燕不同。", "紫塞別當秋露白，碧山飛入暮霞紅。", "宣王德美周詩內，蘇武書傳漢苑中。", "況解銜蘆避弓箭，一聲歸唳楚天風。"]'),
('dff41a7a-2867-45c7-9729-269a5ecce6c1','鶴','徐夤','唐','唐诗','tang','','[]','閬苑瑤臺歲月長，一歸華表好增傷。',64,'全唐诗/poet.tang.40000.json','["閬苑瑤臺歲月長，一歸華表好增傷。", "新聲乍警初零露，折羽閑飛幾片霜。", "要伴神仙歸碧落，豈隨龜雁住方塘。", "三山頂上無人處，瓊樹堪巢不死鄉。"]'),
('e5afcb7b-0593-44de-a08c-a9269a51c1c5','鵲','徐夤','唐','唐诗','tang','','[]','神化難源瑞即開，雕陵毛羽出塵埃。',64,'全唐诗/poet.tang.40000.json','["神化難源瑞即開，雕陵毛羽出塵埃。", "香閨報喜行人至，碧漢填河織女回。", "明月解隨烏繞樹，青銅寧愧雀爲臺。", "瓊枝翠葉庭前植，從待翩翩去又來。"]'),
('a6a540fd-84b5-4666-885b-2620ec8c33ac','霜','徐夤','唐','唐诗','tang','','[]','應節誰窮造化端，菊黃豺祭問應難。',64,'全唐诗/poet.tang.40000.json','["應節誰窮造化端，菊黃豺祭問應難。", "紅窗透出鴛衾冷，白草飛時雁塞寒。", "露結芝蘭瓊屑厚，日乾葵藿粉痕殘。", "世間無比催搖落，松竹何人肯更看。"]'),
('36db4d01-5eb0-4d46-b986-723c3bb36ab8','風','徐夤','唐','唐诗','tang','','[]','城上寒來思莫窮，土囊萍末兩難同。',64,'全唐诗/poet.tang.40000.json','["城上寒來思莫窮，土囊萍末兩難同。", "飄成遠浪江湖際，吹起暮塵京洛中。", "飛雪蕭條殘臘節，落花狼藉古行宮。", "春能和煦秋搖落，生殺還同造化功。"]'),
('f3da03a3-79d5-4ec4-a2ea-6b8586c323be','帆','徐夤','唐','唐诗','tang','','[]','豈勞孤棹送行舟，輕過天涯勢未休。',64,'全唐诗/poet.tang.40000.json','["豈勞孤棹送行舟，輕過天涯勢未休。", "斷岸曉看殘月挂，遠灣寒背夕陽收。", "川平直可追飛箭，風健還能泝急流。", "幸遇濟川恩不淺，北溟東海更何愁。"]'),
('6fff6bc0-28cd-4ade-b329-aef5f1fb8f91','夢','徐夤','唐','唐诗','tang','','[]','月落燈前閉北堂，神魂交入杳冥鄉。',64,'全唐诗/poet.tang.40000.json','["月落燈前閉北堂，神魂交入杳冥鄉。", "文通毫管醒來異，武帝蘅蕪覺後香。", "傅說已徴賢可輔，周公不見恨何長。", "生松十八年方應，通塞人間豈合忙。"]'),
('69efbeef-7563-46c6-9dab-f919f1de2aeb','東','徐夤','唐','唐诗','tang','','[]','紫氣天元出故關，大明先照九垓間。',64,'全唐诗/poet.tang.40000.json','["紫氣天元出故關，大明先照九垓間。", "鰲山海上秦娥去，鱸鱠江邊齊掾還。", "青帝郊坰平似砥，主人階級峻如山。", "蟠桃樹在煙濤水，解凍風高未得攀。"]'),
('8987a0f6-a89c-4224-a462-67cb9e1a7282','西','徐夤','唐','唐诗','tang','','[]','密雲郊外已回秋，日下崦嵫景懶收。',64,'全唐诗/poet.tang.40000.json','["密雲郊外已回秋，日下崦嵫景懶收。", "秦帝城高堅似鐵，李斯書上曲如鉤。", "寧惟東岳凌天秀，更有長庚瞰曙流。", "見說山傍偏出將，犬戎降盡復何愁。"]'),
('77c55f66-4fa7-41a5-9849-8a1e23cb0899','南','徐夤','唐','唐诗','tang','','[]','罩罩嘉魚憶此方，送君前浦恨難量。',64,'全唐诗/poet.tang.40000.json','["罩罩嘉魚憶此方，送君前浦恨難量。", "火山遠照蒼梧郡，銅柱高標碧海鄉。", "陸賈幾時來越島，三閭何日濯滄浪。", "鍾儀冠帶歸心阻，蝴蝶飛園萬草芳。"]'),
('b5c207ff-14dd-4c42-9097-519e8d4bd021','北','徐夤','唐','唐诗','tang','','[]','雪滿湖天日影微，李君降虜失良時。',66,'全唐诗/poet.tang.40000.json','["雪滿湖天日影微，李君降虜失良時。", "窮溟駕浪鵾鵬化，極海寄書鴻雁遲。", "□□□來猶未啓，殘兵奔去杳難追。", "可憐燕谷花[開]晚，鄒律如何爲一吹。"]'),
('12add4a4-08f7-4e0b-89e0-4dd7adb9aee1','雲','徐夤','唐','唐诗','tang','','[]','漠漠沈沈向夕暉，蒼梧巫峽兩相依。',64,'全唐诗/poet.tang.40000.json','["漠漠沈沈向夕暉，蒼梧巫峽兩相依。", "天心白日休空蔽，海上故山應自歸。", "似蓋好臨千乘載，如羅堪翦六銖衣。", "爲霖須救蒼生旱，莫向西郊作雨稀。"]'),
('7e90f29e-1ec0-4b6f-b0b5-27b6fe4838d6','燕','徐夤','唐','唐诗','tang','','[]','從待銜泥濺客衣，百禽靈性比他稀。',64,'全唐诗/poet.tang.40000.json','["從待銜泥濺客衣，百禽靈性比他稀。", "何嫌何恨秋須去，無約無期春自歸。", "鵰鶚不容應不怪，棟梁相庇願相依。", "吳王宮女嬌相襲，合整雙毛預奮飛。"]'),
('2c2d3acc-c0ae-4c3f-a078-3e36d2de16db','蟬','徐夤','唐','唐诗','tang','','[]','寒鳴寧與衆蟲同，翼鬢緌冠豈道窮。',64,'全唐诗/poet.tang.40000.json','["寒鳴寧與衆蟲同，翼鬢緌冠豈道窮。", "殼蛻已從今日化，聲愁何似去年中。", "朝催籬菊花開露，暮促庭槐葉墜風。", "從此最能驚賦客，計居何處轉飛蓬。"]'),
('5d6ae932-1ab4-4689-bf8a-279b4a398ad0','露','徐夤','唐','唐诗','tang','','[]','鶴鳴先警雁來天，洗竹沾花處處鮮。',64,'全唐诗/poet.tang.40000.json','["鶴鳴先警雁來天，洗竹沾花處處鮮。", "散綵幾當蟬飲際，凝光宜對蚌胎前。", "朝垂苑草煙猶重，夜滴宮槐月正圓。", "怵惕與霜同降日，蘋蘩思薦獨淒然。"]'),
('1140634f-7b02-43ac-8070-a0a153ca5e9d','霞','徐夤','唐','唐诗','tang','','[]','天際何人濯錦歸，偏宜殘照與晨暉。',64,'全唐诗/poet.tang.40000.json','["天際何人濯錦歸，偏宜殘照與晨暉。", "流爲洞府千年酒，化作靈山幾襲衣。", "野燒燄連殊赫奕，愁雲陰隔乍依稀。", "勞生願學長生術，飡盡紅桃上漢飛。"]'),
('82569b16-e108-4b7e-8aef-4e4a5e03ebad','蒲','徐夤','唐','唐诗','tang','','[]','濯秀盤根在碧流，紫茵含露向晴抽。',64,'全唐诗/poet.tang.40000.json','["濯秀盤根在碧流，紫茵含露向晴抽。", "編爲細履隨君步，織作輕帆送客愁。", "疎葉稍爲投餌釣，密叢還礙採蓮舟。", "鴛鴦鸂鶒多情甚，日日雙雙遶傍游。"]'),
('544cb9f5-860c-4db1-882a-db17e88cd08a','泉','徐夤','唐','唐诗','tang','','[]','非鑿非疏出洞門，源深流嶮合還分。',64,'全唐诗/poet.tang.40000.json','["非鑿非疏出洞門，源深流嶮合還分。", "高成瀑布漱逋客，清入御溝朝聖君。", "迸滴幾山穿破石，迅飛層嶠噴開雲。", "舊齋一帶連松竹，明月窗前枕上聞。"]'),
('bbd0a254-8b3a-4dfc-8c5b-c9460216e963','煙','徐夤','唐','唐诗','tang','','[]','燎野焚林見所從，惹空橫水展形容。',64,'全唐诗/poet.tang.40000.json','["燎野焚林見所從，惹空橫水展形容。", "能滋甘雨隨車潤，不並行雲逐夢蹤。", "晴鳥迴籠嘉樹薄，春亭嬌幕好花濃。", "有時片片風吹去，海碧山清過幾重。"]'),
('dfb2efa4-daf5-4fc9-950f-44e74f85e0dd','閑','徐夤','唐','唐诗','tang','','[]','不管人間是與非，白雲流水自相依。',64,'全唐诗/poet.tang.40000.json','["不管人間是與非，白雲流水自相依。", "一瓢挂樹傲時代，五柳種門吟落暉。", "江上翠娥遺佩去，岸邊紅袖采蓮歸。", "客星辭得漢光武，却坐東江舊蘚磯。"]'),
('dfa8e3ca-57f4-45f8-a40e-87851ed06654','忙','徐夤','唐','唐诗','tang','','[]','雙競龍舟疾似風，一星毬子兩明同。',64,'全唐诗/poet.tang.40000.json','["雙競龍舟疾似風，一星毬子兩明同。", "平吳破蜀三除裏，滅楚圖秦百戰中。", "春近杜鵑啼不斷，寒催歸雁去何窮。", "兵還失路旌旗亂，驚起紅塵似轉蓬。"]'),
('bb339274-d89b-4c79-a113-3d94d0ea5dd4','淚','徐夤','唐','唐诗','tang','','[]','發事牽情不自繇，偶然惆悵即難收。',64,'全唐诗/poet.tang.40000.json','["發事牽情不自繇，偶然惆悵即難收。", "已聞抱玉沾衣濕，見說迷途滿目流。", "滴盡綺筵紅燭暗，墜殘妝閣曉花羞。", "世間何處偏留得，萬點分明湘水頭。"]'),
('7710181b-8ad9-4df0-ab26-5268fe33d0e1','月','徐夤','唐','唐诗','tang','','[]','碧落誰分造化權，結霜凝雪作嬋娟。',64,'全唐诗/poet.tang.40000.json','["碧落誰分造化權，結霜凝雪作嬋娟。", "寒蟬若不開三穴，狡兔何從上九天。", "莫見團圓明處遠，須看灣曲鑒時偏。", "郄詵樹老堯蓂換，惆悵今年似去年。"]'),
('7ccd7aaf-96f3-44c3-85af-055348c1743c','依御史溫飛卿華清宮二十二韻','徐夤','唐','唐诗','tang','','[]','地靈蒸水暖，天氣待宸遊。',264,'全唐诗/poet.tang.40000.json','["地靈蒸水暖，天氣待宸遊。", "嶽拱蓮花秀，峯高玉蘂秋。", "朝元雕翠閣，乞巧繡瓊樓。", "碧海供驪嶺，黃金絡馬頭。", "五王更入帳，七貴迭封侯。", "夕雨鳴鴛瓦，朝陽曄柘裘。", "伊臯爭負鼎，舜禹讓垂旒。", "墮珥閑應拾，遺釵醉不收。", "飛煙籠劍戟，殘月照旌斿。", "履朔求衣早，臨陽解佩羞。", "宮詞裁錦段，御筆落銀鉤。", "帝里新豐縣，長安舊雍州。", "雪衣傳貝葉，蟬鬢插山榴。", "對景瞻瑤兔，昇天駕綵虬。", "丹書陳北虜，玄甲擐犀牛。", "聖誥多屯否，生靈少怨尤。", "穹旻當有輔，帷幄豈無籌。", "鳳態傷紅豔，鸞輿緩紫騮。", "樹名端正在，人欲夢魂休。", "讖語山旁鬼，塵銷隴畔丘。", "重來芳草恨，往事落花愁。", "五十年鴻業，東憑渭水流。"]'),
('6df0c6d1-1aad-45e6-8cad-3241a44e5409','尚書命題瓦硯','徐夤','唐','唐诗','tang','','[]','遠向端溪得，皆因郢匠成。',120,'全唐诗/poet.tang.40000.json','["遠向端溪得，皆因郢匠成。", "鑿山青靄斷，琢石紫花輕。", "散墨松香起，濡毫藻句清。", "入臺知價重，著匣恐塵生。", "守黑還全器，臨池早著名。", "春闈攜就處，軍幕載將行。", "不獨雄文陣，兼能助筆耕。", "莫嫌涓滴潤，深染古今情。", "洗處無瑕玷，添時識滿盈。", "蘭亭如見用，敲戛有金聲。"]'),
('4ed3fb07-b56a-44d5-ab3e-a53ace3f1316','東風解凍省試','徐夤','唐','唐诗','tang','','[]','暖氣飄蘋末，凍痕銷水中。',72,'全唐诗/poet.tang.40000.json','["暖氣飄蘋末，凍痕銷水中。", "扇冰初覺泮，吹海旋成空。", "入律三春照，朝宗萬里通。", "岸分天影闊，色照日光融。", "波起輕搖綠，鱗遊乍躍紅。", "殷勤排弱羽，飛翥趂和風。"]'),
('0fed89cd-90f4-43ea-b83c-7b1aa7283627','和僕射二十四丈牡丹八韻','徐夤','唐','唐诗','tang','','[]','帝王城裏看，無故亦無新。',96,'全唐诗/poet.tang.40000.json','["帝王城裏看，無故亦無新。", "忍摘都緣借，移栽未有因。", "光陰嫌太促，開落一何頻。", "羞殺登墻女，饒將解佩人。", "蘂堪靈鳳啄，香許白龍親。", "素練籠霞曉，紅妝帶臉春。", "莫辭終夕醉，易老少年身。", "買取歸天上，寧教逐世塵。"]'),
('c1430f85-779c-400c-b141-54ea16be439b','釣絲竹','徐夤','唐','唐诗','tang','','[]','藋藋拂清流，堪維舴艋舟。',72,'全唐诗/poet.tang.40000.json','["藋藋拂清流，堪維舴艋舟。", "野蟲懸作餌，溪月曲爲鉤。", "雨潤搖堦長，風吹繞指柔。", "若將諸樹比，還使綠楊羞。", "蠶婦非堯女，漁人是子猷。", "湖邊舊栽處，長映讀書樓。"]'),
('c3d99610-47c1-41ec-80bc-7f16a45a2026','尚書會仙亭詠薔薇夤坐中聯四韻晚歸補緝所聯因成一篇','徐夤','唐','唐诗','tang','','[]','結綠根株翡翠莖，句芒中夜刺猩猩。',160,'全唐诗/poet.tang.40000.json','["結綠根株翡翠莖，句芒中夜刺猩猩。", "景陽妝赴嚴鐘出，楚峽神教暮雨晴。", "躑躅豈能同日語，玫瑰方可一時呈。", "風吹嫩帶香苞展，露灑啼思淚點輕。", "阿母蘂宮期索去，昭君榆塞闕齎行。", "藂高恐礙含泥燕，架隱宜棲報曙鶯。", "鬬日只憂燒密葉，映階疑欲讓雙旌。", "含煙散纈佳人惜，落地遺鈿少妓爭。", "丹渥不因輸繡段，錢圓誰把買花聲。", "海棠若要分流品，秋菊春蘭兩恰平。"]'),
('c395c5fa-12ff-4ccc-9431-aefb193345ce','和尚書詠泉山瀑布十二韻','徐夤','唐','唐诗','tang','','[]','名齊火浣溢山椒，誰把驚虹挂一條。',192,'全唐诗/poet.tang.40000.json','["名齊火浣溢山椒，誰把驚虹挂一條。", "天外倚來秋水刃，海心飛上白龍綃。", "民田鑿斷雲根引，僧圃穿通竹影澆。", "噴石似煙輕漠漠，濺崖如雨冷瀟瀟。", "水中蠶緒纏蒼壁，日裏虹精挂絳霄。", "寒漱綠陰仙桂老，碎流紅豔野桃夭。", "千尋練寫長年在，六出花開夏日消。", "急恐劃分青嶂骨，久應䙀裂翠微腰。", "濯纓便可譏漁父，洗耳還宜傲帝堯。", "林際猨猱偏得飯，岸邊烏鵲擬爲橋。", "赤城未到詩先寄，廬阜曾遊夢已遙。", "數夜積霖聲更遠，郡樓欹枕聽良宵。"]'),
('cf228736-e4e4-4306-bfd1-e54a57d04b44','自詠十韻','徐夤','唐','唐诗','tang','','[]','只合滄洲釣與耕，忽依螢燭愧功成。',159,'全唐诗/poet.tang.40000.json','["只合滄洲釣與耕，忽依螢燭愧功成。", "未遊宦路叨卑宦，纔到名場得大名。", "梁苑二年陪衆客，溫陵十載佐雙旌。", "錢財盡是侯王惠，骨肉偕承里巷榮。", "拙賦偏聞鐫印賣，惡詩親見畫圖呈多栽桃李期春色，闊鑿池塘許月明。", "寒益輕裯饒美寢，出乘車馬免徒行。", "麤支菽粟防飢歉，薄有桮盤備送迎。", "僧俗共鄰棲隱樂，妻孥同愛水雲清。", "如今便死還甘分，莫更嫌他白髮生。"]'),
('897d7a64-5411-488b-9e59-041f74493267','鏡中覽懷','徐夤','唐','唐诗','tang','','[]','晨起梳頭忽自悲，鏡中親見數莖絲。',32,'全唐诗/poet.tang.40000.json','["晨起梳頭忽自悲，鏡中親見數莖絲。", "從今休說龍泉劍，世上恩讐報已遲。"]'),
('d4ab14d1-365b-468f-8bd7-ec53d48bdc54','楚國史','徐夤','唐','唐诗','tang','','[]','六國商於恨最多，良弓休綰劍休磨。',32,'全唐诗/poet.tang.40000.json','["六國商於恨最多，良弓休綰劍休磨。", "君王不翦如簧舌，再得張儀欲奈何。"]'),
('5ac24802-68ee-4afa-81c5-1f7d8b7faff3','張儀','徐夤','唐','唐诗','tang','','[]','荆楚南來又北歸，分明舌在不應違。',32,'全唐诗/poet.tang.40000.json','["荆楚南來又北歸，分明舌在不應違。", "懷王本是無心者，籠得蒼蠅却放飛。"]'),
('cbd3dc1d-57f7-416d-898d-2a17500b8062','薔薇','徐夤','唐','唐诗','tang','','[]','朝露灑時如濯錦，晚風飄處似遺鈿。',32,'全唐诗/poet.tang.40000.json','["朝露灑時如濯錦，晚風飄處似遺鈿。", "重門剩著黃金鎖，莫被飛瓊摘上天。"]'),
('3a4ee675-2158-4a82-a8ba-0b922b96f20c','大夫松','徐夤','唐','唐诗','tang','','[]','五樹旌封許歲寒，挽柯攀葉也無端。',32,'全唐诗/poet.tang.40000.json','["五樹旌封許歲寒，挽柯攀葉也無端。", "爭如澗底凌霜節，不受秦皇亂世官。"]'),
('e033b3ed-18e6-49e0-80fe-c3d9889a1eae','杏園','徐夤','唐','唐诗','tang','','[]','杏苑簫聲好醉鄉，春風嘉宴更無雙。',32,'全唐诗/poet.tang.40000.json','["杏苑簫聲好醉鄉，春風嘉宴更無雙。", "憑誰爲謔穆天子，莫把瑤池並曲江。"]'),
('17483666-0c00-4a97-9824-4ee04d4ca776','蕉葉','徐夤','唐','唐诗','tang','','[]','綠綺新裁織女機，擺風搖日影離披。',32,'全唐诗/poet.tang.40000.json','["綠綺新裁織女機，擺風搖日影離披。", "只應青帝行春罷，閑倚東牆卓翠旗。"]'),
('3c1efd5a-19b5-4bf9-9fcf-7c9b46d2d342','路旁草','徐夤','唐','唐诗','tang','','[]','楚甸秦原萬里平，誰教根向路傍生。',32,'全唐诗/poet.tang.40000.json','["楚甸秦原萬里平，誰教根向路傍生。", "輕蹄繡轂長相蹋，合是榮時不得榮。"]'),
('8846f4b5-7891-4fd0-9d83-1a1252e4ca18','讀漢紀','徐夤','唐','唐诗','tang','','[]','布衣空手取中原，勁卒雄師不足論。',32,'全唐诗/poet.tang.40000.json','["布衣空手取中原，勁卒雄師不足論。", "楚國八千秦百萬，豁開胸臆一時吞。"]'),
('105a9483-9975-4cfa-98b1-66ce01473700','李夫人二首 一','徐夤','唐','唐诗','tang','','[]','不望金輿到錦帷，人間樂極即須悲。',32,'全唐诗/poet.tang.40000.json','["不望金輿到錦帷，人間樂極即須悲。", "若言要識愁中貌，也似君恩日日衰。"]'),
('411f1c67-19e7-4de2-8843-c4bb63f2ef2e','李夫人二首 二','徐夤','唐','唐诗','tang','','[]','招得香魂爵少翁，九華燈燭曉還空。',32,'全唐诗/poet.tang.40000.json','["招得香魂爵少翁，九華燈燭曉還空。", "漢王不及吳王樂，且與西施死處同。"]'),
('e60bc1d2-e4b3-4087-b004-d68dd8be4c01','明妃','徐夤','唐','唐诗','tang','','[]','不用牽心恨畫工，帝家無策及邊戎。',32,'全唐诗/poet.tang.40000.json','["不用牽心恨畫工，帝家無策及邊戎。", "香魂若得昇明月，夜夜還應照漢宮。"]'),
('8371affc-cbca-4219-ba38-742fac321483','馬嵬','徐夤','唐','唐诗','tang','','[]','二百年來事遠聞，從龍誰解盡如雲。',32,'全唐诗/poet.tang.40000.json','["二百年來事遠聞，從龍誰解盡如雲。", "張均兄弟皆何在，却是楊妃死報君。"]'),
('2b534e5f-fc54-4244-b89b-1d2146c2da67','依韻贈南安方處士五首 一','徐夤','唐','唐诗','tang','','[]','七貴五侯生肯退，利塵名網死當拋。',32,'全唐诗/poet.tang.40000.json','["七貴五侯生肯退，利塵名網死當拋。", "黔婁寂寞嚴陵臥，借問何人與結交。"]'),
('0ef07fbb-9021-4200-9b1a-1a07f721f004','依韻贈南安方處士五首 二','徐夤','唐','唐诗','tang','','[]','休把羸蹄蹋霜雪，書成何處獻君王。',32,'全唐诗/poet.tang.40000.json','["休把羸蹄蹋霜雪，書成何處獻君王。", "嵩山好與浮丘約，三十六峰雲外鄉。"]'),
('89d7ccef-4f26-4b71-97c7-4eb4ef83579c','依韻贈南安方處士五首 三','徐夤','唐','唐诗','tang','','[]','百萬僧中不爲僧，比君知道僅誰能。',32,'全唐诗/poet.tang.40000.json','["百萬僧中不爲僧，比君知道僅誰能。", "無家寄泊南安縣，六月門前也似冰。"]'),
('b8cc6a21-a9b7-4f26-a70a-0074e2a33795','依韻贈南安方處士五首 四','徐夤','唐','唐诗','tang','','[]','兩鬢當春却似秋，僻居誇近野僧樓。',32,'全唐诗/poet.tang.40000.json','["兩鬢當春却似秋，僻居誇近野僧樓。", "落花明月皆臨水，明月不流花自流。"]'),
('3e678ac0-2ce4-427d-ba12-1815c411a2af','依韻贈南安方處士五首 五','徐夤','唐','唐诗','tang','','[]','晉楚忙忙起戰塵，龔黃門外有高人。',32,'全唐诗/poet.tang.40000.json','["晉楚忙忙起戰塵，龔黃門外有高人。", "一畦雲薤三株竹，席上先生未是貧。"]'),
('3253dca8-6a8c-493b-aa60-f7ee4f197377','依韻荅黃校書','徐夤','唐','唐诗','tang','','[]','慈恩雁塔參差榜，杏苑鶯花次第遊。',32,'全唐诗/poet.tang.40000.json','["慈恩雁塔參差榜，杏苑鶯花次第遊。", "白日有愁猶可散，青山高臥況無愁。"]'),
('dfb61907-f39f-4797-8ee8-4086c79317a9','傷進士謝庭皓','徐夤','唐','唐诗','tang','','[]','獻書猶未達明君，何事先遊岱岳雲。',32,'全唐诗/poet.tang.40000.json','["獻書猶未達明君，何事先遊岱岳雲。", "惟有春風護冤魄，與生青草蓋孤墳。"]'),
('0fdf6262-27bb-4869-8d88-4c3cbc853e92','聞司空侍郎訃音','徐夤','唐','唐诗','tang','','[]','園綺生雖逢漢室，巢由死不謁堯階。',32,'全唐诗/poet.tang.40000.json','["園綺生雖逢漢室，巢由死不謁堯階。", "夫君歿去何人葬，合取夷齊隱處埋。"]'),
('409ac501-f726-41d2-b592-d21557e75699','偶題二首 一','徐夤','唐','唐诗','tang','','[]','買骨須求騏驥骨，愛毛宜採鳳皇毛。',32,'全唐诗/poet.tang.40000.json','["買骨須求騏驥骨，愛毛宜採鳳皇毛。", "駑駘燕雀堪何用，仍向人前價例高。"]'),
('06dc1837-2853-434f-b1fe-f269bb0726e7','偶題二首 二','徐夤','唐','唐诗','tang','','[]','賦就長安振大名，斬蛇功與樂天爭。',32,'全唐诗/poet.tang.40000.json','["賦就長安振大名，斬蛇功與樂天爭。", "歸來延壽溪頭坐，終日無人問一聲。"]'),
('fd8e4a6c-57dd-4541-8527-187202242ffe','猨','徐夤','唐','唐诗','tang','','[]','宿有喬林飲有溪，生來蹤跡遠塵泥。',32,'全唐诗/poet.tang.40000.json','["宿有喬林飲有溪，生來蹤跡遠塵泥。", "不知心更愁何事，每向深山夜夜啼。"]'),
('f91daa04-61f6-460c-9d58-2c986981ce9d','追和賈浪仙古鏡','徐夤','唐','唐诗','tang','','[]','誰開黃帝橋山冢，明月飛光出九泉。',32,'全唐诗/poet.tang.40000.json','["誰開黃帝橋山冢，明月飛光出九泉。", "狼藉蘚痕磨不盡，黑雲殘點汙秋天。"]'),
('5454a82f-723b-4df9-8c00-057f3d24f305','蝴蝶三首 一','徐夤','唐','唐诗','tang','','[]','不並難飛繭裏蛾，有花芳處定經過。',34,'全唐诗/poet.tang.40000.json','["不並難飛繭裏蛾，有花芳處定經過。", "天風相送輕飄去，却笑[蜘蛛]謾織羅。"]'),
('e9be9eaa-7c69-4371-9538-0fc0ff65d054','蝴蝶三首 二','徐夤','唐','唐诗','tang','','[]','苒苒雙雙拂畫欄，佳人偷眼再三看。',32,'全唐诗/poet.tang.40000.json','["苒苒雙雙拂畫欄，佳人偷眼再三看。", "莫欺翼短飛長近，試就花間撲已難。"]'),
('acfd526f-af75-430e-97f3-4bd8802df7c1','蝴蝶三首 三','徐夤','唐','唐诗','tang','','[]','栩栩無因繫得他，野園荒徑一何多。',32,'全唐诗/poet.tang.40000.json','["栩栩無因繫得他，野園荒徑一何多。", "不聞絲竹誰教舞，應仗流鶯爲唱歌。"]'),
('d57802d4-e343-42b6-8118-413ed13a9c10','新刺襪','徐夤','唐','唐诗','tang','','[]','素手春溪罷浣紗，巧裁明月半彎斜。',32,'全唐诗/poet.tang.40000.json','["素手春溪罷浣紗，巧裁明月半彎斜。", "齊宮合贈東昏寵，好步黃金菡萏花。"]'),
('622cdc8c-10b2-49c5-948a-d05689b99352','寄華山司空侍郎','徐夤','唐','唐诗','tang','','[]','山掌林中第一人，鶴書時或問眠雲。',32,'全唐诗/poet.tang.40000.json','["山掌林中第一人，鶴書時或問眠雲。", "莫言疎野全無事，明月清風肯放君。"]'),
('40b0453a-1856-4853-a9ca-618f7b951f97','初夏戲題','徐夤','唐','唐诗','tang','','[]','長養薰風拂曉吹，漸開荷芰落薔薇。',32,'全唐诗/poet.tang.40000.json','["長養薰風拂曉吹，漸開荷芰落薔薇。", "青蟲也學莊周夢，化作南園蛺蝶飛。"]'),
('ef9a3c12-6c44-4bcd-b63a-195fd228a93e','客舍寓懷','錢珝','唐','唐诗','tang','','[]','灑灑灘聲晚霽時，客亭風袖半披垂。',64,'全唐诗/poet.tang.40000.json','["灑灑灘聲晚霽時，客亭風袖半披垂。", "野雲行止誰相待，明月襟懷祗自知。", "無伴偶吟溪上路，有花偷笑臘前枝。", "牽情景物潛惆悵，忽似傷春遠別離。"]'),
('fbb7923e-f685-473d-ac3e-752f8b84318c','送王郎中','錢珝','唐','唐诗','tang','','[]','惜別遠相送，却成惆悵多。',24,'全唐诗/poet.tang.40000.json','["惜別遠相送，却成惆悵多。", "獨歸回首處，爭那暮山何。"]'),
('17f9a69e-f778-4d2c-85d6-d8e5e1098e92','江行無題一百首 一','錢珝','唐','唐诗','tang','','[]','傾酒向漣漪，乘流欲去時。',24,'全唐诗/poet.tang.40000.json','["傾酒向漣漪，乘流欲去時。", "寸心同尺璧，投此報馮夷。"]'),
('17923b7c-e3bc-49a5-8e1f-32df5f55f3b0','江行無題一百首 二','錢珝','唐','唐诗','tang','','[]','江曲全縈楚，雲飛半自秦。',24,'全唐诗/poet.tang.40000.json','["江曲全縈楚，雲飛半自秦。", "峴山迴首望，如別故鄉人。"]'),
('992a9fdb-a059-480a-af0b-d39f745ab7b6','江行無題一百首 三','錢珝','唐','唐诗','tang','','[]','浦煙含夜色，冷日轉秋旻。',24,'全唐诗/poet.tang.40000.json','["浦煙含夜色，冷日轉秋旻。", "自有沈碑在，清光不照人。"]'),
('0322221c-e8dc-4373-bf1f-92b3958adb1c','江行無題一百首 四','錢珝','唐','唐诗','tang','','[]','楚岸雲空合，楚城人不來。',24,'全唐诗/poet.tang.40000.json','["楚岸雲空合，楚城人不來。", "祗今誰善舞，莫恨廢章臺。"]'),
('66c08c21-408a-4d67-8417-b8d2d77545c0','江行無題一百首 五','錢珝','唐','唐诗','tang','','[]','行背青山郭，吟當白露秋。',24,'全唐诗/poet.tang.40000.json','["行背青山郭，吟當白露秋。", "風流無屈宋，空詠古荆州。"]'),
('dee1b9d0-4da6-48f7-b87e-b2a44bc10363','江行無題一百首 六','錢珝','唐','唐诗','tang','','["\u957f\u6c5f"]','晚來漁父喜，網重欲收遲。',24,'全唐诗/poet.tang.40000.json','["晚來漁父喜，網重欲收遲。", "恐有長江使，金錢願贖龜。"]'),
('a7594595-00c0-4d3c-afd4-db2a1914bf44','江行無題一百首 七','錢珝','唐','唐诗','tang','','[]','去指龍沙路，徒懸象闕心。',24,'全唐诗/poet.tang.40000.json','["去指龍沙路，徒懸象闕心。", "夜涼無遠夢，不爲偶聞砧。"]'),
('363ade9d-5052-436a-9287-e0709430d552','江行無題一百首 八','錢珝','唐','唐诗','tang','','[]','霧雲疎有葉，雨浪細無花。',24,'全唐诗/poet.tang.40000.json','["霧雲疎有葉，雨浪細無花。", "穩放扁舟去，江天自有涯。"]'),
('7eb2e943-8e06-451c-b231-a44fb2043de9','江行無題一百首 九','錢珝','唐','唐诗','tang','','[]','好日當秋半，層波動旅腸。',24,'全唐诗/poet.tang.40000.json','["好日當秋半，層波動旅腸。", "已行千里外，誰與共秋光。"]'),
('895f8e9b-409c-44a0-8428-7cdf14bd07f0','江行無題一百首 十','錢珝','唐','唐诗','tang','','[]','潤色非東里，官曹更建章。',24,'全唐诗/poet.tang.40000.json','["潤色非東里，官曹更建章。", "宦遊難自定，來喚櫂船郎。"]'),
('e68cb702-b6a6-401a-a1ae-98228a2d566f','江行無題一百首 十一','錢珝','唐','唐诗','tang','','[]','夜江清未曉，徒惜月光沉。',24,'全唐诗/poet.tang.40000.json','["夜江清未曉，徒惜月光沉。", "不是因行樂，堪傷老大心。"]'),
('d7a1fdcf-42df-4bac-929c-67bfc851f259','江行無題一百首 十二','錢珝','唐','唐诗','tang','','[]','翳日多喬木，維舟取束薪。',24,'全唐诗/poet.tang.40000.json','["翳日多喬木，維舟取束薪。", "靜聽江叟語，盡是厭兵人。"]'),
('709f5393-5755-4f83-a422-fbc529b4649f','江行無題一百首 十三','錢珝','唐','唐诗','tang','','[]','箭漏日初短，汀煙草未衰。',24,'全唐诗/poet.tang.40000.json','["箭漏日初短，汀煙草未衰。", "雨餘雖更綠，不是採蘋時。"]'),
('b4c8dff9-340c-4a2b-b480-016d0dbe12f5','江行無題一百首 十四','錢珝','唐','唐诗','tang','','[]','山雨夜來漲，喜魚跳滿江。',24,'全唐诗/poet.tang.40000.json','["山雨夜來漲，喜魚跳滿江。", "岸沙平欲盡，垂蓼入船窗。"]'),
('ce9bcf6f-5fa8-4dc0-98ec-7e58bc7a27b3','江行無題一百首 十五','錢珝','唐','唐诗','tang','','[]','渚邊新鴈下，舟上獨淒涼。',24,'全唐诗/poet.tang.40000.json','["渚邊新鴈下，舟上獨淒涼。", "俱是南來客，憐君綴一行。"]'),
('5f07cf10-91b2-463f-8478-2278f9e1ab62','江行無題一百首 十六','錢珝','唐','唐诗','tang','','[]','雲密連江暗，風斜著物鳴。',24,'全唐诗/poet.tang.40000.json','["雲密連江暗，風斜著物鳴。", "一杯真戰將，笑爾作愁兵。"]'),
('4cf6bd3d-dab6-4217-9986-5da98288d15e','江行無題一百首 十七','錢珝','唐','唐诗','tang','','[]','柳拂斜開路，籬邊數戶村。',24,'全唐诗/poet.tang.40000.json','["柳拂斜開路，籬邊數戶村。", "可能還有意，不掩向江門。"]'),
('6d4230b7-1a46-4ab2-bd17-bfe981c40d0a','江行無題一百首 十八','錢珝','唐','唐诗','tang','','[]','不識相如渴，徒吟子美詩。',24,'全唐诗/poet.tang.40000.json','["不識相如渴，徒吟子美詩。", "江清惟獨看，心外更誰知。"]'),
('af9867bf-cc57-4040-9e47-f7b83b3516bc','江行無題一百首 十九','錢珝','唐','唐诗','tang','','[]','牽路沿江狹，沙崩岸不平。',24,'全唐诗/poet.tang.40000.json','["牽路沿江狹，沙崩岸不平。", "盡知行處險，誰肯載時輕。"]'),
('2f38cbf7-7fc7-42d4-8e6f-91c7b2864482','江行無題一百首 二十','錢珝','唐','唐诗','tang','','[]','憔悴異靈均，非讒作逐臣。',24,'全唐诗/poet.tang.40000.json','["憔悴異靈均，非讒作逐臣。", "如逢漁父問，未是獨醒人。"]'),
('1b4dfe50-60c4-43d0-a014-69d9b73fc8f0','江行無題一百首 二十一','錢珝','唐','唐诗','tang','','[]','水含秋夜靜，雲帶夕陽高。',24,'全唐诗/poet.tang.40000.json','["水含秋夜靜，雲帶夕陽高。", "詩癖非吾病，何妨吮短豪。"]'),
('4bd471e6-b92f-42a0-82ce-d56228ad0cf3','江行無題一百首 二十二','錢珝','唐','唐诗','tang','','[]','帶舟維古岸，還似阻西陵。',24,'全唐诗/poet.tang.40000.json','["帶舟維古岸，還似阻西陵。", "箕伯無多怒，回頭詎不能。"]'),
('a0c7a29d-7ffe-41b0-9c86-17228a396718','江行無題一百首 二十三','錢珝','唐','唐诗','tang','','[]','秋雲久無雨，江燕社猶飛。',24,'全唐诗/poet.tang.40000.json','["秋雲久無雨，江燕社猶飛。", "却笑舟中客，今年未得歸。"]'),
