('d88e8fc3-14df-4105-9451-cd4bf55f1803','江行無題一百首 七十二','錢珝','唐','唐诗','tang','','[]','秋寒鷹隼健，逐雀下雲空。',24,'全唐诗/poet.tang.40000.json','["秋寒鷹隼健，逐雀下雲空。", "知是江湖客，無心擊塞鴻。"]'),
('98315dd2-f3c5-4d6f-8386-9f0f83d9d815','江行無題一百首 七十三','錢珝','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','幽懷念煙水，長恨隔龍沙。',24,'全唐诗/poet.tang.40000.json','["幽懷念煙水，長恨隔龍沙。", "今日滕王閣，分明見落霞。"]'),
('9175459a-8e05-48dc-87a1-abf8347708cf','江行無題一百首 七十四','錢珝','唐','唐诗','tang','','[]','江流何渺渺，懷古獨依依。',24,'全唐诗/poet.tang.40000.json','["江流何渺渺，懷古獨依依。", "漁父非賢者，蘆中但有磯。"]'),
('5004eed2-2a9a-4e68-8268-ddff25dcb37d','江行無題一百首 七十五','錢珝','唐','唐诗','tang','','[]','風雨正甘寢，雲霓忽曉晴。',24,'全唐诗/poet.tang.40000.json','["風雨正甘寢，雲霓忽曉晴。", "放歌雖自遣，一歲又崢嶸。"]'),
('3a8aa0e5-5746-4f5e-a006-86ddd946dc6b','江行無題一百首 七十六','錢珝','唐','唐诗','tang','','[]','幽思正遲遲，沙邊濯弄時。',24,'全唐诗/poet.tang.40000.json','["幽思正遲遲，沙邊濯弄時。", "自憐非博物，猶未識鳧葵。"]'),
('4ed934b8-4536-4021-9f24-41ab44ccdd74','江行無題一百首 七十七','錢珝','唐','唐诗','tang','','[]','曾有煙波客，能歌西塞山。',24,'全唐诗/poet.tang.40000.json','["曾有煙波客，能歌西塞山。", "落花惟待月，一釣紫菱灣。"]'),
('5d2a4ac5-6d18-4433-95fc-9426f9e49f38','江行無題一百首 七十八','錢珝','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','千頃水紋細，一拳嵐影孤。',24,'全唐诗/poet.tang.40000.json','["千頃水紋細，一拳嵐影孤。", "君山寒樹綠，曾過洞庭湖。"]'),
('0fa43a5f-9cdd-4b61-83ff-e789b5bde426','江行無題一百首 七十九','錢珝','唐','唐诗','tang','','[]','光闊重湖水，低斜遠鴈行。',24,'全唐诗/poet.tang.40000.json','["光闊重湖水，低斜遠鴈行。", "未曾無興詠，多謝沈東陽。"]'),
('39d7a9b2-622c-4a24-abe4-3e3ed0f783a9','江行無題一百首 八十','錢珝','唐','唐诗','tang','','[]','晚菊繞江壘，忽如開古屏。',24,'全唐诗/poet.tang.40000.json','["晚菊繞江壘，忽如開古屏。", "莫言時節過，白日有餘馨。"]'),
('cf07926c-f8c3-434d-bdaf-9c211f0b1bbb','江行無題一百首 八十一','錢珝','唐','唐诗','tang','','[]','日落長亭晚，山門步障青。',24,'全唐诗/poet.tang.40000.json','["日落長亭晚，山門步障青。", "可憐無酒分，處處有旗亭。"]'),
('7b3190cb-c1c9-46eb-9c13-d495c674f6f1','江行無題一百首 八十二','錢珝','唐','唐诗','tang','','[]','遠岸無行樹，經霜有伴紅。',24,'全唐诗/poet.tang.40000.json','["遠岸無行樹，經霜有伴紅。", "停船搜好句，題葉贈江楓。"]'),
('6ca9fcfd-9286-443e-bf42-9a91e0e316ad','江行無題一百首 八十三','錢珝','唐','唐诗','tang','','[]','身世比行舟，無風亦暫休。',24,'全唐诗/poet.tang.40000.json','["身世比行舟，無風亦暫休。", "敢言終破浪，惟願穩乘流。"]'),
('b51b6f9a-b058-4c34-896e-09f1f4ba286a','江行無題一百首 八十四','錢珝','唐','唐诗','tang','','[]','數畝蒼苔石，煙蒙鶴卵洲。',24,'全唐诗/poet.tang.40000.json','["數畝蒼苔石，煙蒙鶴卵洲。", "定因詞客遇，名字始風流。"]'),
('8b422a81-48ce-4768-9d6a-084896d74cff','江行無題一百首 八十五','錢珝','唐','唐诗','tang','','[]','興閑停桂楫，路好過松門。',24,'全唐诗/poet.tang.40000.json','["興閑停桂楫，路好過松門。", "不負佳山水，還開酒一樽。"]'),
('2c324b9b-fcf4-4a72-8498-08ca8010507e','江行無題一百首 八十六','錢珝','唐','唐诗','tang','','[]','短檝休敲桂，孤根自駐萍。',24,'全唐诗/poet.tang.40000.json','["短檝休敲桂，孤根自駐萍。", "自憐非劒氣，空向斗牛星。"]'),
('100b4a87-826a-4b42-8a04-434310f5daf1','江行無題一百首 八十七','錢珝','唐','唐诗','tang','','[]','高浪如銀屋，江風一發時。',24,'全唐诗/poet.tang.40000.json','["高浪如銀屋，江風一發時。", "筆端降太白，才大語終奇。"]'),
('f7659c7b-924c-4804-9dd3-068ad9a917c2','江行無題一百首 八十八','錢珝','唐','唐诗','tang','','[]','細竹漁家路，晴陽看結罾。',24,'全唐诗/poet.tang.40000.json','["細竹漁家路，晴陽看結罾。", "喜來邀客坐，分與折腰菱。"]'),
('46d0bd63-e6c5-4a2f-890a-111a5d669d1e','江行無題一百首 八十九','錢珝','唐','唐诗','tang','','[]','平湖五百里，江水想通波。',24,'全唐诗/poet.tang.40000.json','["平湖五百里，江水想通波。", "不奈扁舟去，其如決計何。"]'),
('1eb5b899-8f13-4bb5-aa72-365dd8bc9f1f','江行無題一百首 九十','錢珝','唐','唐诗','tang','','[]','數逢雲斷處，去岸映高山。',24,'全唐诗/poet.tang.40000.json','["數逢雲斷處，去岸映高山。", "身到章江日，應猶未得閑。"]'),
('b215d922-ee4b-49cf-b268-2608562a5a9f','江行無題一百首 九十一','錢珝','唐','唐诗','tang','','[]','一灣斜照水，三版順風船。',24,'全唐诗/poet.tang.40000.json','["一灣斜照水，三版順風船。", "未敢相邀釣，勞生只自憐。"]');
